window.THEORY_BANK=[
{id:1,cat:'rules',q:'What is the national speed limit on a single carriageway for cars and motorcycles?',opts:['50 mph','60 mph','70 mph','80 mph'],ans:1,exp:'The national speed limit on a single carriageway is 60 mph for cars and motorcycles.'},
{id:2,cat:'rules',q:'What is the national speed limit on a dual carriageway for cars and motorcycles?',opts:['50 mph','60 mph','70 mph','80 mph'],ans:2,exp:'The national speed limit on a dual carriageway is 70 mph for cars and motorcycles.'},
{id:3,cat:'rules',q:'What is the speed limit in a built-up area unless signs show otherwise?',opts:['20 mph','30 mph','40 mph','50 mph'],ans:1,exp:'The default speed limit in a built-up area with street lighting is 30 mph unless signs indicate otherwise.'},
{id:4,cat:'rules',q:'What is the national speed limit on a motorway for cars?',opts:['50 mph','60 mph','70 mph','80 mph'],ans:2,exp:'The national speed limit on a motorway is 70 mph for cars.'},
{id:5,cat:'rules',q:'When approaching a roundabout, who has priority?',opts:['Traffic approaching from the left','Traffic approaching from the right','Traffic already on the roundabout','The fastest vehicle'],ans:2,exp:'You must give way to traffic already on the roundabout, approaching from your right.'},
{id:6,cat:'rules',q:'What does a single broken white line along the centre of the road mean?',opts:['No overtaking allowed','You may cross to overtake if safe','You must stay on the left at all times','The road is one-way'],ans:1,exp:'A single broken white centre line means you may cross it to overtake if it is safe to do so.'},
{id:7,cat:'rules',q:'When may you overtake on the left?',opts:['Whenever the right lane is busy','When the vehicle in front is signalling to turn right','Only on motorways','Never under any circumstances'],ans:1,exp:'You may overtake on the left when the vehicle ahead is signalling to turn right and you can safely pass on the left.'},
{id:8,cat:'rules',q:'What should you do when approaching a zebra crossing where a pedestrian is waiting to cross?',opts:['Flash your headlights to signal them across','Sound your horn to warn them','Slow down and stop to let them cross','Speed up and pass before they step onto the crossing'],ans:2,exp:'You must slow down and stop to let pedestrians cross at a zebra crossing when they are waiting.'},
{id:9,cat:'rules',q:'At a pelican crossing, what does a flashing amber light mean?',opts:['You must stop and wait for the green light','You may proceed if the crossing is clear of pedestrians','You must give way to oncoming traffic','The crossing is out of order'],ans:1,exp:'A flashing amber light at a pelican crossing means you may go if the crossing is clear of pedestrians.'},
{id:10,cat:'rules',q:'You are at a junction with no road signs or markings. A vehicle is approaching from your right. Who has priority?',opts:['You, because you arrived first','The vehicle from the right always has priority','Neither vehicle has priority; both should proceed with caution','The larger vehicle has priority'],ans:2,exp:'At an unmarked junction, no one has automatic priority. Both drivers should proceed with great caution and be prepared to give way.'},
{id:11,cat:'rules',q:'What is the speed limit for a car towing a caravan on a motorway?',opts:['50 mph','60 mph','70 mph','80 mph'],ans:1,exp:'A car towing a caravan or trailer on a motorway has a speed limit of 60 mph.'},
{id:12,cat:'rules',q:'What is the speed limit for a car towing a caravan on a single carriageway?',opts:['40 mph','50 mph','60 mph','70 mph'],ans:1,exp:'A car towing a caravan or trailer on a single carriageway has a speed limit of 50 mph.'},
{id:13,cat:'rules',q:'When must you NOT overtake another vehicle?',opts:['On a dual carriageway','When approaching a junction','On a road with a broken centre line','When the road ahead is clear'],ans:1,exp:'You must not overtake when approaching a junction as the other vehicle may be turning and the situation is unpredictable.'},
{id:14,cat:'rules',q:'What do double white lines with a solid line on your side mean?',opts:['You may overtake if it is safe','You must not cross or straddle the line','You may park on the road','The road is a clearway'],ans:1,exp:'A solid white line on your side of double white lines means you must not cross or straddle it except in specific circumstances such as turning into a side road.'},
{id:15,cat:'rules',q:'You want to turn right at a roundabout. Which lane should you normally use on approach?',opts:['The left lane','The right lane','Either lane','The middle lane only'],ans:1,exp:'When turning right at a roundabout, you should normally approach in the right-hand lane.'},
{id:16,cat:'rules',q:'What should you do when entering a box junction?',opts:['Enter only if your exit road is clear','Enter at any time as long as the light is green','Stop in the box if traffic is heavy','Enter and wait until traffic moves'],ans:0,exp:'You must not enter a box junction unless your exit road is clear. The exception is when turning right and only prevented by oncoming traffic.'},
{id:17,cat:'rules',q:'At a crossroads with no priority signs, who should you give way to?',opts:['Only vehicles from the left','Only vehicles from the right','Traffic from both directions; proceed with caution','Nobody; you always have right of way'],ans:2,exp:'At an unmarked crossroads, no one has automatic priority. You should approach with caution and be prepared to give way.'},
{id:18,cat:'rules',q:'What is the speed limit for cars on a dual carriageway when towing a trailer?',opts:['50 mph','60 mph','70 mph','40 mph'],ans:1,exp:'When towing a trailer on a dual carriageway, the speed limit for cars is 60 mph.'},
{id:19,cat:'rules',q:'You see a \'STOP\' sign at a junction. What must you do?',opts:['Slow down and proceed if the road is clear','Stop at the line and wait until it is safe to proceed','Stop only if there are vehicles approaching','Give way to traffic from the right only'],ans:1,exp:'At a STOP sign, you must come to a complete stop at the line and only proceed when it is safe.'},
{id:20,cat:'rules',q:'What does a \'GIVE WAY\' sign require you to do?',opts:['Stop completely before proceeding','Slow down and give way to traffic on the major road','Continue at the same speed','Sound your horn before entering the junction'],ans:1,exp:'A GIVE WAY sign means you must slow down and be prepared to stop to give way to traffic on the road you are joining.'},
{id:21,cat:'rules',q:'On a three-lane motorway, when should you use the right-hand lane?',opts:['For normal driving','Only for overtaking when the left and middle lanes are occupied','When travelling above 60 mph','At any time if the road is quiet'],ans:1,exp:'The right-hand lane on a motorway should only be used for overtaking when the left-hand and middle lanes are occupied by slower traffic.'},
{id:22,cat:'rules',q:'What should you do after overtaking on a motorway?',opts:['Stay in the right-hand lane','Move back to the left as soon as it is safe','Flash your hazard lights','Slow down immediately'],ans:1,exp:'After overtaking, you should move back to the left-hand lane as soon as it is safe to do so. Do not hog the middle or right-hand lanes.'},
{id:23,cat:'rules',q:'What is the minimum distance you should leave when following a vehicle in dry conditions at 60 mph?',opts:['One car length','A two-second gap','A one-second gap','Six car lengths'],ans:1,exp:'In dry conditions, you should keep at least a two-second gap between you and the vehicle in front.'},
{id:24,cat:'rules',q:'In wet conditions, how much should you increase your following distance?',opts:['No increase is needed','Double the distance','Triple the distance','Quadruple the distance'],ans:1,exp:'In wet conditions, you should at least double your following distance because stopping distances increase significantly.'},
{id:25,cat:'rules',q:'You are driving on a motorway and miss your exit. What should you do?',opts:['Reverse back to the exit','Stop on the hard shoulder and walk back','Continue to the next exit','Make a U-turn at the next gap in the central reservation'],ans:2,exp:'If you miss your exit on a motorway, you must continue to the next exit. Never reverse, stop, or make a U-turn on a motorway.'},
{id:26,cat:'rules',q:'When can you drive in a bus lane?',opts:['Never under any circumstances','During the hours shown on the sign if your vehicle is permitted','Only if the bus lane is empty','Any time outside rush hour'],ans:1,exp:'Some bus lanes allow other vehicles to use them outside certain hours. Check the signs for the times of operation and which vehicles are permitted.'},
{id:27,cat:'rules',q:'What is the legal minimum tread depth for car tyres in the UK?',opts:['1.0 mm','1.6 mm','2.0 mm','2.5 mm'],ans:1,exp:'The legal minimum tread depth for car tyres in the UK is 1.6 mm across the central three-quarters of the tyre width.'},
{id:28,cat:'rules',q:'You are approaching a puffin crossing and the red light is showing. When may you proceed?',opts:['When the pedestrians have finished crossing','When the green light shows','When the flashing amber appears','After waiting 30 seconds'],ans:1,exp:'At a puffin crossing, you may only proceed when the green light shows. Puffin crossings do not have a flashing amber phase.'},
{id:29,cat:'rules',q:'What should you do when you see a school crossing patrol officer holding up a sign?',opts:['Sound your horn to warn children','Stop and wait until they signal you to proceed','Slow down but continue if the road is clear','Flash your headlights at the children'],ans:1,exp:'When a school crossing patrol shows the stop sign, you must stop and wait until all children have crossed and the patrol signals you to move.'},
{id:30,cat:'rules',q:'On a road with a 40 mph speed limit, what is the overall stopping distance at 40 mph in dry conditions?',opts:['23 metres','36 metres','53 metres','73 metres'],ans:1,exp:'At 40 mph, the overall stopping distance in dry conditions is approximately 36 metres (118 feet), comprising thinking and braking distance.'},
{id:31,cat:'rules',q:'What should you do when an emergency vehicle approaches with blue flashing lights and sirens?',opts:['Stop immediately wherever you are','Pull over to the left when safe and allow it to pass','Speed up to get out of the way','Ignore it and continue driving normally'],ans:1,exp:'When an emergency vehicle approaches, you should pull over safely to let it pass. Do not stop suddenly or block the road.'},
{id:32,cat:'rules',q:'You are turning right from a major road into a side road. Who do you need to give way to?',opts:['Only oncoming vehicles','Oncoming vehicles and pedestrians crossing the side road','Nobody; you have right of way','Only vehicles behind you'],ans:1,exp:'When turning right, you must give way to oncoming traffic and also to pedestrians who are already crossing the road you are turning into.'},
{id:33,cat:'rules',q:'What is the speed limit on a single carriageway for goods vehicles over 7.5 tonnes?',opts:['40 mph','50 mph','60 mph','70 mph'],ans:1,exp:'Goods vehicles over 7.5 tonnes have a speed limit of 50 mph on single carriageways.'},
{id:34,cat:'rules',q:'When may you use hazard warning lights while driving?',opts:['To thank another driver','When parked illegally','On a motorway or unrestricted dual carriageway to warn traffic behind of a hazard ahead','Whenever you are driving slowly'],ans:2,exp:'You may use hazard warning lights while moving only on a motorway or unrestricted dual carriageway to warn following traffic of a hazard ahead.'},
{id:35,cat:'rules',q:'At a toucan crossing, who can use the crossing?',opts:['Only pedestrians','Only cyclists','Both pedestrians and cyclists','Only horse riders'],ans:2,exp:'A toucan crossing is designed for both pedestrians and cyclists to use together.'},
{id:36,cat:'rules',q:'What lane should you be in when going straight ahead at a roundabout?',opts:['The right-hand lane','The left-hand lane','Either lane unless road markings indicate otherwise','The outside lane only'],ans:1,exp:'When going straight ahead at a roundabout, you should generally use the left-hand lane unless road markings direct you otherwise.'},
{id:37,cat:'rules',q:'You are driving at night on an unlit road. When must you use dipped headlights instead of full beam?',opts:['At all times on unlit roads','When meeting or following other traffic','Only in fog','Only in built-up areas'],ans:1,exp:'You must dip your headlights when meeting oncoming vehicles or following other traffic to avoid dazzling other road users.'},
{id:38,cat:'rules',q:'What is the purpose of an urban clearway?',opts:['To allow parking at any time','To prevent stopping during specified times','To reduce the speed limit to 20 mph','To allow loading at all times'],ans:1,exp:'An urban clearway is a road where you must not stop during the times shown on the sign, except to pick up or set down passengers.'},
{id:39,cat:'rules',q:'When should you signal before turning left?',opts:['Only in heavy traffic','In good time before the turn','Only if there are pedestrians nearby','You do not need to signal when turning left'],ans:1,exp:'You should always signal in good time before turning left to let other road users know your intentions.'},
{id:40,cat:'rules',q:'What does a red traffic light mean?',opts:['Slow down and prepare to stop','Stop behind the stop line and wait','Proceed with caution','Stop only if pedestrians are crossing'],ans:1,exp:'A red traffic light means you must stop behind the stop line. You must not cross it until the light turns green.'},
{id:41,cat:'rules',q:'What does a red and amber traffic light showing together mean?',opts:['You may go if the road is clear','Stop and wait; the green signal is about to show','Caution, the lights are changing to red','You may proceed but give way to pedestrians'],ans:1,exp:'Red and amber together mean stop and wait. The green light is about to show, but you must not go until the green light appears.'},
{id:42,cat:'rules',q:'You are on a dual carriageway and want to turn right into a side road. What should you do?',opts:['Use the right-hand lane well in advance and signal right','Stay in the left lane until the last moment','Stop in the central reservation regardless of space','Signal left then move right'],ans:0,exp:'You should move into the right-hand lane in good time, signal right, and slow down to turn safely.'},
{id:43,cat:'rules',q:'What is the rule about using the horn in a built-up area at night?',opts:['You may use the horn at any time','You must not use the horn between 11:30 pm and 7:00 am in a built-up area when stationary','You may only use the horn between 8 pm and 6 am','The horn may never be used at night'],ans:1,exp:'You must not sound your horn in a built-up area between 11:30 pm and 7:00 am when your vehicle is stationary, unless a moving vehicle poses a danger.'},
{id:44,cat:'rules',q:'What should you do if you want to overtake a cyclist?',opts:['Sound your horn to warn them and pass closely','Give them at least as much room as you would a car','Pass as quickly as possible','Overtake only if they signal you to pass'],ans:1,exp:'When overtaking a cyclist, give them at least as much room as you would when overtaking a car. The Highway Code recommends at least 1.5 metres at speeds up to 30 mph.'},
{id:45,cat:'rules',q:'You are in the left-hand lane of a motorway. A vehicle is trying to join from a slip road. What should you do?',opts:['Speed up to prevent them joining','Move to another lane if safe, or adjust your speed to let them merge','Stop and let them in','Flash your lights to warn them not to join'],ans:1,exp:'If safe, move to the middle lane to allow traffic to join. If you cannot change lanes, adjust your speed to create a gap.'},
{id:46,cat:'rules',q:'What does a flashing green arrow at a junction mean?',opts:['You may go in the direction shown but must give way to pedestrians and other traffic','You must stop','You have full right of way in the direction shown','The traffic lights are faulty'],ans:0,exp:'A green filter arrow means you may proceed in the direction of the arrow, but you should still give way to any traffic and pedestrians already in the junction.'},
{id:47,cat:'rules',q:'What is the maximum speed limit for cars in a 20 mph zone?',opts:['20 mph','25 mph','30 mph','It depends on road conditions'],ans:0,exp:'In a 20 mph zone, the maximum speed limit is 20 mph. These zones are typically found near schools and residential areas.'},
{id:48,cat:'rules',q:'You are turning left at a junction. A cyclist is on your left going straight ahead. Who has priority?',opts:['You, because you are turning','The cyclist going straight ahead','Whoever arrives at the junction first','Neither; it depends on the road markings'],ans:1,exp:'You must give way to cyclists going straight ahead when you are turning left. Check your mirrors and blind spot before turning.'},
{id:49,cat:'rules',q:'When can you enter a box junction when turning right?',opts:['Never','When your exit road is clear, even if oncoming traffic prevents you from completing the turn immediately','Only when there is no other traffic','When the traffic light is green'],ans:1,exp:'You may enter a box junction when turning right if your exit is clear but you are only prevented from turning by oncoming traffic or vehicles also turning right.'},
{id:50,cat:'rules',q:'What is the speed limit for cars on a single carriageway with no street lights and no speed limit signs?',opts:['30 mph','40 mph','50 mph','60 mph'],ans:3,exp:'On a single carriageway with no street lighting, the national speed limit of 60 mph applies for cars unless signs say otherwise.'},
{id:51,cat:'rules',q:'On a motorway, when may you use the hard shoulder for driving?',opts:['When the motorway is congested','When it has been opened as a running lane on a smart motorway','To overtake slow vehicles','At any time in an emergency'],ans:1,exp:'You may only drive on the hard shoulder when it has been opened as a running lane on a smart motorway, indicated by overhead signs.'},
{id:52,cat:'rules',q:'At a roundabout, when should you signal left?',opts:['As you approach the roundabout','After you have passed the exit before the one you want','Only when taking the first exit','You never need to signal left at a roundabout'],ans:1,exp:'You should signal left after passing the exit before the one you intend to take, to let other road users know you are leaving the roundabout.'},
{id:53,cat:'rules',q:'What is the law regarding mobile phone use while driving?',opts:['You may use a handheld phone if stationary in traffic','It is illegal to use a handheld phone while driving, including when stopped at traffic lights','You may use a handheld phone only for navigation','It is permitted in emergencies'],ans:1,exp:'It is illegal to hold and use a phone, sat nav, tablet, or any device while driving, even when stopped at traffic lights or queuing in traffic.'},
{id:54,cat:'rules',q:'What must you do before reversing your vehicle?',opts:['Sound your horn','Check all around the vehicle for obstructions and pedestrians','Switch on your hazard warning lights','Only check your mirrors'],ans:1,exp:'Before reversing, you must check all around your vehicle, especially for children and pedestrians who may not be visible in your mirrors.'},
{id:55,cat:'rules',q:'You are driving on a road with a central reservation. Is it a dual carriageway?',opts:['Yes, always','No, it is a single carriageway','Only if it has two lanes in each direction','Yes, any road with a central reservation is a dual carriageway'],ans:3,exp:'A dual carriageway is any road with a central reservation separating the carriageways, regardless of the number of lanes.'},
{id:56,cat:'rules',q:'What should you do when a traffic light changes to green?',opts:['Move off immediately','Check that the junction is clear before proceeding','Rev your engine and go','Sound your horn if the car in front does not move instantly'],ans:1,exp:'When the light turns green, check that the junction is clear before moving off. Pedestrians or vehicles may still be crossing.'},
{id:57,cat:'rules',q:'On a three-lane dual carriageway, which lane should you normally drive in?',opts:['The middle lane','The right-hand lane','The left-hand lane','Any lane you choose'],ans:2,exp:'You should normally drive in the left-hand lane of a dual carriageway. The other lanes are for overtaking.'},
{id:58,cat:'rules',q:'What should you do if you break down on a motorway?',opts:['Stop in the right-hand lane and put on your hazard lights','Try to reach the nearest exit or emergency area, or move to the hard shoulder if available','Call for help from the middle lane','Walk along the motorway to the nearest phone'],ans:1,exp:'If you break down, try to get your vehicle to the hard shoulder, an emergency area, or exit the motorway. Switch on your hazard lights and leave the vehicle from the left side if on the hard shoulder.'},
{id:59,cat:'rules',q:'What is the overall stopping distance at 70 mph in dry conditions?',opts:['53 metres','73 metres','96 metres','120 metres'],ans:2,exp:'At 70 mph, the overall stopping distance in dry conditions is approximately 96 metres (315 feet).'},
{id:60,cat:'rules',q:'When approaching a junction where the traffic lights have failed, what should you do?',opts:['Treat it as a give way junction and proceed with caution','Stop and wait for the lights to be repaired','Drive through at normal speed','Flash your lights to warn other drivers'],ans:0,exp:'If traffic lights are not working, treat the junction as an unmarked junction. Proceed with great caution and be prepared to give way.'},
{id:61,cat:'safety',q:'What is the overall stopping distance at 30 mph on a dry road?',opts:['14 metres (46 feet)','23 metres (75 feet)','36 metres (118 feet)','53 metres (175 feet)'],ans:1,exp:'At 30 mph the overall stopping distance is 23 metres (75 feet), combining thinking and braking distance.'},
{id:62,cat:'safety',q:'What is the overall stopping distance at 50 mph on a dry road?',opts:['36 metres (118 feet)','53 metres (175 feet)','73 metres (240 feet)','96 metres (315 feet)'],ans:1,exp:'At 50 mph the overall stopping distance is 53 metres (175 feet).'},
{id:63,cat:'safety',q:'What is the overall stopping distance at 70 mph on a dry road?',opts:['53 metres (175 feet)','73 metres (240 feet)','96 metres (315 feet)','120 metres (394 feet)'],ans:2,exp:'At 70 mph the overall stopping distance is 96 metres (315 feet).'},
{id:64,cat:'safety',q:'At 30 mph, what is the thinking distance on a dry road?',opts:['6 metres (20 feet)','9 metres (30 feet)','14 metres (46 feet)','21 metres (69 feet)'],ans:1,exp:'At 30 mph the thinking distance is 9 metres (30 feet).'},
{id:65,cat:'safety',q:'At 70 mph, what is the thinking distance on a dry road?',opts:['9 metres (30 feet)','15 metres (49 feet)','21 metres (69 feet)','30 metres (98 feet)'],ans:2,exp:'At 70 mph the thinking distance is 21 metres (69 feet).'},
{id:66,cat:'safety',q:'What is the braking distance at 30 mph on a dry road?',opts:['6 metres (20 feet)','9 metres (30 feet)','14 metres (46 feet)','23 metres (75 feet)'],ans:2,exp:'At 30 mph the braking distance is 14 metres (46 feet).'},
{id:67,cat:'safety',q:'What is the braking distance at 70 mph on a dry road?',opts:['38 metres (125 feet)','55 metres (180 feet)','75 metres (245 feet)','96 metres (315 feet)'],ans:2,exp:'At 70 mph the braking distance is 75 metres (245 feet).'},
{id:68,cat:'safety',q:'How much can wet roads increase your overall stopping distance?',opts:['It stays the same','It can double','It can triple','It can quadruple'],ans:1,exp:'On wet roads your overall stopping distance can at least double compared to dry conditions.'},
{id:69,cat:'safety',q:'How much can icy roads increase your braking distance?',opts:['Twice as far','Five times as far','Ten times as far','Twenty times as far'],ans:2,exp:'On icy roads your braking distance can increase by up to ten times.'},
{id:70,cat:'safety',q:'What is the legal alcohol limit for drivers in England and Wales?',opts:['50 mg per 100 ml of blood','80 mg per 100 ml of blood','100 mg per 100 ml of blood','35 mg per 100 ml of blood'],ans:1,exp:'The legal drink-drive limit in England and Wales is 80 mg of alcohol per 100 ml of blood.'},
{id:71,cat:'safety',q:'What is the legal alcohol limit for drivers in Scotland?',opts:['80 mg per 100 ml of blood','50 mg per 100 ml of blood','35 mg per 100 ml of blood','60 mg per 100 ml of blood'],ans:1,exp:'Scotland has a lower drink-drive limit of 50 mg of alcohol per 100 ml of blood.'},
{id:72,cat:'safety',q:'Even one alcoholic drink before driving can affect your ability to drive safely. What is the only safe option?',opts:['Drink coffee before driving','Eat a large meal to absorb the alcohol','Avoid alcohol altogether if you plan to drive','Wait 30 minutes after drinking'],ans:2,exp:'The only way to be sure you are safe to drive is to avoid alcohol completely before driving.'},
{id:73,cat:'safety',q:'How long can alcohol stay in your body after a heavy night of drinking?',opts:['Up to 6 hours','Up to 12 hours','Up to 18 hours','Up to 24 hours'],ans:2,exp:'Alcohol can remain in your system for up to 18 hours or longer after heavy drinking, meaning you may still be over the limit the morning after.'},
{id:74,cat:'safety',q:'What is the maximum penalty for causing death by dangerous driving while under the influence of alcohol?',opts:['5 years in prison','10 years in prison','14 years in prison','Life imprisonment'],ans:3,exp:'Causing death by dangerous driving can carry a maximum penalty of life imprisonment.'},
{id:75,cat:'safety',q:'Which of the following is a sign that you are too tired to drive safely?',opts:['Feeling hungry','Your eyes feel heavy and keep closing','Feeling too warm','Listening to quiet music'],ans:1,exp:'Heavy eyes that keep closing are a clear warning sign of driver fatigue and you should stop as soon as it is safe.'},
{id:76,cat:'safety',q:'What should you do if you feel drowsy while driving on a motorway?',opts:['Open the window and continue','Turn up the radio','Leave at the next exit or services, stop and rest','Speed up to reach your destination faster'],ans:2,exp:'You should leave the motorway at the next exit or service area, stop in a safe place, and take a break. Fresh air or loud music are not effective long-term solutions.'},
{id:77,cat:'safety',q:'How often should you take a break on a long journey to avoid tiredness?',opts:['Every 30 minutes','At least every two hours','Every four hours','Only when you feel tired'],ans:1,exp:'The Highway Code recommends taking a break of at least 15 minutes every two hours on long journeys.'},
{id:78,cat:'safety',q:'You feel sleepy while driving. You stop and drink two cups of coffee. What should you also do?',opts:['Continue driving immediately','Take a short nap of about 15 minutes','Splash cold water on your face and drive on','Walk briskly around the car once'],ans:1,exp:'After drinking caffeinated drinks, you should rest for about 15 minutes to allow the caffeine to take effect before continuing.'},
{id:79,cat:'safety',q:'When must you use your rear fog lights?',opts:['Whenever it rains','When visibility is seriously reduced, generally below 100 metres','At night on unlit roads','In light drizzle'],ans:1,exp:'Rear fog lights must only be used when visibility is seriously reduced to below 100 metres. Using them at other times can dazzle drivers behind you.'},
{id:80,cat:'safety',q:'You are driving in heavy fog. What should you do when you leave the fog?',opts:['Speed up immediately','Switch off your fog lights','Keep your fog lights on in case the fog returns','Flash your headlights'],ans:1,exp:'You must switch off your fog lights once visibility improves, as they can dazzle other drivers and obscure your brake lights.'},
{id:81,cat:'safety',q:'What does aquaplaning mean?',opts:['Your brakes overheat and stop working','Your tyres lose contact with the road surface due to water','Your steering locks because of ice','Your engine stalls in deep water'],ans:1,exp:'Aquaplaning occurs when a layer of water builds up between the tyre and the road surface, causing a loss of grip and steering control.'},
{id:82,cat:'safety',q:'What should you do if your vehicle starts to aquaplane?',opts:['Brake firmly','Steer sharply to regain grip','Ease off the accelerator and do not brake harshly','Accelerate to drive through the water'],ans:2,exp:'If you aquaplane you should ease off the accelerator gently and avoid harsh braking or steering until your tyres regain grip.'},
{id:83,cat:'safety',q:'What is the main danger of driving on black ice?',opts:['It is easy to see and avoid','Your engine will overheat','You may not be able to see it and your vehicle could skid','It only forms on bridges'],ans:2,exp:'Black ice is a thin, transparent layer of ice on the road that is very difficult to see, making it extremely dangerous.'},
{id:84,cat:'safety',q:'At what temperature is the road surface most likely to be icy?',opts:['At or below 0 degrees Celsius','Below minus 10 degrees Celsius','Below 5 degrees Celsius','Below minus 5 degrees Celsius'],ans:0,exp:'Roads can become icy at or below 0 degrees Celsius. However, be aware that ice can form even when the air temperature is slightly above freezing.'},
{id:85,cat:'safety',q:'When driving in snow, what gear should you use to pull away?',opts:['First gear','Second gear','Third gear','Reverse gear'],ans:1,exp:'Using second gear helps reduce wheel spin when pulling away on snow or ice by providing less torque to the wheels.'},
{id:86,cat:'safety',q:'By law, who is responsible for making sure a child under 14 wears a seat belt in a car?',opts:['The child themselves','The front seat passenger','The driver','The car owner'],ans:2,exp:'The driver is legally responsible for ensuring that all passengers under 14 years old wear a seat belt or use an appropriate child restraint.'},
{id:87,cat:'safety',q:'Up to what height must a child use an appropriate child car seat?',opts:['125 cm or 12 years old','135 cm or 12 years old','150 cm or 14 years old','120 cm or 10 years old'],ans:1,exp:'Children must use a child car seat until they are 135 cm tall or 12 years old, whichever comes first.'},
{id:88,cat:'safety',q:'When can an adult passenger legally travel without wearing a seat belt?',opts:['When sitting in the rear seat','When they have a valid medical exemption certificate','When travelling less than one mile','When the vehicle is travelling below 30 mph'],ans:1,exp:'An adult may only be exempt from wearing a seat belt if they hold a valid medical exemption certificate signed by a doctor.'},
{id:89,cat:'safety',q:'A rear-facing baby seat must never be placed in which position?',opts:['The rear seat behind the driver','The rear seat behind the passenger','A front seat protected by an active airbag','The centre rear seat'],ans:2,exp:'A rear-facing baby seat must never be used in a front seat with an active frontal airbag, as the airbag could cause serious injury or death to the child.'},
{id:90,cat:'safety',q:'What is the penalty for using a hand-held mobile phone while driving?',opts:['3 points and a £100 fine','6 penalty points and a £200 fine','4 penalty points and a £150 fine','2 penalty points and a £50 fine'],ans:1,exp:'Using a hand-held mobile phone while driving carries a fixed penalty of 6 points on your licence and a £200 fine.'},
{id:91,cat:'safety',q:'When is it legal to use a hand-held mobile phone while driving?',opts:['When stopped at traffic lights','When driving slowly in traffic','When you need to call 999 in a genuine emergency and it is unsafe to stop','When using it as a sat nav'],ans:2,exp:'You may only use a hand-held phone to call 999 or 112 in a genuine emergency when it is unsafe or impractical to stop.'},
{id:92,cat:'safety',q:'What effect does using a mobile phone have on your driving?',opts:['It has no significant effect','It improves your concentration','It significantly reduces your ability to concentrate and react','It only affects new drivers'],ans:2,exp:'Using a mobile phone while driving significantly reduces your concentration, reaction time, and ability to assess road conditions.'},
{id:93,cat:'safety',q:'New drivers who get 6 or more penalty points within two years of passing their test face what consequence?',opts:['A fine only','Their licence is revoked','A driving awareness course','A 3-month ban'],ans:1,exp:'New drivers who accumulate 6 or more penalty points within two years of passing their test will have their licence revoked and must retake both the theory and practical tests.'},
{id:94,cat:'safety',q:'What is the overall stopping distance at 20 mph on a dry road?',opts:['6 metres (20 feet)','9 metres (30 feet)','12 metres (40 feet)','14 metres (46 feet)'],ans:2,exp:'At 20 mph the overall stopping distance is 12 metres (40 feet).'},
{id:95,cat:'safety',q:'What is the overall stopping distance at 40 mph on a dry road?',opts:['23 metres (75 feet)','36 metres (118 feet)','53 metres (175 feet)','73 metres (240 feet)'],ans:1,exp:'At 40 mph the overall stopping distance is 36 metres (118 feet).'},
{id:96,cat:'safety',q:'What is the overall stopping distance at 60 mph on a dry road?',opts:['53 metres (175 feet)','73 metres (240 feet)','96 metres (315 feet)','112 metres (368 feet)'],ans:1,exp:'At 60 mph the overall stopping distance is 73 metres (240 feet).'},
{id:97,cat:'safety',q:'How does tiredness affect your reaction time?',opts:['It has no effect','It reduces reaction time slightly','It can significantly increase your reaction time','It improves focus'],ans:2,exp:'Tiredness significantly increases reaction time and impairs your ability to judge speed and distance, making you much more likely to be involved in a collision.'},
{id:98,cat:'safety',q:'When should you use dipped headlights rather than sidelights?',opts:['Only at night','When visibility is seriously reduced during the day','Only in fog','Only on motorways'],ans:1,exp:'You should use dipped headlights when visibility is seriously reduced during the day, for example in heavy rain, spray, mist, or fog.'},
{id:99,cat:'safety',q:'What effect can illegal drugs have on your driving?',opts:['They can improve reaction times','They have no effect if taken in small amounts','They can severely impair judgement, coordination, and reaction times','They only affect you if you feel drowsy'],ans:2,exp:'Illegal drugs can severely impair your judgement, coordination, and reaction times, making driving extremely dangerous. It is an offence to drive while unfit through drugs.'},
{id:100,cat:'safety',q:'What is the drug driving limit enforced by UK law?',opts:['There is no limit; any trace of illegal drugs is an offence','A high threshold similar to alcohol','The same as the alcohol limit','Drugs are not tested for'],ans:0,exp:'The UK has a zero-tolerance approach to illegal drugs and driving. Very low limits are set for illegal drugs, meaning any trace in your system could lead to prosecution.'},
{id:101,cat:'safety',q:'You are driving in heavy rain. Why should you increase your following distance?',opts:['Because your car uses more fuel in the rain','Because stopping distances increase on wet roads','Because your mirrors are harder to see','Because the speed limit is lower in rain'],ans:1,exp:'In heavy rain your stopping distance can at least double, so you should leave a greater gap between your vehicle and the one in front.'},
{id:102,cat:'safety',q:'What should you do before driving through a ford or flood water?',opts:['Drive through as fast as possible','Stop and check the depth of the water','Sound your horn to warn others','Only cross if another vehicle is already in the water'],ans:1,exp:'Before driving through a ford or flood water you should stop and assess the depth. If it is too deep your vehicle could stall or be swept away.'},
{id:103,cat:'safety',q:'After driving through a flood, what should you do?',opts:['Continue driving normally','Test your brakes gently','Accelerate hard to dry them','Turn off your headlights'],ans:1,exp:'After driving through water you should test your brakes gently to make sure they are working properly. Water can reduce their effectiveness.'},
{id:104,cat:'safety',q:'In very hot weather, what can happen to the road surface?',opts:['The road becomes stronger','The surface can soften and become slippery','The road surface cools down','There is no effect on the road'],ans:1,exp:'In very hot weather the road surface can soften and melt, reducing tyre grip and increasing the risk of skidding.'},
{id:105,cat:'safety',q:'What is the safest way to use a sat nav while driving?',opts:['Programme it while driving slowly','Have a passenger set the destination','Set the destination before you start your journey','Hold it in one hand while driving'],ans:2,exp:'You should always set your sat nav destination before starting your journey. Adjusting it while driving is dangerous and could count as a distraction offence.'},
{id:106,cat:'safety',q:'What is the minimum tread depth required by law for car tyres?',opts:['1 mm across the central three-quarters of the tyre','1.6 mm across the central three-quarters of the tyre','2 mm across the whole tyre','0.8 mm across the whole tyre'],ans:1,exp:'The legal minimum tread depth for car tyres is 1.6 mm across the central three-quarters of the breadth and around the entire circumference.'},
{id:107,cat:'safety',q:'When are you allowed to drive with only your sidelights on?',opts:['On any road at night','On a road with a speed limit of 30 mph or less with street lighting','On a motorway','Never; you must always use headlights at night'],ans:1,exp:'You may park or drive using only sidelights on roads with a speed limit of 30 mph or less that have street lighting.'},
{id:108,cat:'safety',q:'What should you do if your vehicle breaks down on a motorway?',opts:['Stay in your vehicle with your seat belt on','Get out and stand behind your vehicle','Move to the left, get out on the left side, and wait behind the barrier','Call a friend for help before contacting the emergency services'],ans:2,exp:'If you break down on a motorway you should pull onto the hard shoulder or emergency area, get out via the left-hand door, and wait behind the safety barrier away from traffic.'},
{id:109,cat:'safety',q:'Prescription medicines can affect your ability to drive safely. What should you do?',opts:['Ignore the warning labels','Check with your doctor or pharmacist whether they may affect your driving','Only take half the dose before driving','Stop taking the medicine entirely'],ans:1,exp:'Always check with your doctor or pharmacist whether your prescription medicine could impair your driving. Some medications cause drowsiness or affect reaction times.'},
{id:110,cat:'safety',q:'What is the recommended minimum following distance in dry conditions at normal speeds?',opts:['One second','Two seconds','Three seconds','Four seconds'],ans:1,exp:'In dry conditions you should keep at least a two-second gap between you and the vehicle in front. In wet conditions this should be doubled to four seconds.'},
{id:111,cat:'vehicle',q:'What is the minimum legal tyre tread depth across the central three-quarters of a car tyre in the UK?',opts:['1.0 mm','1.6 mm','2.0 mm','2.5 mm'],ans:1,exp:'The legal minimum tyre tread depth in the UK is 1.6 mm across the central three-quarters of the tread width around the entire circumference.'},
{id:112,cat:'vehicle',q:'When should you check your tyre pressures?',opts:['Only before an MOT test','When the tyres are hot after a long journey','When the tyres are cold before a journey','Only when a warning light appears'],ans:2,exp:'Tyre pressures should be checked when the tyres are cold, as heat from driving increases pressure and gives an inaccurate reading.'},
{id:113,cat:'vehicle',q:'What colour is the engine coolant temperature warning light on your dashboard?',opts:['Green','Blue','Red','Yellow'],ans:2,exp:'The engine coolant temperature warning light is red, indicating the engine is overheating and you should stop as soon as it is safe to do so.'},
{id:114,cat:'vehicle',q:'At what age must a car first have an MOT test in the UK?',opts:['One year old','Two years old','Three years old','Four years old'],ans:2,exp:'Cars must have their first MOT test when they are three years old, and then every year after that.'},
{id:115,cat:'vehicle',q:'What could happen if you drive with seriously under-inflated tyres?',opts:['Improved fuel economy','Better grip in wet conditions','The vehicle handling will be affected and braking distance increased','The tyres will last longer'],ans:2,exp:'Under-inflated tyres affect steering and handling, increase braking distances, and can overheat, leading to tyre failure.'},
{id:116,cat:'vehicle',q:'How often should you check the engine oil level in your vehicle?',opts:['Only at service intervals','Regularly, such as weekly or before a long journey','Once a year','Only when the oil warning light comes on'],ans:1,exp:'You should check your engine oil level regularly and always before a long journey to prevent engine damage from low oil levels.'},
{id:117,cat:'vehicle',q:'What does a red oil pressure warning light on the dashboard mean?',opts:['The oil needs changing at the next service','The oil filter is due for replacement','You should stop and check the oil level as soon as it is safe','The engine is running at the correct temperature'],ans:2,exp:'A red oil pressure warning light means oil pressure is dangerously low. You should stop as soon as safely possible and check the oil level.'},
{id:118,cat:'vehicle',q:'When are you permitted to use front fog lights?',opts:['At any time during the night','When visibility is seriously reduced, generally below 100 metres','Whenever it is raining','In built-up areas to be more visible'],ans:1,exp:'Front fog lights should only be used when visibility is seriously reduced to below 100 metres. Using them at other times can dazzle other drivers.'},
{id:119,cat:'vehicle',q:'What must you do by law after using rear fog lights when visibility improves?',opts:['Leave them on until you reach your destination','Switch them off','Reduce your speed further','Flash your headlights'],ans:1,exp:'You must switch off rear fog lights when visibility improves, as they can dazzle drivers behind you and mask your brake lights.'},
{id:120,cat:'vehicle',q:'What is the purpose of the anti-lock braking system (ABS) in a vehicle?',opts:['To reduce the overall braking distance','To allow you to continue steering while braking hard','To make the brakes more powerful','To prevent wear on the brake pads'],ans:1,exp:'ABS prevents the wheels from locking during heavy braking, allowing the driver to maintain steering control.'},
{id:121,cat:'vehicle',q:'What should you do if the brake fluid level in the reservoir is below the minimum mark?',opts:['Top it up with engine oil','Top it up with the correct brake fluid and have the system checked','It is normal and does not need attention','Add water to bring it to the correct level'],ans:1,exp:'Low brake fluid could indicate a leak or worn brake pads. Top up with the correct fluid and have the braking system inspected.'},
{id:122,cat:'vehicle',q:'What effect does a worn exhaust system have on your vehicle?',opts:['It improves engine performance','It increases harmful emissions and may cause excessive noise','It reduces fuel consumption','It has no significant effect'],ans:1,exp:'A worn or damaged exhaust system can increase harmful emissions and noise levels, and may cause you to fail an MOT test.'},
{id:123,cat:'vehicle',q:'When must you use your headlights?',opts:['Only on motorways at night','Between sunset and sunrise and in seriously reduced visibility','Only in fog','Only when other vehicles have their lights on'],ans:1,exp:'You must use headlights between sunset and sunrise and at any time when visibility is seriously reduced.'},
{id:124,cat:'vehicle',q:'What could be the cause if your vehicle pulls to one side when braking?',opts:['The tyres are correctly inflated','The steering wheel needs adjusting','There may be a brake fault on one side','The suspension is working correctly'],ans:2,exp:'If a vehicle pulls to one side under braking, it usually indicates uneven braking, possibly due to a seized caliper, worn pads, or a hydraulic fault on one side.'},
{id:125,cat:'vehicle',q:'How can you tell if your vehicle\'s battery is failing?',opts:['The engine runs more quietly','The vehicle is harder to start, especially in cold weather','Fuel consumption improves','The exhaust produces white smoke'],ans:1,exp:'A failing battery often makes the engine difficult to start, particularly in cold weather, and electrical systems may also become unreliable.'},
{id:126,cat:'vehicle',q:'What does a catalytic converter do?',opts:['Filters particles from diesel exhaust','Reduces harmful exhaust emissions by converting them into less toxic gases','Increases engine power output','Cools the exhaust gases before they leave the vehicle'],ans:1,exp:'A catalytic converter reduces harmful gases such as carbon monoxide and nitrogen oxides by converting them into less harmful substances.'},
{id:127,cat:'vehicle',q:'You notice your windscreen wipers are leaving smears across the glass. What should you do?',opts:['Ignore it until the next service','Replace the wiper blades','Use the wipers on a faster setting','Apply engine oil to the wiper blades'],ans:1,exp:'Smearing wipers indicate worn blades that are not clearing the windscreen effectively. They should be replaced to maintain clear visibility.'},
{id:128,cat:'vehicle',q:'What is the legal requirement for the condition of your vehicle\'s windscreen?',opts:['Small chips are acceptable anywhere on the windscreen','The windscreen must provide the driver with a clear view of the road','Tinted windscreens do not need to meet any standard','Cracks are permitted if they are not in the driver\'s line of sight'],ans:1,exp:'The windscreen must give the driver a clear, unobstructed view of the road. Damage in the swept area can cause an MOT failure.'},
{id:129,cat:'vehicle',q:'What should you do if the engine coolant level is low?',opts:['Top it up with the correct coolant mixture when the engine is cool','Add cold water immediately while the engine is hot','Drive to the nearest garage regardless','Ignore it as long as the warning light is not on'],ans:0,exp:'Never remove the coolant cap when the engine is hot as pressurised steam can cause burns. Wait for the engine to cool, then top up with the correct coolant mixture.'},
{id:130,cat:'vehicle',q:'What items are checked during an MOT test?',opts:['Only the engine and gearbox','Lights, brakes, steering, tyres, exhaust emissions, and other safety items','Interior cleanliness and paintwork condition','Only the items listed in the vehicle handbook'],ans:1,exp:'The MOT test covers essential safety and environmental items including lights, brakes, steering, suspension, tyres, seatbelts, and exhaust emissions.'},
{id:131,cat:'vehicle',q:'When should you use your hazard warning lights?',opts:['When double-parking for a short time','When your vehicle has broken down and is causing an obstruction','When driving slowly in the left lane of a motorway','When overtaking on a dual carriageway'],ans:1,exp:'Hazard warning lights should be used to warn other road users that your vehicle is a temporary obstruction, for example if you have broken down.'},
{id:132,cat:'vehicle',q:'What does excessive black smoke from a diesel engine exhaust usually indicate?',opts:['The engine is running efficiently','The fuel system may be faulty, causing incomplete combustion','The catalytic converter is working correctly','The vehicle has recently had an oil change'],ans:1,exp:'Black smoke from a diesel exhaust indicates the fuel is not being burned completely, which can be caused by a faulty injector, air filter, or turbo.'},
{id:133,cat:'vehicle',q:'Why is it important to maintain the correct engine oil level?',opts:['It has no effect on the engine','It lubricates moving parts, reduces friction, and helps cool the engine','It only affects the colour of the exhaust smoke','It prevents the battery from going flat'],ans:1,exp:'Engine oil lubricates and cools the moving parts of the engine. Running with low oil can cause serious and expensive engine damage.'},
{id:134,cat:'vehicle',q:'What might a spongy feeling when you press the brake pedal suggest?',opts:['The brakes are working perfectly','There may be air in the hydraulic braking system','The brake pads are new','The ABS system is activated'],ans:1,exp:'A spongy brake pedal often indicates air in the hydraulic brake lines or a fluid leak, both of which require immediate attention.'},
{id:135,cat:'vehicle',q:'How does an incorrectly adjusted headlight affect other road users?',opts:['It has no effect','It can dazzle oncoming drivers, reducing their visibility','It improves your visibility at night','It only affects your own vision'],ans:1,exp:'Incorrectly adjusted headlights can dazzle other road users and create a dangerous situation. They should be properly aligned.'},
{id:136,cat:'vehicle',q:'What is the purpose of power steering fluid?',opts:['To lubricate the engine cylinders','To allow the steering to operate smoothly with reduced effort','To cool the braking system','To improve tyre grip on wet roads'],ans:1,exp:'Power steering fluid transmits hydraulic pressure to assist steering, making it easier to turn the wheel, especially at low speeds.'},
{id:137,cat:'vehicle',q:'What should you check before setting off on a long journey?',opts:['Only that you have enough fuel','Oil, coolant, tyre pressures and condition, lights, and windscreen washer fluid','Only the tyre pressures','Only the windscreen wipers'],ans:1,exp:'Before a long journey you should carry out basic vehicle checks including oil, coolant, tyres, lights, and washer fluid to reduce the risk of a breakdown.'},
{id:138,cat:'vehicle',q:'What does a flashing red battery warning light on the dashboard usually indicate?',opts:['The battery is fully charged','There may be a fault with the charging system','The headlights are on','The engine oil is low'],ans:1,exp:'A battery warning light indicates the battery is not being charged properly, often due to a fault with the alternator or drive belt.'},
{id:139,cat:'vehicle',q:'Why should you avoid mixing different types of brake fluid?',opts:['It makes no difference what type you use','Different types can react together and cause brake failure','Mixing them improves braking performance','It only affects the colour of the fluid'],ans:1,exp:'Mixing incompatible brake fluids can cause seals to deteriorate and may lead to brake failure. Always use the type specified by the manufacturer.'},
{id:140,cat:'vehicle',q:'What is the main cause of brake fade?',opts:['Driving in cold weather','Continuous or heavy braking causing the brakes to overheat','Using the handbrake too often','Braking gently on a dry road'],ans:1,exp:'Brake fade occurs when excessive heat builds up from prolonged or repeated heavy braking, reducing the effectiveness of the brakes.'},
{id:141,cat:'vehicle',q:'What should you do if your vehicle\'s head restraint is incorrectly adjusted?',opts:['Remove it completely','Adjust it so the centre is at least level with your eyes','Leave it as it is','Lower it as far as possible'],ans:1,exp:'A correctly adjusted head restraint should be positioned so its centre is at least at eye level to protect against whiplash injuries in a rear-end collision.'},
{id:142,cat:'vehicle',q:'What is the legal requirement for the use of seatbelts in the UK?',opts:['Only the driver must wear one','All occupants must wear a seatbelt where one is fitted, unless a valid exemption applies','Rear passengers do not need to wear seatbelts','Seatbelts are optional on short journeys'],ans:1,exp:'By law, all vehicle occupants must wear a seatbelt where one is available. The driver is responsible for ensuring passengers under 14 are belted.'},
{id:143,cat:'vehicle',q:'What could cause your steering to feel heavy?',opts:['Over-inflated tyres','Under-inflated tyres or a fault with the power steering system','Driving at high speed on a motorway','Having passengers in the vehicle'],ans:1,exp:'Heavy steering can be caused by under-inflated tyres, low power steering fluid, or a power steering pump failure.'},
{id:144,cat:'vehicle',q:'When is it acceptable to drive with a broken exhaust pipe?',opts:['Never, it should be repaired before driving','Only on short journeys','Only during the daytime','Only if you drive slowly'],ans:0,exp:'A broken exhaust can leak dangerous fumes into the cabin including carbon monoxide, and may cause you to fail an MOT. It should be repaired promptly.'},
{id:145,cat:'vehicle',q:'What does the tyre pressure monitoring system (TPMS) warning light indicate?',opts:['Your tyres need replacing','One or more of your tyres may be significantly under-inflated','Your tyres are over-inflated','The tread depth is too low'],ans:1,exp:'The TPMS warning light alerts you that one or more tyres have dropped significantly below the recommended pressure and should be checked immediately.'},
{id:146,cat:'vehicle',q:'How can you reduce the exhaust emissions from your vehicle?',opts:['Drive in a lower gear at all times','Have the vehicle serviced regularly and maintain correct tyre pressures','Only drive at night','Remove the catalytic converter'],ans:1,exp:'Regular servicing ensures the engine runs efficiently, and correct tyre pressures reduce rolling resistance, both of which help lower emissions.'},
{id:147,cat:'vehicle',q:'What is the purpose of the vehicle\'s differential?',opts:['To increase top speed','To allow the driven wheels to rotate at different speeds when cornering','To improve fuel economy on motorways','To reduce exhaust emissions'],ans:1,exp:'The differential allows the outer wheel to turn faster than the inner wheel when cornering, improving handling and reducing tyre wear.'},
{id:148,cat:'vehicle',q:'Why should windscreen washer fluid be kept topped up?',opts:['It is only needed for the MOT test','A clean windscreen is essential for clear visibility and safe driving','It cools the engine','It prevents the wipers from wearing out'],ans:1,exp:'Windscreen washer fluid is essential for clearing dirt, insects, and road spray from the windscreen to maintain good visibility.'},
{id:149,cat:'vehicle',q:'What should you do if an amber engine management warning light stays on while driving?',opts:['Ignore it as amber lights are not urgent','Have the vehicle checked by a qualified mechanic as soon as possible','Immediately stop and turn off the engine','Increase speed to clear the fault'],ans:1,exp:'An amber engine management light indicates a fault that needs professional diagnosis. It may affect emissions or engine performance. Have it checked promptly.'},
{id:150,cat:'vehicle',q:'What happens if you continue to drive when the brake pads are excessively worn?',opts:['Braking improves over time','The brake discs can become damaged, increasing repair costs and reducing braking efficiency','The brakes become self-adjusting','Fuel consumption is reduced'],ans:1,exp:'Worn brake pads can damage the brake discs and significantly reduce braking effectiveness, making the vehicle unsafe to drive.'},
{id:151,cat:'signs',q:'What does a triangular sign with a red border and an exclamation mark mean?',opts:['Speed limit ahead','Other danger ahead','No entry','Road works ahead'],ans:1,exp:'A triangular sign with a red border and an exclamation mark warns of other danger not covered by specific warning signs. A plate beneath will indicate the nature of the danger.'},
{id:152,cat:'signs',q:'What shape is a stop sign?',opts:['Circular','Triangular','Octagonal','Rectangular'],ans:2,exp:'The stop sign is the only octagonal sign used on UK roads. Its unique shape makes it recognisable even when covered in snow or dirt.'},
{id:153,cat:'signs',q:'What does a circular sign with a red border and no symbol inside mean?',opts:['National speed limit applies','No vehicles allowed','End of restriction','No waiting'],ans:0,exp:'A white circular sign with a red border and no other markings indicates that the national speed limit applies on that road.'},
{id:154,cat:'signs',q:'What does a \'give way\' sign look like?',opts:['A red octagon','An inverted white triangle with a red border','A blue circle','A green rectangle'],ans:1,exp:'The give way sign is an inverted triangle with a red border. Its unique upside-down shape helps drivers recognise it even from behind.'},
{id:155,cat:'signs',q:'What do blue circular signs generally indicate?',opts:['Prohibitions','Warnings','Positive instructions or mandatory requirements','Tourist information'],ans:2,exp:'Blue circular signs give positive instructions, such as minimum speed limits, keep left, or turn left ahead. They tell you what you must do.'},
{id:156,cat:'signs',q:'What does a red circular sign with a white horizontal bar mean?',opts:['No overtaking','No entry','No waiting','Road closed'],ans:1,exp:'A red circle with a white horizontal bar means no entry for vehicular traffic. You must not drive past this sign.'},
{id:157,cat:'signs',q:'What colour background do motorway signs have?',opts:['Green','White','Blue','Brown'],ans:2,exp:'Motorway signs have a blue background. This distinguishes them from primary route signs which have green backgrounds.'},
{id:158,cat:'signs',q:'What colour background do primary route signs have?',opts:['Blue','Brown','White','Green'],ans:3,exp:'Primary route direction signs have green backgrounds with white text and yellow route numbers.'},
{id:159,cat:'signs',q:'What do brown signs with white text indicate?',opts:['Motorway directions','Tourist attractions','Temporary warnings','Hospital directions'],ans:1,exp:'Brown signs with white lettering are used to direct traffic to tourist attractions and facilities of interest.'},
{id:160,cat:'signs',q:'What does a triangular sign showing two bumps mean?',opts:['Uneven road surface ahead','Speed bumps ahead','Bridge ahead','Dual carriageway ahead'],ans:0,exp:'This triangular warning sign alerts drivers to an uneven road surface ahead so they can reduce speed.'},
{id:161,cat:'signs',q:'What do double white lines along the centre of the road mean when the line nearest you is solid?',opts:['You may cross the lines to overtake if safe','You must not cross or straddle the solid line','You may park on the opposite side','The road is one way'],ans:1,exp:'When the white line nearest to you is solid, you must not cross or straddle it except to enter premises or a side road.'},
{id:162,cat:'signs',q:'What does a broken white centre line along the road indicate?',opts:['No overtaking','You may cross it if the road is clear','Cycle lane boundary','Edge of the carriageway'],ans:1,exp:'A broken white centre line marks the middle of the road. You may cross it to overtake if the road ahead is clear and it is safe to do so.'},
{id:163,cat:'signs',q:'What do yellow criss-cross lines painted on the road at a junction indicate?',opts:['Parking area','Pedestrian crossing','Box junction - do not enter unless your exit is clear','Speed reduction zone'],ans:2,exp:'Yellow box junction markings mean you must not enter the box unless your exit road is clear. The exception is when turning right and only oncoming traffic is preventing you.'},
{id:164,cat:'signs',q:'What do countdown markers beside the road show?',opts:['Distance to the next service station','Distance to the start of a motorway exit slip road','Speed limit changing ahead','Distance to the next town'],ans:1,exp:'Countdown markers show three, two, then one diagonal stripe at 300, 200, and 100 yards before a motorway exit. They help you prepare to leave the motorway.'},
{id:165,cat:'signs',q:'What does a triangular sign with a picture of a car skidding mean?',opts:['Slippery road ahead','Sports car zone','Car park ahead','Oil on the road'],ans:0,exp:'This warning sign indicates a slippery road surface ahead. Reduce your speed and avoid harsh braking, steering, or acceleration.'},
{id:166,cat:'signs',q:'What shape are regulatory prohibition signs in the UK?',opts:['Triangular','Rectangular','Circular with a red border','Octagonal'],ans:2,exp:'Prohibition signs are circular with a red border. They tell you what you must not do, such as no right turn or no overtaking.'},
{id:167,cat:'signs',q:'What does a circular sign with a red border showing a bicycle mean?',opts:['Cycle route ahead','Cycle lane only','No cycling','Bicycle parking'],ans:2,exp:'A red circle with a bicycle symbol means cycling is prohibited on that road or path.'},
{id:168,cat:'signs',q:'What does a blue rectangular sign with a white letter P mean?',opts:['Police station','Petrol station','Parking available','Post office'],ans:2,exp:'A blue rectangular sign with a white letter P indicates that parking is available at or near that location.'},
{id:169,cat:'signs',q:'What does a triangular warning sign with a train symbol mean?',opts:['Train station ahead','Level crossing without a barrier ahead','No trains','Railway museum'],ans:1,exp:'This warning sign alerts you to a level crossing without a barrier or gate ahead. Be prepared to stop if lights flash or a train approaches.'},
{id:170,cat:'signs',q:'What do chevron signs on bends indicate?',opts:['The road is closed ahead','The direction of a sharp bend in the road','A change in speed limit','Road works are in progress'],ans:1,exp:'Chevron signs with black and white arrows are placed on sharp bends to guide you around the curve and indicate its direction.'},
{id:171,cat:'signs',q:'What does a circular blue sign showing a number 30 mean?',opts:['Maximum speed 30 mph','Minimum speed 30 mph','Recommended speed 30 mph','Speed limit ends in 30 metres'],ans:1,exp:'A blue circular sign with a number indicates a minimum speed limit. You must not drive slower than the speed shown.'},
{id:172,cat:'signs',q:'What does a circular sign with a red border and two cars side by side mean?',opts:['Two lanes ahead','Dual carriageway begins','No overtaking','Cars may park two abreast'],ans:2,exp:'This prohibition sign means no overtaking. You must not overtake the vehicle in front of you until you pass a sign cancelling the restriction.'},
{id:173,cat:'signs',q:'What does a triangular sign showing falling rocks mean?',opts:['Quarry entrance ahead','Risk of falling or fallen rocks ahead','Cliff edge ahead','No heavy vehicles'],ans:1,exp:'This warning sign alerts you to the risk of falling or fallen rocks on the road ahead. Drive carefully and watch for debris.'},
{id:174,cat:'signs',q:'What does a one-way street sign look like?',opts:['A red circle with a white arrow','A blue rectangular sign with a white arrow','A green triangular sign','A white diamond'],ans:1,exp:'A one-way street is indicated by a blue rectangular sign with a white arrow showing the direction of traffic flow.'},
{id:175,cat:'signs',q:'What does a triangular sign with a picture of children mean?',opts:['Playground area - no vehicles','School crossing patrol ahead','Children likely to be crossing the road ahead','No children allowed'],ans:2,exp:'This warning sign indicates an area where children are likely to cross or be near the road, such as near a school or playground.'},
{id:176,cat:'signs',q:'What does a speed limit sign with a diagonal line through the number mean?',opts:['The speed limit shown now applies','End of the speed limit shown','Double the speed limit applies','Advisory speed only'],ans:1,exp:'A speed limit sign with a diagonal line through the number means that particular speed restriction has ended. The national speed limit or another limit then applies.'},
{id:177,cat:'signs',q:'What does a triangular sign showing a T-junction mean?',opts:['Telephone ahead','T-junction ahead where you must give way','Traffic lights ahead','Tram crossing'],ans:1,exp:'This warning sign tells you a T-junction is ahead. The road you are on ends and you must turn left or right, giving way to traffic on the through road.'},
{id:178,cat:'signs',q:'What does a triangular sign showing two-way arrows mean?',opts:['Dual carriageway ahead','Two-way traffic crosses a one-way road','Road narrows on both sides','Two-way traffic ahead on the road you are using'],ans:3,exp:'This sign warns that two-way traffic lies ahead, typically placed where a one-way street or dual carriageway ends and becomes a two-way single carriageway.'},
{id:179,cat:'signs',q:'What does a red circle with a diagonal line through a horn symbol mean?',opts:['Sound your horn to warn others','No audible warning devices allowed','Horn testing area','Emergency vehicles only'],ans:1,exp:'This sign means you must not sound your horn. It is often found near hospitals and in quiet zones, usually applying during certain hours.'},
{id:180,cat:'signs',q:'What do white diagonal hatching markings bordered by a broken white line mean?',opts:['You must not enter this area','You should not enter unless it is necessary and safe','Bus lane only','Cycle lane marking'],ans:1,exp:'Diagonal white hatching bordered by a broken line is an area you should not enter unless it is necessary and you can see it is safe to do so.'},
{id:181,cat:'signs',q:'What do white diagonal hatching markings bordered by a solid white line mean?',opts:['Parking area','You must not enter this area except in an emergency','Pedestrian zone','Temporary road surface'],ans:1,exp:'When diagonal hatching is bordered by a solid white line, you must not enter the area except in an emergency.'},
{id:182,cat:'signs',q:'What does a triangular sign showing a gate or fence mean?',opts:['Farm entrance ahead','Gated road ahead','Level crossing with barrier or gate ahead','Private road'],ans:2,exp:'This sign warns of a level crossing with a barrier or gate ahead. Be prepared to stop when the barrier is down or the lights are flashing.'},
{id:183,cat:'signs',q:'What does a circular sign with a red border showing 7.5T mean?',opts:['Maximum weight 7.5 tonnes allowed','Minimum weight 7.5 tonnes required','Bridge weight limit 7.5 tonnes','No vehicles over 7.5 tonnes maximum gross weight'],ans:3,exp:'This prohibition sign means vehicles exceeding 7.5 tonnes maximum gross weight are not permitted on that road.'},
{id:184,cat:'signs',q:'What does a triangular sign showing a steep hill with a percentage mean?',opts:['Road gradient percentage for planning purposes','Steep hill downwards ahead','Percentage of traffic using the road','Gradient of road camber'],ans:1,exp:'This warning sign shows a steep hill descending ahead with the gradient shown as a percentage. Use a low gear and be prepared to brake.'},
{id:185,cat:'signs',q:'What does a blue circle with a white bicycle symbol mean?',opts:['No cycling','Bicycle parking only','Route to be used by pedal cycles only','Cycle repair shop ahead'],ans:2,exp:'A blue circular sign with a bicycle symbol is a mandatory sign meaning the route must be used by pedal cycles only.'},
{id:186,cat:'signs',q:'What does a triangular sign with a windsock symbol mean?',opts:['Airport ahead','Kite flying area','Side winds likely ahead','Parachute drop zone'],ans:2,exp:'This warning sign alerts you to the likelihood of strong side winds ahead, often found on exposed bridges or hillside roads.'},
{id:187,cat:'signs',q:'What does a triangular sign showing a queue of cars mean?',opts:['Car park ahead','Traffic queues likely ahead','Funeral procession route','Multi-storey car park'],ans:1,exp:'This sign warns that traffic queues are likely ahead. Be prepared to slow down or stop and avoid being caught out by stationary vehicles.'},
{id:188,cat:'signs',q:'What does a circular blue sign with a white arrow pointing up mean?',opts:['One-way street','No entry from the opposite direction','Ahead only - you must proceed straight ahead','Maximum height limit'],ans:2,exp:'A blue circle with a white upward arrow means ahead only. You must continue straight ahead and not turn left or right.'},
{id:189,cat:'signs',q:'What does a red circle with a red X on a motorway overhead gantry mean?',opts:['Lane ahead is temporarily narrowed','Lane is closed - do not use this lane','Slow down to 40 mph','Roadworks in this lane'],ans:1,exp:'A red X on an overhead gantry means the lane is closed. You must not drive in a lane showing a red X and should move to an open lane safely.'},
{id:190,cat:'signs',q:'What does a triangular sign showing a hump bridge mean?',opts:['Speed hump ahead','Hump bridge ahead','Road rises steeply','Tunnel ahead'],ans:1,exp:'This warning sign tells you a hump bridge is ahead. Slow down and be prepared for oncoming vehicles in the centre of the road as visibility is restricted.'},
{id:191,cat:'signs',q:'What does a circular sign with a red border showing a left-turn arrow with a line through it mean?',opts:['Turn left only','Left lane closed','No left turn','Diversion to the left'],ans:2,exp:'A red circle with a left-turn arrow crossed out means no left turn is permitted at that junction.'},
{id:192,cat:'signs',q:'What does a triangular sign showing a zigzag line mean?',opts:['Winding road ahead','Series of bends ahead','River crossing','Mountain road ahead'],ans:1,exp:'This warning sign indicates a series of bends in the road ahead. Reduce your speed and be prepared for the changing road direction.'},
{id:193,cat:'signs',q:'What does a rectangular green sign on a non-motorway road usually indicate?',opts:['Tourist attraction','Primary route direction','Motorway junction','Temporary diversion'],ans:1,exp:'Green rectangular signs on non-motorway roads indicate primary route directions. They display route numbers and destinations.'},
{id:194,cat:'signs',q:'What does a triangular sign with an elderly couple symbol mean?',opts:['Retirement home ahead','Elderly people\'s crossing ahead','No elderly pedestrians','Heritage site ahead'],ans:1,exp:'This warning sign indicates a place where elderly or infirm pedestrians are likely to cross the road. Drive carefully and be ready to stop.'},
{id:195,cat:'signs',q:'What do zig-zag white lines at a pedestrian crossing mean?',opts:['You may park here briefly','You must not park or wait on these lines','Speed bumps ahead','Give way to oncoming traffic'],ans:1,exp:'Zig-zag white lines at pedestrian crossings mean you must not park or wait on them. They keep the area clear so pedestrians and drivers can see each other.'},
{id:196,cat:'signs',q:'What does a triangular sign with a lightning bolt symbol mean?',opts:['Electric vehicle charging point','Overhead electric cable ahead','Power station ahead','Risk of electric shock'],ans:1,exp:'This warning sign indicates overhead electric cables ahead, usually at a height that could be hazardous to high vehicles.'},
{id:197,cat:'signs',q:'What does a circular sign with a red border showing the number 40 mean?',opts:['Minimum speed 40 mph','Recommended speed 40 mph','Maximum speed 40 mph','Speed limit changes in 40 metres'],ans:2,exp:'A red circular sign with a number indicates the maximum speed limit in miles per hour. You must not exceed 40 mph on that stretch of road.'},
{id:198,cat:'signs',q:'What does a triangular sign with a deer symbol mean?',opts:['Deer park entrance','Wild animals likely on the road ahead','No hunting zone','Safari park ahead'],ans:1,exp:'This warning sign alerts you that wild animals, particularly deer, may be on or crossing the road ahead. Be vigilant especially at dawn and dusk.'},
{id:199,cat:'signs',q:'What does a blue circle with two white arrows showing opposing directions mean?',opts:['Two-way traffic ahead','Vehicles may pass either side to reach the same destination','No overtaking','Dual carriageway begins'],ans:1,exp:'A blue circular sign with two arrows pointing in different directions around a central island means vehicles may pass either side to reach the same destination.'},
{id:200,cat:'signs',q:'What do short broken white lines along the centre of the road mean?',opts:['Hazard ahead - do not cross','Edge of the carriageway','Lane markings on a multi-lane road','No parking zone'],ans:2,exp:'Short broken white lines are used as lane markings on roads with multiple lanes going in the same direction, guiding drivers to stay within their lane.'},
{id:201,cat:'hazards',q:'What is the recommended minimum following distance in good, dry conditions?',opts:['At least a one-second gap','At least a two-second gap','At least a three-second gap','At least a four-second gap'],ans:1,exp:'The two-second rule gives you a safe following distance in dry conditions.'},
{id:202,cat:'hazards',q:'You are driving past a parked ice cream van. What should you be especially aware of?',opts:['The van may pull out without signalling','Children may run out from behind the van','The driver may open their door suddenly','The van may be illegally parked'],ans:1,exp:'Children are often excited and may run out into the road without looking, especially near ice cream vans.'},
{id:203,cat:'hazards',q:'When should you use the Mirror-Signal-Manoeuvre routine?',opts:['Only when turning left or right','Only when overtaking other vehicles','Before any change in speed or direction','Only when approaching traffic lights'],ans:2,exp:'The MSM routine should be used before any change in speed or direction to ensure safety.'},
{id:204,cat:'hazards',q:'What should you do when approaching an unmarked crossroads?',opts:['Speed up to get through quickly','Assume you have right of way','Slow down and be ready to give way','Flash your headlights to claim priority'],ans:2,exp:'At an unmarked crossroads, no one has priority. You should slow down and be prepared to give way.'},
{id:205,cat:'hazards',q:'In wet weather, how should you adjust your following distance?',opts:['Keep the same two-second gap','Double it to at least four seconds','Increase it to at least three seconds','Reduce it to one second'],ans:1,exp:'In wet conditions, stopping distances are at least double, so you should allow at least a four-second gap.'},
{id:206,cat:'hazards',q:'You notice a vehicle behind you is tailgating. What should you do?',opts:['Brake sharply to warn them','Speed up to increase the gap','Gradually increase the gap ahead of you','Move to the hard shoulder'],ans:2,exp:'By increasing the gap ahead, you allow more time to brake gently, reducing the risk of the tailgater hitting you.'},
{id:207,cat:'hazards',q:'What is a major hazard when driving at night on an unlit road?',opts:['Your fuel consumption increases','Pedestrians and cyclists are harder to see','Your engine overheats more easily','Road surfaces are smoother at night'],ans:1,exp:'At night, pedestrians and cyclists wearing dark clothing are very difficult to see on unlit roads.'},
{id:208,cat:'hazards',q:'When should you check your mirrors?',opts:['Only when changing lanes','Only before turning','Regularly and before any change of speed or direction','Only when reversing'],ans:2,exp:'You should check your mirrors regularly and well before signalling, changing direction, or altering speed.'},
{id:209,cat:'hazards',q:'You are approaching roadworks on a motorway with a contraflow system. What should you do?',opts:['Maintain your normal motorway speed','Reduce speed and obey the temporary speed limit','Overtake slower vehicles within the contraflow','Move to the lane closest to the central reservation'],ans:1,exp:'Contraflow systems have reduced speed limits and narrow lanes. You must obey the temporary signs.'},
{id:210,cat:'hazards',q:'What hazard should you anticipate near a school at 3:30 pm on a weekday?',opts:['Heavy goods vehicles loading','Children crossing the road unexpectedly','Road cleaning vehicles blocking the road','Farm animals being herded'],ans:1,exp:'Schools finish around this time. Children may be excited and run into the road without looking.'},
{id:211,cat:'hazards',q:'What is a blind spot?',opts:['An area covered by your rear-view mirror','An area of road you cannot see in your mirrors','A spot where road markings have faded','An area with no street lighting'],ans:1,exp:'Blind spots are areas not visible in your mirrors. You should do a shoulder check before changing lanes.'},
{id:212,cat:'hazards',q:'You see a horse and rider ahead on a narrow country road. What should you do?',opts:['Sound your horn to alert the rider','Pass quickly to avoid holding up traffic','Slow down, give plenty of room, and pass wide and slowly','Flash your headlights and proceed at normal speed'],ans:2,exp:'Horses can be easily startled. You should slow down, give plenty of room, and pass slowly and quietly.'},
{id:213,cat:'hazards',q:'Why should you scan junctions even when you have a green traffic light?',opts:['Because traffic lights often malfunction','Because other drivers or cyclists may not stop at their red light','Because green means you must accelerate quickly','Because pedestrians always have priority at junctions'],ans:1,exp:'Other road users may run a red light or misjudge their approach. Always scan the junction before proceeding.'},
{id:214,cat:'hazards',q:'You are driving behind a large vehicle. Why should you drop back further than normal?',opts:['To allow the driver to see you in their mirrors','To reduce wind resistance on your vehicle','To avoid exhaust fumes','To let other traffic overtake you more easily'],ans:0,exp:'If you are too close behind a large vehicle, the driver will not be able to see you in their mirrors.'},
{id:215,cat:'hazards',q:'What should you do if you see an emergency vehicle approaching with blue flashing lights?',opts:['Stop immediately wherever you are','Pull over safely when it is safe to do so and let it pass','Accelerate to keep ahead of it','Ignore it if you are on a main road'],ans:1,exp:'You should pull over safely when you can to let emergency vehicles pass, but do not endanger yourself or others.'},
{id:216,cat:'hazards',q:'On an icy road, how much longer can your stopping distance be compared to dry conditions?',opts:['Twice as long','Three times as long','Five times as long','Up to ten times as long'],ans:3,exp:'On icy roads, stopping distances can be up to ten times longer than on dry roads.'},
{id:217,cat:'hazards',q:'You are driving along a road with parked cars on the left. What should you watch for?',opts:['Speed cameras hidden behind the cars','Car doors opening suddenly or pedestrians stepping out','Other drivers flashing their headlights','Potholes underneath the parked cars'],ans:1,exp:'Doors may open suddenly and pedestrians, especially children, may step out from between parked vehicles.'},
{id:218,cat:'hazards',q:'What does the term \'defensive driving\' mean?',opts:['Driving slowly at all times','Driving aggressively to assert your position','Planning ahead and anticipating the actions of other road users','Only driving in daylight hours'],ans:2,exp:'Defensive driving means being aware of potential hazards and anticipating what others might do.'},
{id:219,cat:'hazards',q:'When overtaking a cyclist, what is the minimum recommended passing distance at speeds up to 30 mph?',opts:['Half a metre','At least 1.5 metres','At least 3 metres','At least 5 metres'],ans:1,exp:'The Highway Code recommends leaving at least 1.5 metres when overtaking cyclists at speeds up to 30 mph.'},
{id:220,cat:'hazards',q:'You are approaching a pelican crossing and the amber light is flashing. What should you do?',opts:['Stop and wait for the green light','Give way to any pedestrians still on the crossing','Accelerate to clear the crossing quickly','Sound your horn to warn pedestrians'],ans:1,exp:'A flashing amber light at a pelican crossing means you must give way to pedestrians still on the crossing.'},
{id:221,cat:'hazards',q:'Why is it dangerous to overtake near a junction?',opts:['Because junctions always have speed bumps','Because a vehicle may emerge from the junction into your path','Because road surfaces are weaker near junctions','Because you will receive a fixed penalty notice'],ans:1,exp:'Vehicles may pull out of a junction without seeing you, especially if you are overtaking and in an unexpected position.'},
{id:222,cat:'hazards',q:'What should you do if sheep are blocking the road in a rural area?',opts:['Drive through them slowly sounding your horn','Stop, switch off your engine, and wait patiently','Reverse and find another route','Flash your headlights to move them'],ans:1,exp:'Animals can be unpredictable. Stop and wait for them to move or for the farmer to clear the road.'},
{id:223,cat:'hazards',q:'At night, when should you dip your headlights?',opts:['When driving on any lit road','When meeting oncoming traffic or following another vehicle closely','Only when driving in fog','Only in residential areas'],ans:1,exp:'You should dip your headlights to avoid dazzling oncoming drivers or the driver of the vehicle ahead.'},
{id:224,cat:'hazards',q:'You see \'SCHOOL\' written on the road surface. What should you expect?',opts:['A 20 mph speed limit at all times','Children crossing the road, possibly with a school crossing patrol','A mandatory stop sign ahead','A one-way system around the school'],ans:1,exp:'School road markings warn of a school ahead. Be prepared for children crossing and possible crossing patrols.'},
{id:225,cat:'hazards',q:'Why should you look over your shoulder before opening your car door?',opts:['To check for approaching cyclists or traffic','To check the weather conditions','To see if there are parking restrictions','To check if your passengers are ready'],ans:0,exp:'Cyclists or other road users could be approaching. The Dutch Reach technique helps prevent dooring incidents.'},
{id:226,cat:'hazards',q:'What hazard does a contraflow system on a motorway present?',opts:['There is no hard shoulder available for breakdowns','You drive on the opposite carriageway with oncoming traffic nearby and narrow lanes','Speed limits are always 70 mph in contraflow systems','Only lorries are affected by contraflow systems'],ans:1,exp:'In a contraflow you may be driving in narrow lanes close to oncoming traffic with no central reservation.'},
{id:227,cat:'hazards',q:'How can you identify that a driver ahead may be about to turn?',opts:['Their brake lights come on and they signal','They drive in a straight line at constant speed','They increase speed approaching a junction','They switch off their headlights'],ans:0,exp:'Brake lights and signals are key clues. Also watch for the vehicle slowing and positioning to turn.'},
{id:228,cat:'hazards',q:'You are driving in heavy rain. Why should you increase your following distance?',opts:['Because your windscreen wipers may fail','Because spray from other vehicles reduces your visibility and stopping distance increases','Because heavy rain causes engine problems','Because your indicators are harder to see'],ans:1,exp:'Spray reduces visibility and wet roads increase stopping distances significantly.'},
{id:229,cat:'hazards',q:'What is the main risk of driving too close to the vehicle ahead?',opts:['You may not be able to read their number plate','You will not have enough time to react if they brake suddenly','Your insurance premium will increase','You will use more fuel'],ans:1,exp:'Tailgating reduces your reaction time and stopping distance, greatly increasing the risk of a collision.'},
{id:230,cat:'hazards',q:'You see flashing amber lights near roadworks. What do they mean?',opts:['The road ahead is closed','There is a hazard ahead; slow down and proceed with caution','You must stop and wait for a green light','Roadworks have been completed'],ans:1,exp:'Flashing amber lights near roadworks warn of a hazard ahead. Slow down and proceed carefully.'},
{id:231,cat:'hazards',q:'A motorcyclist is filtering through slow-moving traffic. What should you do?',opts:['Open your door to block them','Move to the centre of the lane to prevent them passing','Be aware of their presence and avoid sudden lane changes','Flash your lights to stop them'],ans:2,exp:'Motorcyclists may filter through traffic. Check your mirrors before changing position and allow them space.'},
{id:232,cat:'hazards',q:'When driving on a single-track road, what should you do if you see an oncoming vehicle?',opts:['Flash your headlights and keep going','Pull into a passing place on your left to let them pass','Always reverse to the nearest passing place','Sound your horn as a warning'],ans:1,exp:'Use passing places to let oncoming traffic through. Pull into a passing place on your left or wait opposite one on your right.'},
{id:233,cat:'hazards',q:'What is the main hazard of driving through a ford?',opts:['Your paintwork may be damaged','Your brakes may become less effective after passing through water','Your radio may stop working','Your windows may fog up'],ans:1,exp:'Water can reduce brake effectiveness. After driving through a ford, test your brakes gently.'},
{id:234,cat:'hazards',q:'You see a bus indicating to pull away from a bus stop. What should you do?',opts:['Flash your lights to tell the driver to wait','Give way to the bus if it is safe to do so','Sound your horn to warn the bus driver','Overtake the bus before it moves off'],ans:1,exp:'You should give way to buses pulling away from stops in built-up areas when it is safe to do so.'},
{id:235,cat:'hazards',q:'What extra hazard should you anticipate when driving past a row of parked vehicles in a residential area?',opts:['Speed cameras may be present','Children may run out between the vehicles','The road surface is likely to be damaged','There will be double yellow lines'],ans:1,exp:'Children may be hidden between parked cars and can run out suddenly without looking.'},
{id:236,cat:'hazards',q:'What should you do before reversing your vehicle?',opts:['Sound your horn twice','Check all around the vehicle for obstructions, children, and animals','Switch on your hazard warning lights','Open your window and shout a warning'],ans:1,exp:'Before reversing, check all around for hazards that may not be visible from the driver\'s seat, especially small children.'},
{id:237,cat:'hazards',q:'You are driving on a motorway and see a vehicle broken down on the hard shoulder. What should you do?',opts:['Stop on the hard shoulder to help','Move to a lane away from the hard shoulder if safe to do so','Slow down to 10 mph as you pass','Flash your lights at the broken-down vehicle'],ans:1,exp:'Moving to a lane further from the hard shoulder gives a safety margin to people who may be near the broken-down vehicle.'},
{id:238,cat:'hazards',q:'Why is it particularly dangerous to overtake on a road with dips and hidden crests?',opts:['Because your fuel consumption increases','Because you cannot see oncoming traffic that may be hidden by the road layout','Because your brakes are less effective going uphill','Because your steering becomes heavy on hills'],ans:1,exp:'Hidden dips or crests can conceal oncoming vehicles, making overtaking extremely dangerous.'},
{id:239,cat:'hazards',q:'What should you do if you are dazzled by the headlights of an oncoming vehicle at night?',opts:['Flash your headlights back at them','Slow down and if necessary stop until your eyes recover','Stare directly at the oncoming lights','Swerve to the left to avoid the light'],ans:1,exp:'If dazzled, slow down or stop. Avoid looking directly at the oncoming lights; look to the left edge of the road.'},
{id:240,cat:'hazards',q:'You notice a pedestrian with a white cane and red band. What does this indicate?',opts:['The person is a traffic warden','The person is both deaf and blind','The person has a visual impairment only','The person is a school crossing patrol officer'],ans:1,exp:'A white cane with a red band indicates that the person is both deaf and blind. Give them extra time and space.'},
{id:241,cat:'hazards',q:'When driving in fog, why should you avoid using full beam headlights?',opts:['Because full beam headlights use more battery power','Because the light reflects off the fog and reduces your visibility further','Because full beam headlights are illegal in fog','Because they dazzle other road users less than dipped beams'],ans:1,exp:'Full beam reflects off fog particles back towards you, making visibility worse. Use dipped headlights or fog lights.'},
{id:242,cat:'hazards',q:'What does a flashing green beacon on a vehicle indicate?',opts:['A fire engine responding to an emergency','A doctor responding to an emergency call','A police vehicle on routine patrol','A vehicle carrying hazardous materials'],ans:1,exp:'A flashing green beacon is used by doctors on emergency calls. Give way to them when possible.'},
{id:243,cat:'hazards',q:'You are following a long vehicle that signals left but moves out to the right. What should you do?',opts:['Overtake on the left as they have left a gap','Stay well back as the vehicle may be turning left and needs extra room to swing out','Sound your horn to alert the driver','Accelerate past on the right quickly'],ans:1,exp:'Long vehicles often need to swing out to the right before making a left turn. Stay back and give them space.'},
{id:244,cat:'hazards',q:'What is the two-second rule used for?',opts:['Timing how long to indicate before turning','Measuring a safe following distance in good conditions','Deciding when to overtake another vehicle','Timing how long to check your mirrors'],ans:1,exp:'The two-second rule helps you maintain a safe following distance. Pick a fixed point and count two seconds after the vehicle ahead passes it.'},
{id:245,cat:'hazards',q:'Why are motorcyclists particularly vulnerable at junctions?',opts:['Because their vehicles are slower than cars','Because they are smaller and harder to see than larger vehicles','Because they always travel too fast','Because they never use headlights during the day'],ans:1,exp:'Motorcycles are narrower and can be hidden by other traffic or street furniture, making them hard to spot at junctions.'},
{id:246,cat:'hazards',q:'You are driving towards a zebra crossing. A person is waiting to cross. What must you do?',opts:['Sound your horn to let them know you have seen them','Flash your headlights to signal them to cross','Slow down and stop to let them cross','Maintain your speed as they have not yet stepped onto the crossing'],ans:2,exp:'You should be prepared to slow down and stop for anyone waiting at a zebra crossing to let them cross safely.'},
{id:247,cat:'hazards',q:'What extra precaution should you take when driving past roadworks with cones narrowing the lanes?',opts:['Increase your speed to clear the area quickly','Keep to the speed limit for the roadworks and watch for workers near the carriageway','Drive in the centre of both lanes','Only use first gear throughout the roadworks'],ans:1,exp:'Obey reduced speed limits at roadworks and watch for workers, machinery, and uneven road surfaces.'},
{id:248,cat:'hazards',q:'Why should you avoid coasting when driving downhill?',opts:['Because it increases fuel consumption','Because you lose the engine\'s braking effect and have less control','Because the clutch will overheat','Because the battery will not charge'],ans:1,exp:'Coasting means the engine is not connected to the wheels. You lose engine braking and have less control of the vehicle.'},
{id:249,cat:'hazards',q:'You see double white lines along the centre of the road with the solid line nearest to you. What does this mean?',opts:['You may overtake if the road ahead is clear','You must not cross or straddle the line except in specific circumstances','You may park on the left-hand side','The road ahead has a speed limit of 60 mph'],ans:1,exp:'A solid white line nearest to you means you must not cross or straddle it except to enter premises or pass a stationary obstruction.'},
{id:250,cat:'hazards',q:'What should you do if you see a vehicle with flashing blue lights approaching from behind while you are on a roundabout?',opts:['Stop immediately on the roundabout','Leave the roundabout at the next exit and pull over safely','Reverse off the roundabout','Increase your speed to exit faster'],ans:1,exp:'Do not stop on a roundabout. Continue to the next exit, leave the roundabout, and then pull over safely to let the emergency vehicle pass.'},
{id:251,cat:'vulnerable',q:'You are approaching a zebra crossing where a pedestrian is waiting to cross. What should you do?',opts:['Flash your headlights to signal them across','Sound your horn to alert them','Slow down and be prepared to stop','Speed up to pass before they step out'],ans:2,exp:'You must slow down and be prepared to stop at a zebra crossing when a pedestrian is waiting to cross.'},
{id:252,cat:'vulnerable',q:'Why should you check your nearside mirror before turning left?',opts:['To check for oncoming traffic','To check for cyclists filtering on your left','To check your road position','To see if the road is clear ahead'],ans:1,exp:'Cyclists often filter along the left side of traffic. Always check your nearside mirror before turning left to avoid cutting across them.'},
{id:253,cat:'vulnerable',q:'You see a group of children playing near the kerb. What should you do?',opts:['Sound your horn to warn them','Flash your headlights at them','Slow down and be ready to stop','Continue at the same speed but steer away'],ans:2,exp:'Children are unpredictable and may run into the road without warning. Slow down and be prepared to stop.'},
{id:254,cat:'vulnerable',q:'What does a triangular sign showing two children mean?',opts:['Play area ahead','School crossing patrol ahead','School ahead','No children allowed'],ans:2,exp:'This warning sign indicates a school ahead. Drive slowly and watch for children who may be crossing the road.'},
{id:255,cat:'vulnerable',q:'You are driving behind a cyclist who is approaching a roundabout. What should you do?',opts:['Overtake them before the roundabout','Sound your horn to make them aware of you','Allow them plenty of room and do not rush them','Drive close behind to encourage them to speed up'],ans:2,exp:'Cyclists may need to change direction at a roundabout. Give them space and time and do not attempt to rush or squeeze past them.'},
{id:256,cat:'vulnerable',q:'An elderly pedestrian is crossing the road very slowly ahead of you. What should you do?',opts:['Rev your engine to hurry them','Be patient and allow them to cross in their own time','Sound your horn gently','Edge forward to encourage them to move faster'],ans:1,exp:'Elderly people may take longer to cross the road. Be patient and allow them time to cross safely.'},
{id:257,cat:'vulnerable',q:'When should you use particular care near a parked ice cream van?',opts:['In winter months','When it is raining','At all times as children may run out','Only during school hours'],ans:2,exp:'Children are often excited around ice cream vans and may run into the road without looking. Always exercise extra care.'},
{id:258,cat:'vulnerable',q:'You see a person with a white stick and red band crossing the road. What does this indicate?',opts:['The person is deaf','The person is deaf and blind','The person is blind','The person has a physical disability'],ans:1,exp:'A white stick with a red band indicates that the person is both deaf and blind. Give them extra time and space.'},
{id:259,cat:'vulnerable',q:'How should you react when a motorcyclist is filtering through slow-moving traffic?',opts:['Block their path to stop them','Open your door to warn them','Be aware of them and allow them to pass safely','Speed up to prevent them overtaking'],ans:2,exp:'Motorcyclists may filter through traffic. Be aware of their presence and do not obstruct them.'},
{id:260,cat:'vulnerable',q:'What should you do when passing a horse and rider on the road?',opts:['Sound your horn to alert them','Pass slowly and give them plenty of room','Rev your engine to warn the horse','Flash your lights to let them know you are there'],ans:1,exp:'Horses can be easily startled. Pass slowly and give them as much room as possible.'},
{id:261,cat:'vulnerable',q:'You see a pedestrian with a guide dog waiting at a crossing. The dog is in a harness. What should you be aware of?',opts:['The dog may pull the person across at any time','The person may not be able to see your signal to cross','Guide dogs are trained to cross when safe','The dog will bark when it is safe to cross'],ans:1,exp:'A guide dog user may not be able to see any signal you give. Wait patiently and do not sound your horn or flash your lights.'},
{id:262,cat:'vulnerable',q:'You are turning right from a main road into a side road. What should you look out for?',opts:['Oncoming vehicles only','Pedestrians already crossing the side road','Traffic signs only','Parked vehicles in the side road'],ans:1,exp:'Pedestrians may already be crossing the side road. They have priority if they are already crossing when you turn.'},
{id:263,cat:'vulnerable',q:'Why are motorcyclists more vulnerable at junctions?',opts:['They always ride too fast','They are harder to see than larger vehicles','They do not have to follow traffic rules','Their indicators are on the wrong side'],ans:1,exp:'Motorcyclists are smaller and can be harder to see, especially at junctions. Always look carefully before emerging.'},
{id:264,cat:'vulnerable',q:'What should you do if you see a cyclist looking over their right shoulder as you approach?',opts:['Speed up and pass quickly','Slow down as they may be about to turn right','Sound your horn to warn them','Maintain your speed and position'],ans:1,exp:'A cyclist looking over their shoulder is likely preparing to move out or turn right. Be ready for them to change direction.'},
{id:265,cat:'vulnerable',q:'At a pelican crossing, what do flashing amber lights mean?',opts:['You must stop and wait','You must give way to pedestrians still on the crossing','You may proceed as the crossing is clear','The lights are faulty'],ans:1,exp:'Flashing amber at a pelican crossing means you must give way to pedestrians still crossing, but may proceed if the crossing is clear.'},
{id:266,cat:'vulnerable',q:'Where would you expect to see a toucan crossing?',opts:['Near a farm','Near a zoo','Where a cycle route crosses a road','On a motorway'],ans:2,exp:'Toucan crossings are shared by pedestrians and cyclists. The name comes from \'two can\' cross together.'},
{id:267,cat:'vulnerable',q:'You notice a child running between parked cars ahead. What should you do?',opts:['Continue at the speed limit','Slow down and cover the brake','Sound your horn and continue','Flash your headlights at the child'],ans:1,exp:'A child running between parked cars may dash out into the road. Slow down immediately and be ready to stop.'},
{id:268,cat:'vulnerable',q:'What is a common danger when driving near schools at opening and closing times?',opts:['Increased roadworks','Children crossing without looking','More heavy goods vehicles','Fewer parking spaces'],ans:1,exp:'Children may be excited and rush across the road without checking for traffic. Reduce your speed near schools during these times.'},
{id:269,cat:'vulnerable',q:'Why should you allow extra room when overtaking a cyclist in windy conditions?',opts:['Cyclists ride faster in the wind','Wind can cause the cyclist to wobble or swerve','Cyclists cannot hear you in the wind','Wind reduces your braking distance'],ans:1,exp:'Strong winds can blow a cyclist off course. Allow extra room in case they are blown sideways into your path.'},
{id:270,cat:'vulnerable',q:'You are following a rider on horseback who is signalling right but keeping to the left of the road. Why might they do this?',opts:['They are confused about which way to go','The horse is refusing to move right','They are staying left while preparing to turn right because the horse needs more space','They are signalling to you to overtake'],ans:2,exp:'Horse riders may keep left even when turning right as horses need space. Do not assume they are turning left.'},
{id:271,cat:'vulnerable',q:'How can you tell that a puffin crossing is different from a pelican crossing?',opts:['Puffin crossings are only for cyclists','Puffin crossings have sensors that detect pedestrians and there is no flashing amber phase','Puffin crossings are always wider','Puffin crossings have barriers'],ans:1,exp:'Puffin crossings have sensors that detect whether pedestrians are still crossing. They do not have a flashing amber phase.'},
{id:272,cat:'vulnerable',q:'What should you do when a wheelchair user is crossing at a pedestrian crossing?',opts:['Rev your engine to hurry them','Allow them extra time to cross','Sound your horn to alert them','Edge forward slowly'],ans:1,exp:'Wheelchair users may take longer to cross the road. Be patient and allow them extra time to cross safely.'},
{id:273,cat:'vulnerable',q:'You are on a country road and see a horse rider ahead. What should you avoid doing?',opts:['Slowing down','Giving them space','Sounding your horn or revving your engine','Making eye contact with the rider'],ans:2,exp:'Loud noises from horns or engines can easily startle horses, causing a dangerous situation for the rider and other road users.'},
{id:274,cat:'vulnerable',q:'When driving past a bus that has stopped at a bus stop, why should you watch out for pedestrians?',opts:['Pedestrians may step out from behind the bus','The bus driver may signal you to stop','Pedestrians always have right of way at bus stops','The bus may reverse'],ans:0,exp:'Pedestrians may step into the road from behind a bus without checking for traffic. Be ready to slow down or stop.'},
{id:275,cat:'vulnerable',q:'What should you do if a motorcyclist is following you closely?',opts:['Brake sharply to warn them','Speed up to increase the gap','Slow down gradually to increase the space in front of you','Ignore them completely'],ans:2,exp:'If a motorcyclist is tailgating you, gradually slow down to increase the safety buffer ahead so you do not need to brake harshly.'},
{id:276,cat:'vulnerable',q:'Why are older drivers potentially more vulnerable on the road?',opts:['They always drive too slowly','They may have slower reaction times and reduced eyesight','They never check their mirrors','They do not understand modern road signs'],ans:1,exp:'Older drivers may have slower reactions and reduced vision. Be patient and give them extra time and space.'},
{id:277,cat:'vulnerable',q:'When must you stop for a school crossing patrol?',opts:['Only during school holidays','Only when children are visible','When the school crossing patrol shows the stop sign','Only when a police officer is present'],ans:2,exp:'You must stop when the school crossing patrol displays the stop sign, regardless of whether you can see children waiting.'},
{id:278,cat:'vulnerable',q:'You see a cyclist holding out their left arm. What does this mean?',opts:['They are slowing down','They intend to turn left','They are asking you to overtake','They are waving you past'],ans:1,exp:'A cyclist holding out their left arm is signalling that they intend to turn left.'},
{id:279,cat:'vulnerable',q:'What is the recommended minimum gap when overtaking a cyclist at speeds up to 30 mph?',opts:['Half a metre','One metre','1.5 metres','3 metres'],ans:2,exp:'The Highway Code recommends leaving at least 1.5 metres when overtaking cyclists at speeds up to 30 mph, and more at higher speeds.'},
{id:280,cat:'vulnerable',q:'You approach a crossing where a blind person is waiting with a guide dog. The dog steps forward but then stops. What should you do?',opts:['Drive around them carefully','Wait patiently and do not rev your engine or sound your horn','Flash your headlights to let them cross','Shout out of the window to tell them it is safe'],ans:1,exp:'Wait patiently. Do not do anything that might confuse the guide dog or startle the pedestrian.'},
{id:281,cat:'vulnerable',q:'Why should you take particular care when driving near a pedestrian carrying a white stick?',opts:['They may be a traffic warden','They are visually impaired and may not see you','They are directing traffic','They have a physical injury'],ans:1,exp:'A white stick indicates visual impairment. The person may not be able to see your vehicle approaching.'},
{id:282,cat:'vulnerable',q:'At which type of crossing can cyclists ride across alongside pedestrians?',opts:['Zebra crossing','Pelican crossing','Toucan crossing','Puffin crossing'],ans:2,exp:'Toucan crossings are designed for both pedestrians and cyclists to use together.'},
{id:283,cat:'vulnerable',q:'You notice a motorcyclist weaving through heavy traffic. Why should you be extra cautious?',opts:['Motorcyclists have priority in traffic','They could appear suddenly beside or in front of your vehicle','Motorcyclists are exempt from traffic rules','They will always pass on your left'],ans:1,exp:'Motorcyclists filtering through traffic may appear unexpectedly. Always check mirrors before changing lanes or opening doors.'},
{id:284,cat:'vulnerable',q:'What hazard should you be aware of when driving slowly past a line of parked cars?',opts:['Car doors may open suddenly','Speed cameras are often hidden behind parked cars','Parked cars can roll forward','Pedestrians cannot cross near parked cars'],ans:0,exp:'Occupants of parked cars may open their doors into your path without checking. Drive slowly and be prepared to react.'},
{id:285,cat:'vulnerable',q:'You see two young children on the pavement near a ball that has rolled into the road. What should you expect?',opts:['The children will wait for you to pass','One or both children may run into the road to retrieve the ball','An adult will come to collect the ball','The children will look both ways first'],ans:1,exp:'Young children may run into the road to chase a ball without considering traffic. Slow down and be ready to stop.'},
{id:286,cat:'vulnerable',q:'Why should you give extra room to a cyclist on a wet road?',opts:['Cyclists go faster in wet conditions','Road markings and drain covers can be slippery for cyclists','Cyclists prefer more room in the rain','The cyclist might stop to put on waterproofs'],ans:1,exp:'Wet road surfaces, drain covers and painted markings become slippery, which can cause a cyclist to lose control.'},
{id:287,cat:'vulnerable',q:'You see a person at the side of the road using a powered wheelchair. How should you treat them?',opts:['The same as any other pedestrian','As a slow-moving vehicle','As a cyclist','They should not be on the road'],ans:0,exp:'A powered wheelchair user should be treated the same as any other pedestrian. Give them plenty of room.'},
{id:288,cat:'vulnerable',q:'What should you do if you see a horse rider raise their hand to ask you to slow down?',opts:['Ignore them and continue','Sound your horn to acknowledge','Slow down and pass carefully','Stop immediately in the road'],ans:2,exp:'If a rider raises their hand, slow down and pass the horse carefully with plenty of room to avoid startling it.'},
{id:289,cat:'vulnerable',q:'You are driving at night on an unlit road and see a pedestrian ahead wearing dark clothing. What does this situation require?',opts:['You should flash your headlights repeatedly','Extra vigilance as pedestrians may be harder to see','You should drive faster to pass them quickly','You should use your horn to warn them'],ans:1,exp:'Pedestrians in dark clothing are very difficult to see at night, especially on unlit roads. Reduce speed and stay alert.'},
{id:290,cat:'vulnerable',q:'A cyclist ahead of you is approaching a left turn. What should you avoid doing?',opts:['Slowing down behind them','Overtaking them just before the turn','Giving them space','Checking your mirrors'],ans:1,exp:'Do not overtake a cyclist just before you turn left. You risk cutting across their path and causing a collision.'},
{id:291,cat:'motorway',q:'What is the minimum speed limit on a UK motorway?',opts:['30 mph','40 mph','50 mph','There is no minimum speed limit'],ans:3,exp:'There is no minimum speed limit on UK motorways, but you must not drive so slowly that you endanger other road users.'},
{id:292,cat:'motorway',q:'When are you allowed to stop on the hard shoulder of a motorway?',opts:['When you want to make a phone call','In an emergency or breakdown','When you need to check a map','When you are feeling tired'],ans:1,exp:'The hard shoulder should only be used in genuine emergencies or breakdowns, not for routine stops.'},
{id:293,cat:'motorway',q:'What does a red X sign displayed above a motorway lane mean?',opts:['The lane is open to traffic','The lane is closed and you must not drive in it','There is slow traffic ahead','You should reduce speed to 40 mph'],ans:1,exp:'A red X means the lane is closed. You must move out of that lane as soon as it is safe to do so. It is illegal to drive in a closed lane.'},
{id:294,cat:'motorway',q:'You are joining a motorway from a slip road. What should you do?',opts:['Stop at the end of the slip road and wait for a gap','Match the speed of traffic on the motorway and merge safely','Drive slowly onto the motorway so other drivers can see you','Always use the hard shoulder to build up speed'],ans:1,exp:'Use the slip road to build up speed so you can match the flow of traffic on the motorway before merging.'},
{id:295,cat:'motorway',q:'What is the national speed limit on a UK motorway for cars?',opts:['60 mph','65 mph','70 mph','80 mph'],ans:2,exp:'The national speed limit for cars on a motorway is 70 mph unless signs indicate otherwise.'},
{id:296,cat:'motorway',q:'On a smart motorway, what does a variable speed limit sign indicate?',opts:['A suggested speed only','The maximum speed you may legally drive','The minimum speed you must maintain','A speed for lorries only'],ans:1,exp:'Variable speed limits on smart motorways are legally enforceable. You must not exceed the speed shown on the sign.'},
{id:297,cat:'motorway',q:'Which vehicles are not allowed on a motorway?',opts:['Caravans','Motorcycles over 50 cc','Learner drivers with a provisional licence','Cars towing trailers'],ans:2,exp:'Learner drivers holding a provisional car licence are not permitted to drive on motorways unless with an approved instructor in a dual-control car.'},
{id:298,cat:'motorway',q:'You have broken down on the motorway. What should you do after stopping on the hard shoulder?',opts:['Stay in your vehicle with the doors locked','Try to repair the vehicle yourself','Get out of the vehicle on the side away from traffic and move behind the barrier','Put on your hazard lights and wait in the right-hand lane'],ans:2,exp:'Leave the vehicle from the side furthest from traffic and wait behind the safety barrier if one is available.'},
{id:299,cat:'motorway',q:'What colour are motorway signs?',opts:['Green','White','Blue','Brown'],ans:2,exp:'Motorway signs have a blue background. Primary route signs are green and non-primary route signs are white.'},
{id:300,cat:'motorway',q:'On a three-lane motorway, which lane should you normally drive in?',opts:['The right-hand lane','The middle lane','The left-hand lane','Any lane you prefer'],ans:2,exp:'You should normally drive in the left-hand lane. Use the middle and right-hand lanes for overtaking only.'},
{id:301,cat:'motorway',q:'What should you do if you miss your exit on a motorway?',opts:['Reverse along the hard shoulder','Make a U-turn at the next gap in the central reservation','Continue to the next exit','Stop and check your map on the hard shoulder'],ans:2,exp:'If you miss your exit, carry on to the next one. Never reverse, stop or make a U-turn on a motorway.'},
{id:302,cat:'motorway',q:'What is a smart motorway that uses all-lane running?',opts:['A motorway with no speed cameras','A motorway where the hard shoulder is used as a permanent traffic lane','A motorway with wider lanes','A motorway that only opens at peak times'],ans:1,exp:'On an all-lane running smart motorway, the hard shoulder is permanently converted into a running lane with emergency refuge areas provided instead.'},
{id:303,cat:'motorway',q:'How far apart are emergency refuge areas typically located on a smart motorway?',opts:['Every 500 metres','Every 1 to 1.5 miles','Every 5 miles','Every 10 miles'],ans:1,exp:'Emergency refuge areas on smart motorways are typically located every 1 to 1.5 miles.'},
{id:304,cat:'motorway',q:'You see amber flashing lights on a motorway. What do they warn you about?',opts:['A police speed check ahead','A hazard ahead such as an accident or obstruction','The motorway is about to close completely','Roadworks have ended'],ans:1,exp:'Amber flashing lights on a motorway warn of a hazard ahead. Adjust your speed and look for further information signs.'},
{id:305,cat:'motorway',q:'When may you use the right-hand lane of a three-lane motorway?',opts:['At any time if you are driving at the speed limit','Only for overtaking','Only when directed by police','Only if the left and middle lanes are closed'],ans:1,exp:'The right-hand lane of a motorway is for overtaking only. Move back to the left when you have finished overtaking.'},
{id:306,cat:'motorway',q:'What should you do if you experience a tyre blowout on the motorway?',opts:['Brake sharply and stop immediately','Hold the steering wheel firmly, gradually reduce speed and pull over when safe','Swerve to the hard shoulder immediately','Increase speed to maintain stability'],ans:1,exp:'Keep a firm hold on the steering wheel and gradually slow down. Do not brake harshly as this could cause you to lose control.'},
{id:307,cat:'motorway',q:'What is the purpose of reflective studs on a motorway?',opts:['To mark speed camera locations','To indicate service stations','To help you identify lanes and the edges of the carriageway in poor visibility','To mark emergency phone locations'],ans:2,exp:'Reflective studs help you navigate the motorway in poor visibility. Different colours indicate different features of the road.'},
{id:308,cat:'motorway',q:'What colour are the reflective studs between the carriageway and the hard shoulder?',opts:['White','Red','Amber','Green'],ans:1,exp:'Red studs mark the left edge of the carriageway next to the hard shoulder. This helps you avoid drifting onto the hard shoulder.'},
{id:309,cat:'motorway',q:'You are driving on a motorway and feel drowsy. What should you do?',opts:['Open the window and carry on','Stop on the hard shoulder for a nap','Leave at the next exit or services and take a break','Turn up the radio and keep going'],ans:2,exp:'If you feel drowsy, leave the motorway at the next exit or service area. Do not stop on the hard shoulder except in an emergency.'},
{id:310,cat:'motorway',q:'What do green reflective studs on a motorway indicate?',opts:['The edge of the main carriageway','Lane boundaries','The location of slip roads and lay-bys','The central reservation'],ans:2,exp:'Green reflective studs mark the edge of the main carriageway at slip roads and lay-bys.'},
{id:311,cat:'motorway',q:'What is the purpose of a crawler lane on a motorway?',opts:['For emergency vehicles only','To allow slow-moving vehicles to use on steep uphill gradients','For cyclists','For vehicles joining the motorway'],ans:1,exp:'Crawler lanes are provided on steep uphill sections to allow slower vehicles to move to the left so faster traffic can pass safely.'},
{id:312,cat:'motorway',q:'On a smart motorway, what should you do if your vehicle breaks down and you cannot reach an emergency refuge area?',opts:['Try to continue to the next exit','Move to the left-hand lane, switch on hazard lights and call for help','Get out and try to push the vehicle','Wait in the right-hand lane with your hazard lights on'],ans:1,exp:'If you cannot reach a refuge area, move as far left as possible, turn on hazard lights, and contact emergency services.'},
{id:313,cat:'motorway',q:'What is the maximum speed limit for a car towing a caravan on a motorway?',opts:['50 mph','60 mph','70 mph','80 mph'],ans:1,exp:'The maximum speed for a car towing a caravan or trailer on a motorway is 60 mph.'},
{id:314,cat:'motorway',q:'You are travelling on a motorway and the vehicle ahead suddenly slows. What should you do?',opts:['Brake sharply and sound your horn','Move to the right-hand lane immediately','Reduce speed gradually and use your hazard lights briefly to warn traffic behind','Maintain your speed and steer around them'],ans:2,exp:'Reduce speed smoothly and consider briefly using your hazard lights to alert drivers behind you to the slowing traffic.'},
{id:315,cat:'motorway',q:'What should you do before changing lanes on a motorway?',opts:['Sound your horn','Check mirrors, signal, and check your blind spot','Flash your headlights at other drivers','Slow down first then move across'],ans:1,exp:'Always use the mirror-signal-manoeuvre routine and check your blind spot before changing lanes on a motorway.'},
{id:316,cat:'motorway',q:'How should you position your vehicle when driving through roadworks on a motorway?',opts:['Straddle two lanes for safety','Keep within your lane and follow any temporary road markings','Drive on the hard shoulder to avoid the roadworks','Overtake on the left to pass through quickly'],ans:1,exp:'Stay in your lane and obey all signs and temporary speed limits through motorway roadworks.'},
{id:317,cat:'motorway',q:'What do white reflective studs on a motorway indicate?',opts:['The hard shoulder edge','Lane markings','The central reservation','Slip road boundaries'],ans:1,exp:'White reflective studs mark the lane boundaries on a motorway.'},
{id:318,cat:'motorway',q:'When may you overtake on the left on a motorway?',opts:['Whenever the left lane is moving faster','When traffic is moving slowly in queues and your lane is moving faster than the lane on your right','At any time if you signal first','You must never overtake on the left'],ans:1,exp:'You may pass on the left when traffic is moving slowly in queues and your lane is moving at a faster rate than the lane to your right.'},
{id:319,cat:'motorway',q:'You see a broken-down vehicle on a smart motorway with no hard shoulder. What lane management sign would you expect to see?',opts:['A green arrow above all lanes','A red X above the affected lane','A national speed limit sign','A blue information sign'],ans:1,exp:'A red X will be displayed above the lane where the broken-down vehicle is located to close that lane to traffic.'},
{id:320,cat:'motorway',q:'What should you do if fog suddenly reduces visibility on a motorway?',opts:['Switch on rear fog lights and reduce speed','Stop immediately in the lane you are in','Move to the hard shoulder and wait','Keep driving at the same speed using the vehicle ahead as a guide'],ans:0,exp:'Switch on fog lights, slow down and increase the gap between you and the vehicle ahead. Do not hang on to the tail lights of the vehicle in front.'},
{id:321,cat:'documents',q:'How long is a standard MOT certificate valid for?',opts:['6 months','1 year','2 years','3 years'],ans:1,exp:'An MOT certificate is valid for one year from the date it was issued.'},
{id:322,cat:'documents',q:'At what age must a car first have an MOT test?',opts:['1 year old','2 years old','3 years old','5 years old'],ans:2,exp:'A car must have its first MOT test when it is three years old from the date of first registration.'},
{id:323,cat:'documents',q:'What is the minimum level of motor insurance cover required by law in the UK?',opts:['Fully comprehensive','Third party, fire and theft','Third party only','No insurance is required for private use'],ans:2,exp:'The minimum legal requirement is third party insurance, which covers damage or injury you cause to other people and their property.'},
{id:324,cat:'documents',q:'What does SORN stand for?',opts:['Standard Off-Road Notice','Statutory Off Road Notification','Special Off-Road Notification','Standing Order Road Notice'],ans:1,exp:'SORN stands for Statutory Off Road Notification. You must declare a SORN if your vehicle is kept off the road and is not taxed or insured.'},
{id:325,cat:'documents',q:'When must you notify the DVLA about changes to your vehicle or personal details?',opts:['Within 7 days','As soon as possible','Within 6 months','At the next MOT'],ans:1,exp:'You must tell the DVLA as soon as possible if you change your name, address, or if there are changes to your vehicle.'},
{id:326,cat:'documents',q:'What is the maximum fine for driving without insurance?',opts:['A fixed penalty of 100 pounds','500 pounds','1000 pounds','Unlimited'],ans:3,exp:'Driving without insurance can result in an unlimited fine, 6 to 8 penalty points, and disqualification from driving.'},
{id:327,cat:'documents',q:'How many penalty points will result in disqualification for a new driver within the first two years of passing their test?',opts:['3 points','6 points','9 points','12 points'],ans:1,exp:'New drivers who accumulate 6 or more penalty points within two years of passing their test will have their licence revoked.'},
{id:328,cat:'documents',q:'What document must you produce if asked by a police officer at the roadside?',opts:['Your birth certificate','Your MOT certificate only','Your driving licence','Your passport'],ans:2,exp:'A police officer can ask to see your driving licence. If you do not have it with you, you may be asked to produce it at a police station within 7 days.'},
{id:329,cat:'documents',q:'What is a V5C document?',opts:['An insurance certificate','A vehicle registration certificate','An MOT certificate','A driving licence counterpart'],ans:1,exp:'The V5C is the vehicle registration certificate. It records the registered keeper of the vehicle, not necessarily the owner.'},
{id:330,cat:'documents',q:'How many penalty points can lead to disqualification for an experienced driver under the totting-up procedure?',opts:['6 points','9 points','12 points','15 points'],ans:2,exp:'If you accumulate 12 or more penalty points within a three-year period, you face disqualification under the totting-up procedure.'},
{id:331,cat:'documents',q:'What category of driving licence do you need to drive a standard car?',opts:['Category A','Category B','Category C','Category D'],ans:1,exp:'Category B covers cars and light vehicles up to 3,500 kg with up to 8 passenger seats.'},
{id:332,cat:'documents',q:'When can you drive a vehicle without an MOT certificate?',opts:['On Sundays only','When driving to a pre-booked MOT test appointment','When the vehicle is less than five years old','When you have comprehensive insurance'],ans:1,exp:'You may drive a vehicle without a valid MOT only when driving directly to a pre-booked MOT test at an authorised testing station.'},
{id:333,cat:'documents',q:'What happens if you are caught driving with an expired vehicle tax disc?',opts:['You receive a verbal warning','You could receive a fine of up to 1,000 pounds','Nothing, as tax is no longer displayed','You will be banned from driving'],ans:1,exp:'Even though paper tax discs are no longer used, your vehicle must still be taxed. Driving an untaxed vehicle can result in a fine of up to 1,000 pounds.'},
{id:334,cat:'documents',q:'What is an endorsement on a driving licence?',opts:['A letter of recommendation from your insurer','A record of penalty points or disqualifications on your licence','A note confirming your address','A vehicle registration number'],ans:1,exp:'An endorsement is a record of a motoring conviction showing the offence code, date and any penalty points applied to your driving licence.'},
{id:335,cat:'documents',q:'For how long do most endorsements stay on your driving licence?',opts:['1 year','2 years','4 years','10 years'],ans:2,exp:'Most endorsements remain on your licence for 4 years from the date of the offence. More serious offences such as drink driving remain for 11 years.'},
{id:336,cat:'documents',q:'What must you do if you sell your vehicle?',opts:['Nothing, the new owner handles everything','Notify the DVLA by completing the relevant section of the V5C','Cancel your MOT','Return your driving licence'],ans:1,exp:'You must inform the DVLA when you sell or transfer your vehicle by completing the relevant section of the V5C registration certificate.'},
{id:337,cat:'documents',q:'What does third-party insurance cover?',opts:['Damage to your own vehicle','Damage or injury you cause to other people and their property','Theft of your vehicle','Fire damage to your vehicle'],ans:1,exp:'Third-party insurance is the minimum legal cover. It pays for damage or injury you cause to others but does not cover your own vehicle.'},
{id:338,cat:'documents',q:'Who is legally responsible for ensuring a vehicle driven on public roads is properly insured?',opts:['The vehicle manufacturer','The registered keeper only','The driver and the registered keeper','The insurance company'],ans:2,exp:'Both the driver and the registered keeper are legally responsible for ensuring the vehicle is properly insured for use on public roads.'},
{id:339,cat:'documents',q:'What category licence is required to ride a motorcycle?',opts:['Category A','Category B','Category C','Category D'],ans:0,exp:'Category A covers motorcycles. There are subcategories including AM, A1, A2 and A depending on the size and power of the motorcycle.'},
{id:340,cat:'documents',q:'A SORN is valid until when?',opts:['For 6 months only','For 12 months and must be renewed','Until the vehicle is taxed, sold, scrapped or permanently exported','Until the next MOT is due'],ans:2,exp:'A SORN remains in force until you tax the vehicle, sell it, scrap it, or permanently export it from the UK.'},
{id:341,cat:'documents',q:'What happens to your driving licence if you are disqualified from driving?',opts:['It is destroyed permanently','You keep it but cannot use it','It must be surrendered to the court','It is returned automatically after the ban'],ans:2,exp:'If you are disqualified, you must surrender your licence to the court. You may need to apply for a new one after the disqualification period.'},
{id:342,cat:'documents',q:'What is the penalty for driving while disqualified?',opts:['3 penalty points','A fixed penalty notice only','Up to 6 months imprisonment and an unlimited fine','A written warning'],ans:2,exp:'Driving while disqualified is a serious offence that can result in up to 6 months in prison, an unlimited fine, and further disqualification.'},
{id:343,cat:'documents',q:'At what age can you apply for a provisional driving licence to drive a car?',opts:['15 years and 9 months','16 years','17 years','18 years'],ans:0,exp:'You can apply for a provisional driving licence up to 3 months before your 16th birthday, but you cannot drive a car on public roads until you are 17.'},
{id:344,cat:'documents',q:'What must a provisional licence holder display on their vehicle?',opts:['P plates','Green L plates','Red L plates or D plates in Wales','No plates are required'],ans:2,exp:'Provisional licence holders must display red L plates (or D plates in Wales) on the front and rear of their vehicle at all times while driving.'},
{id:345,cat:'documents',q:'How can you check whether a vehicle is taxed and has a valid MOT?',opts:['By checking the paper tax disc on the windscreen','By contacting the manufacturer','By using the DVLA online vehicle enquiry service','By asking the previous owner'],ans:2,exp:'You can check a vehicle\'s tax and MOT status online using the DVLA vehicle enquiry service at gov.uk.'},
{id:346,cat:'documents',q:'What is the legal requirement regarding vehicle registration plates?',opts:['They must be in any colour you choose','They must conform to the prescribed font, size and colour','They only need to be displayed at the front','Custom fonts are permitted if legible'],ans:1,exp:'Registration plates must meet strict legal requirements including prescribed font, spacing, size and colour to ensure they are readable.'},
{id:347,cat:'documents',q:'If you receive a fixed penalty notice for a motoring offence, how many penalty points are typically imposed for using a mobile phone while driving?',opts:['3 points','6 points','9 points','12 points'],ans:1,exp:'Using a handheld mobile phone while driving results in 6 penalty points and a 200 pound fine.'},
{id:348,cat:'documents',q:'What is the purpose of the Vehicle Excise Duty?',opts:['To fund road building exclusively','It is a tax that must be paid to keep a vehicle on public roads','To pay for vehicle insurance','To cover MOT testing costs'],ans:1,exp:'Vehicle Excise Duty, commonly called road tax, must be paid to legally keep or use a vehicle on public roads in the UK.'},
{id:349,cat:'documents',q:'What must you do with a vehicle that has failed its MOT and is not roadworthy?',opts:['Drive it home immediately','You must not drive it on public roads unless going to a pre-booked repair or MOT','Park it on the road with a SORN','You have 14 days to get it repaired before the MOT expires'],ans:1,exp:'A vehicle that has failed its MOT and has dangerous defects must not be driven on public roads except to a place of repair or for a pre-booked MOT.'},
{id:350,cat:'documents',q:'What should you do if you change your name due to marriage?',opts:['Nothing until your licence expires','Notify the DVLA and apply for an updated driving licence','Only inform your insurance company','Wait until your next MOT'],ans:1,exp:'You must notify the DVLA of any change of name and apply for an updated driving licence as soon as possible.'},
{id:351,cat:'rules',q:'What colour are the lines used to mark a red route?',opts:['Yellow','White','Red','Blue'],ans:2,exp:'Red routes are marked with red lines. Single red lines mean no stopping during displayed times; double red lines mean no stopping at any time.'},
{id:352,cat:'rules',q:'You are driving on a red route. What do double red lines at the edge of the road mean?',opts:['No parking during working hours','No stopping at any time','Residents\' parking only','Loading permitted for 20 minutes'],ans:1,exp:'Double red lines on a red route mean no stopping at any time for any reason, unless directed to do so by a police officer.'},
{id:353,cat:'rules',q:'What is the purpose of a controlled parking zone?',opts:['To allow free parking at all times','To limit parking within an area without repeater signs on every street','To ban all parking entirely','To provide parking for disabled badge holders only'],ans:1,exp:'A controlled parking zone (CPZ) sets parking restrictions across an area. Entry signs show the rules, so individual streets do not need repeater signs.'},
{id:354,cat:'rules',q:'You see zigzag white lines on both sides of a pedestrian crossing. What do they mean?',opts:['You may park if the crossing is not in use','You must not park or overtake the leading vehicle on the zigzag lines','You may stop briefly to pick up passengers','They mark a bus stop area'],ans:1,exp:'Zigzag lines at pedestrian crossings mean you must not park or wait on them, and you must not overtake the leading vehicle approaching the crossing.'},
{id:355,cat:'rules',q:'At a Pegasus crossing, which additional road users can cross besides pedestrians?',opts:['Cyclists','Horse riders','Motorcyclists','Tram passengers'],ans:1,exp:'A Pegasus crossing, also called an equestrian crossing, has facilities for horse riders as well as pedestrians, with higher-mounted controls.'},
{id:356,cat:'rules',q:'What must you do when approaching a level crossing with barriers and a steady amber light followed by twin flashing red lights?',opts:['Speed up to cross before the barriers lower','Stop behind the white line and wait','Proceed with caution if no train is visible','Sound your horn to alert other road users'],ans:1,exp:'When the amber light shows followed by flashing red lights at a level crossing, you must stop and wait behind the white line until the lights stop flashing.'},
{id:357,cat:'rules',q:'You are waiting at a level crossing and the red lights continue to flash after a train has passed. What should you do?',opts:['Continue to wait as another train may be approaching','Carefully drive around the barriers','Proceed once the first train has passed','Flash your headlights at oncoming traffic'],ans:0,exp:'If the red lights continue to flash after a train has passed, another train may be coming. You must wait until the lights stop flashing and barriers rise.'},
{id:358,cat:'rules',q:'At an open level crossing with no gates or barriers, what should you do?',opts:['Cross quickly without stopping','Stop, look both ways, and listen for trains before crossing','Sound your horn before crossing','Wait for a signal from the signalman'],ans:1,exp:'At an open level crossing with no barriers, you must stop, look both ways, and listen carefully before crossing. Only proceed if you are certain it is safe.'},
{id:359,cat:'rules',q:'What should you do if your vehicle breaks down on a level crossing?',opts:['Try to push it clear of the crossing','Get everyone out of the vehicle and clear of the crossing, then phone the signal operator','Wait in the vehicle for help','Wave a red flag to warn the train driver'],ans:1,exp:'Get everyone out immediately and away from the crossing. Use the railway telephone to contact the signal operator. Only move the vehicle if there is time.'},
{id:360,cat:'rules',q:'You are driving in a one-way street. Which side of the road may you overtake on?',opts:['Only the right','Only the left','Either side','You must not overtake in a one-way street'],ans:2,exp:'In a one-way street you may pass other traffic on either side, as all traffic is travelling in the same direction.'},
{id:361,cat:'rules',q:'What must you be aware of when driving in a contraflow bus lane?',opts:['Buses will be travelling towards you','The lane is only for use by taxis','You may use the bus lane if it is empty','Buses will be travelling in the same direction as you'],ans:0,exp:'In a contraflow bus lane, buses travel in the opposite direction to other traffic. You must stay in your lane and be alert for oncoming buses.'},
{id:362,cat:'rules',q:'What is the main purpose of traffic calming measures such as speed humps and chicanes?',opts:['To increase traffic flow','To reduce vehicle speeds in residential areas','To provide extra parking spaces','To test vehicle suspension'],ans:1,exp:'Traffic calming measures are designed to slow traffic in residential and built-up areas, reducing the risk of accidents and making streets safer for pedestrians.'},
{id:363,cat:'rules',q:'You are approaching a mini roundabout. What should you do?',opts:['Drive over the central marking if no traffic is around','Give way to traffic from the right as you would at a normal roundabout','Treat it as a crossroads and stop completely','Always give way to traffic from the left'],ans:1,exp:'At a mini roundabout, you must give way to traffic approaching from your right, just as you would at a full-sized roundabout.'},
{id:364,cat:'rules',q:'Can large vehicles drive over the central painted circle of a mini roundabout?',opts:['Never under any circumstances','Yes, if they need to because their size makes it physically difficult to drive around it','Only emergency vehicles may do so','Only if the roundabout is on a one-way street'],ans:1,exp:'Large vehicles may need to drive over the painted central circle of a mini roundabout if their size makes it impractical to go around it.'},
{id:365,cat:'rules',q:'When may you stop on a clearway?',opts:['To drop off passengers','To make a phone call','You must not stop at any time on a clearway','To check your route on a map'],ans:2,exp:'On a clearway you must not stop at any time while the restriction is in force. This keeps the road clear for moving traffic.'},
{id:366,cat:'rules',q:'What do single yellow lines at the edge of the road indicate?',opts:['No parking at any time','Parking restrictions apply during the times shown on nearby plates','Parking is allowed for up to one hour','Residents\' parking only'],ans:1,exp:'Single yellow lines mean there are waiting restrictions during the times shown on nearby signs or plates. Outside those times, you may park.'},
{id:367,cat:'rules',q:'What do double yellow lines at the edge of the road mean?',opts:['No waiting at any time','No waiting during working hours only','Parking for disabled badge holders only','Loading is not permitted'],ans:0,exp:'Double yellow lines mean no waiting at any time. You must not park or wait there unless loading restrictions also apply.'},
{id:368,cat:'rules',q:'What colour kerb marks indicate that loading and unloading is not permitted?',opts:['Single yellow stripe on the kerb','Double yellow stripes on the kerb','Red stripe on the kerb','White stripe on the kerb'],ans:0,exp:'Yellow kerb marks indicate loading restrictions. A single yellow stripe means no loading during certain times; double yellow stripes mean no loading at any time.'},
{id:369,cat:'rules',q:'You see a sign indicating a 20 mph zone. Are there repeater speed signs within the zone?',opts:['Yes, every 100 metres','Yes, at every junction','No, the zone entry sign is sufficient','Only on dual carriageways within the zone'],ans:2,exp:'In a 20 mph zone, repeater signs are not normally used. The zone entry sign and traffic calming measures apply throughout.'},
{id:370,cat:'rules',q:'What is the difference between a 20 mph zone and a 20 mph speed limit?',opts:['There is no difference','A 20 mph zone uses traffic calming and has no repeater signs; a 20 mph limit uses repeater signs','A 20 mph zone only applies during school hours','A 20 mph limit only applies at night'],ans:1,exp:'A 20 mph zone typically has traffic calming measures and no repeater signs, while a 20 mph speed limit road has repeater signs but may not have physical calming measures.'},
{id:371,cat:'rules',q:'What should you do when a tram approaches and you are driving on a road shared with trams?',opts:['Stop immediately wherever you are','Give way to the tram as it cannot steer to avoid you','Speed up to get past the tram','Flash your headlights to warn the tram driver'],ans:1,exp:'Trams run on fixed rails and cannot steer to avoid you. Always give way to trams on shared roads.'},
{id:372,cat:'rules',q:'What must you avoid doing on tram tracks?',opts:['Driving parallel to them','Parking on them or obstructing them','Looking at them','Crossing them at junctions'],ans:1,exp:'You must not park on or obstruct tram tracks at any time. Trams cannot deviate from their route and could be delayed or cause an accident.'},
{id:373,cat:'rules',q:'How should you overtake a tram?',opts:['Always on the left','Always on the right','On the left unless road signs or markings direct you to pass on the right','You must never overtake a tram'],ans:2,exp:'You should normally overtake a tram on the left, but follow road signs or markings if they direct you to pass on the right.'},
{id:374,cat:'rules',q:'At a road junction, when should you avoid blocking the junction?',opts:['Only during rush hour','At all times, even if you have a green traffic light','Only when turning right','Only when the road ahead is on an incline'],ans:1,exp:'You must never block a junction. Even if the traffic light is green, do not enter the junction unless your exit road is clear.'},
{id:375,cat:'rules',q:'You want to turn right at a crossroads where oncoming traffic is also turning right. What is the safest method?',opts:['Always turn behind the oncoming vehicle (offside to offside)','Always turn in front of the oncoming vehicle','It depends on the road layout and any road markings; follow the guidance','Sound your horn and turn as quickly as possible'],ans:2,exp:'The safest method depends on the junction layout and markings. Turning offside to offside is generally safer as it gives a clear view of oncoming traffic, but follow road markings.'},
{id:376,cat:'rules',q:'What should you do when approaching a junction on a road with a speed awareness message painted on the surface?',opts:['Ignore it; only signs are legally enforceable','Check your speed and slow down if necessary','Stop completely','Speed up to clear the junction quickly'],ans:1,exp:'Speed awareness markings on the road surface remind you to check your speed. Slow down if you are travelling too fast for the conditions.'},
{id:377,cat:'rules',q:'When are you permitted to overtake on a road with a solid white centre line on your side?',opts:['Never under any circumstances','When turning into a side road or property entrance, or passing a stationary obstruction','When no other traffic is visible','When the vehicle ahead is driving below the speed limit'],ans:1,exp:'You may cross a solid white line to enter a side road or premises, to pass a stationary vehicle, or on the direction of a police officer, but not simply to overtake a moving vehicle.'},
{id:378,cat:'rules',q:'What must you do when approaching a green traffic light that has been green for some time?',opts:['Speed up to get through before it changes','Be prepared to stop as it may be about to change','Flash your headlights to warn others','Sound your horn to alert pedestrians'],ans:1,exp:'A traffic light that has been green for a while is known as a stale green. Be ready to stop safely as it is likely to change soon.'},
{id:379,cat:'rules',q:'When driving through a one-way street, which lane should you use if you want to turn left at the end?',opts:['The right-hand lane','The left-hand lane','The centre lane','Any lane, as it is one-way'],ans:1,exp:'In a one-way street, get into the left-hand lane in good time if you want to turn left. Road markings may also direct you.'},
{id:380,cat:'rules',q:'When driving through a one-way street, which lane should you use if you want to turn right at the end?',opts:['The left-hand lane','The right-hand lane','The centre lane only','Any lane you prefer'],ans:1,exp:'In a one-way street, move to the right-hand lane well before the junction if you intend to turn right, unless road markings direct otherwise.'},
{id:381,cat:'rules',q:'What do red studs on the road surface mark?',opts:['The left-hand edge of the carriageway','The right-hand edge of the carriageway or central reservation','Lane divisions on a motorway','Pedestrian crossing areas'],ans:1,exp:'Red studs mark the edge of the carriageway nearest the central reservation, which is the right-hand side on a motorway. They help you stay in lane at night.'},
{id:382,cat:'rules',q:'What should you do when tram rails are set into the road and the road surface is wet?',opts:['Drive normally; tram rails have no effect on grip','Take extra care as the rails can be slippery, especially for cyclists and motorcyclists','Avoid the road entirely','Increase speed to reduce time on the rails'],ans:1,exp:'Tram rails can be very slippery when wet, especially for two-wheeled vehicles. Take extra care and cross them at a wide angle if possible.'},
{id:383,cat:'rules',q:'You are in a lane marked with a left-turn arrow on the road. What must you do?',opts:['Turn left only','Go straight ahead if it is safe','Change lanes if you want to go straight ahead','Ignore the marking if no other traffic is present'],ans:0,exp:'If your lane has a directional arrow painted on the road, you must follow that direction. Get into the correct lane in good time.'},
{id:384,cat:'rules',q:'What is the rule when approaching a road with a \'No entry\' sign?',opts:['You may enter if the road appears clear','You must not enter that road from your direction','You may enter outside peak hours','The sign only applies to goods vehicles'],ans:1,exp:'A No Entry sign means you must not enter that road from the direction you are travelling. It is a regulatory sign and must be obeyed.'},
{id:385,cat:'rules',q:'What does a flashing amber beacon on a vehicle indicate?',opts:['An emergency vehicle responding to a call','A slow-moving or potentially hazardous vehicle','A vehicle that has broken down','A vehicle carrying dangerous goods'],ans:1,exp:'A flashing amber beacon warns you that the vehicle is slow-moving or could be a potential hazard, such as a road maintenance or recovery vehicle.'},
{id:386,cat:'rules',q:'At a Pelican crossing, what should you do if a pedestrian is still on the crossing when the flashing amber light appears?',opts:['Sound your horn to hurry them','Wait for them to finish crossing before driving on','Drive around them carefully','Flash your headlights as a warning'],ans:1,exp:'During the flashing amber phase at a Pelican crossing, you must give way to any pedestrians still on the crossing before moving off.'},
{id:387,cat:'rules',q:'When may you park on the right-hand side of the road at night?',opts:['Never','Only in a one-way street','Only on a dual carriageway','Only if you leave your sidelights on'],ans:1,exp:'You may park on the right-hand side of the road at night only if you are in a one-way street.'},
{id:388,cat:'rules',q:'What is the rule about parking near a junction?',opts:['You must not park within 10 metres of a junction','You may park anywhere near a junction on a quiet road','Parking near junctions is allowed if you leave your hazard lights on','You must not park within 5 metres of a junction'],ans:0,exp:'You must not park within 10 metres (32 feet) of a junction, as this could obstruct the view of other road users and create a hazard.'},
{id:389,cat:'rules',q:'What should you avoid doing when overtaking a vehicle at night?',opts:['Using your indicators','Using full beam headlights that could dazzle the driver you are passing','Checking your mirrors','Using your dipped headlights'],ans:1,exp:'When overtaking at night, do not use full beam headlights as they can dazzle the driver of the vehicle you are passing. Use dipped headlights.'},
{id:390,cat:'rules',q:'You are approaching a signal-controlled crossing and the amber light is flashing. What does this mean?',opts:['You must stop and wait','You may proceed if the crossing is clear of pedestrians','The signals are out of order','You must reverse away from the crossing'],ans:1,exp:'A flashing amber signal at a Pelican crossing means you may proceed if no pedestrians are on the crossing. Give way to anyone still crossing.'},
{id:391,cat:'rules',q:'What must you do when driving past a tram that has stopped at a tram stop?',opts:['Stop and wait until the tram moves off','Pass the tram carefully and watch for passengers stepping into the road','Speed past to avoid delaying traffic','Sound your horn to alert passengers'],ans:1,exp:'Pass a stationary tram carefully, watching for passengers who may step into the road, especially if there is no safety island at the stop.'},
{id:392,cat:'rules',q:'In which situation are you allowed to drive in a cycle lane marked by a solid white line?',opts:['When the cycle lane is empty','During the times shown on signs if the line is broken, but never if the line is solid during its operational hours','At any time if you are turning left','When there are no cyclists ahead'],ans:1,exp:'A mandatory cycle lane has a solid white line and you must not drive or park in it during its hours of operation. A broken line advisory cycle lane may be entered if necessary.'},
{id:393,cat:'rules',q:'What should you do if traffic lights are showing a green filter arrow to the left while the main light is red?',opts:['Wait until the main light turns green','You may proceed in the direction of the arrow with caution','Flash your headlights and proceed straight ahead','Ignore the arrow and wait for the full green'],ans:1,exp:'A green filter arrow means you may proceed in the direction shown, even if the main traffic light is red, but give way to pedestrians and other traffic.'},
{id:394,cat:'rules',q:'What is the rule regarding parking opposite a dropped kerb?',opts:['You may park there for up to 30 minutes','You must not park there as it is an access point for wheelchairs and pushchairs','You may park if you display a disabled badge','Parking is only prohibited during rush hours'],ans:1,exp:'Dropped kerbs are provided to assist wheelchair users, pushchair users, and pedestrians. You must not park in front of them.'},
{id:395,cat:'rules',q:'What distance must you park from a level crossing?',opts:['At least 5 metres','At least 10 metres','At least 15 metres','You must not park near a level crossing at all'],ans:2,exp:'You must not park within 15 metres of a level crossing to ensure clear visibility and safe passage for other road users.'},
{id:396,cat:'rules',q:'You arrive at a junction with traffic lights showing a steady green light. What should you check before entering?',opts:['Only your rear-view mirror','That the junction is clear and your exit road is not blocked','Only the traffic light colour','Whether there is a speed camera nearby'],ans:1,exp:'Even on a green light, you should check that the junction is clear and your exit is not blocked before entering to avoid blocking the junction.'},
{id:397,cat:'rules',q:'When is it legal to park on a pavement in England?',opts:['It is permitted everywhere','Only where signs specifically allow it; otherwise it is banned in London and restricted elsewhere','Whenever the road is narrow','Between 6 pm and 8 am only'],ans:1,exp:'Pavement parking is banned in London unless signed otherwise. Outside London, local authorities can restrict it but a national ban has been under review.'},
{id:398,cat:'rules',q:'What should you do when driving towards a tram that is signalling to move off from a stop?',opts:['Speed up to pass before it moves','Give way to the tram as you would to a bus signalling to pull out','Flash your headlights to stop it','Sound your horn to warn the driver'],ans:1,exp:'You should give way to a tram signalling to move off. Trams are large, run on fixed rails, and cannot manoeuvre around you.'},
{id:399,cat:'rules',q:'What speed limit applies in a pedestrian zone during the hours when vehicles are permitted?',opts:['There is no speed limit','A maximum of 10 mph typically applies','30 mph','20 mph in all cases'],ans:1,exp:'When vehicles are allowed to enter a pedestrian zone during restricted times, they should travel at a very low speed, typically around 10 mph or walking pace.'},
{id:400,cat:'rules',q:'How should you approach a road where lane discipline signs show lanes merging?',opts:['Speed up to get ahead of other traffic','Merge in turn with other traffic, showing courtesy','Force your way into the lane you need','Stop and wait for all traffic to clear'],ans:1,exp:'When lanes merge, use the merge-in-turn principle. Allow traffic to take turns feeding into the remaining lane, maintaining a safe following distance.'},
{id:401,cat:'rules',q:'What must you do when you see a school warning sign with flashing amber lights?',opts:['Maintain your current speed','Slow down and be prepared to stop for children crossing','Only slow down during term time','Stop completely until the lights stop flashing'],ans:1,exp:'Flashing amber lights with a school warning sign mean children may be crossing. Slow down and be prepared to stop.'},
{id:402,cat:'rules',q:'On which type of road would you find a contraflow system?',opts:['On a motorway or dual carriageway during roadworks','Only on one-way streets','Only in pedestrian zones','Only on residential roads'],ans:0,exp:'Contraflow systems are often used during motorway or dual carriageway roadworks, where traffic in both directions shares one carriageway. Follow signs and lane markings carefully.'},
{id:403,cat:'rules',q:'What does a single broken white line along the edge of the road mean?',opts:['The edge of the carriageway','A cycle lane','A bus lane','A parking bay'],ans:0,exp:'A broken white line along the edge of the road marks the boundary of the carriageway, helping you to stay on the road, especially at night.'},
{id:404,cat:'rules',q:'What is the Highway Code rule regarding overtaking near a school crossing?',opts:['Overtaking is permitted if the crossing patrol is not present','You must not overtake when approaching a school crossing patrol','You may overtake only on the left','Overtaking is allowed if children are on the pavement'],ans:1,exp:'You must not overtake near a school crossing patrol. Slow down and be prepared to stop for children and the crossing patrol.'},
{id:405,cat:'rules',q:'What should you do when you see a road sign showing a width restriction ahead?',opts:['Proceed at normal speed if your vehicle seems narrow enough','Slow down and check your vehicle’s width against the restriction shown','Speed up to pass through quickly','Only lorry drivers need to check their width'],ans:1,exp:'If a width restriction is shown, slow down and ensure your vehicle does not exceed the maximum width displayed before proceeding.'},
{id:406,cat:'rules',q:'What colour are the cat’s eyes that mark the edge of a motorway carriageway nearest the central reservation?',opts:['Red','White','Amber','Green'],ans:2,exp:'Amber cat’s eyes mark the right-hand edge of the carriageway nearest the central reservation. Red marks the left edge near the hard shoulder, and green marks slip road exits and entrances.'},
{id:407,cat:'rules',q:'When approaching a hump bridge, what should you do?',opts:['Speed up to maintain momentum','Slow down, keep to your side of the road, and be prepared for oncoming traffic you cannot see','Sound your horn before crossing','Stop at the top of the bridge to check for traffic'],ans:1,exp:'A hump bridge limits your view of the road ahead. Slow down, stay on your side, and be prepared for vehicles coming from the other direction.'},
{id:408,cat:'rules',q:'What is the rule about driving on a road with tramlines running along the centre?',opts:['You must not drive on the tramlines at any time','You may drive on the tramlines to overtake, but give way to trams','You should only cross them at junctions where signs permit','Follow the signs and markings; do not straddle the tramlines unless directed to do so'],ans:3,exp:'Follow road signs and markings around tramlines. Do not straddle or park on them unless road markings direct you to do so, and always give way to trams.'},
{id:409,cat:'rules',q:'What should you do if you are in the wrong lane at a roundabout and will miss your intended exit?',opts:['Signal and force your way across lanes','Continue around the roundabout and take the correct exit on the next circuit','Stop and reverse in your lane','Cross the central island to reach the correct exit'],ans:1,exp:'If you are in the wrong lane, do not make sudden lane changes. Continue safely around the roundabout and take the correct exit on the next circuit.'},
{id:410,cat:'rules',q:'You are driving along a road with speed cushions. How should you drive over them?',opts:['Straddle them so your wheels avoid the raised sections','Drive over them at the appropriate reduced speed for the zone','Speed up so the bumps feel less severe','Swerve around them using the oncoming lane'],ans:1,exp:'Speed cushions are traffic calming devices. Drive over them at the appropriate reduced speed. Do not swerve into the path of oncoming traffic to avoid them.'},
{id:411,cat:'safety',q:'Your vehicle catches fire while driving. What should you do first?',opts:['Open the bonnet to inspect','Pull over and get everyone out','Drive faster to blow out flames','Pour water on the engine'],ans:1,exp:'Stop safely, get everyone out and away from the vehicle, then call the fire service.'},
{id:412,cat:'safety',q:'Where should you keep a fire extinguisher in your car?',opts:['In the boot under luggage','Within easy reach inside the cabin','On the roof rack','In the glove compartment'],ans:1,exp:'A fire extinguisher should be easily accessible so you can use it quickly in an emergency.'},
{id:413,cat:'safety',q:'At the scene of an accident, an unconscious casualty is breathing normally. What should you do?',opts:['Give them water to drink','Place them in the recovery position','Sit them upright','Shake them vigorously'],ans:1,exp:'The recovery position keeps the airway clear and prevents choking if the casualty vomits.'},
{id:414,cat:'safety',q:'How should you place a casualty in the recovery position?',opts:['On their back with legs raised','On their front face down','On their side with the upper leg bent for support','Sitting up against a wall'],ans:2,exp:'The recovery position is on their side with the airway open and the upper leg bent to prevent rolling.'},
{id:415,cat:'safety',q:'At an accident scene, a casualty has stopped breathing. What should you do?',opts:['Place them in the recovery position','Begin CPR immediately','Wait for the ambulance','Give them a drink'],ans:1,exp:'If breathing has stopped, begin CPR with chest compressions and rescue breaths until help arrives.'},
{id:416,cat:'safety',q:'When should you use a warning triangle on the road?',opts:['Whenever you park legally','When your vehicle has broken down','When overtaking','At traffic lights'],ans:1,exp:'A warning triangle alerts other road users to a broken-down vehicle or obstruction ahead.'},
{id:417,cat:'safety',q:'How far behind your vehicle should you place a warning triangle on a single carriageway?',opts:['5 metres','20 metres','45 metres','100 metres'],ans:2,exp:'Place a warning triangle at least 45 metres behind your vehicle on the same side of the road.'},
{id:418,cat:'safety',q:'Why should you NOT use a warning triangle on a motorway?',opts:['It is too small to be seen','It is illegal to carry one','Placing it puts you at risk from fast-moving traffic','Motorways have their own warning systems'],ans:2,exp:'Walking on a live motorway carriageway to place a triangle is extremely dangerous due to high-speed traffic.'},
{id:419,cat:'safety',q:'You break down on a motorway. What should you do?',opts:['Stay in the right-hand lane with hazard lights on','Pull onto the hard shoulder, exit the vehicle from the left, and call for help','Try to repair the vehicle in the live lane','Wave down other drivers for assistance'],ans:1,exp:'Use the hard shoulder, get out via the left-side doors, move behind the barrier, and use the emergency telephone.'},
{id:420,cat:'safety',q:'On a smart motorway with no hard shoulder, where should you stop in an emergency?',opts:['In the left-hand lane','In an emergency refuge area','On the central reservation','In the outside lane'],ans:1,exp:'Emergency refuge areas are provided on smart motorways for breakdowns when there is no hard shoulder.'},
{id:421,cat:'safety',q:'While waiting on the hard shoulder of a motorway, where should you stand?',opts:['On the carriageway near your vehicle','Behind the vehicle','Well away from the carriageway, behind the barrier','In front of the vehicle'],ans:2,exp:'Stand behind the safety barrier, well away from the carriageway, to avoid being hit by passing traffic.'},
{id:422,cat:'safety',q:'What should you do when driving in very high winds?',opts:['Drive faster to maintain stability','Keep a firm grip on the steering and reduce speed','Open all windows for ventilation','Stay in the outside lane'],ans:1,exp:'High winds can blow your vehicle off course. Reduce speed and hold the steering wheel firmly.'},
{id:423,cat:'safety',q:'Which vehicles are most affected by high winds on exposed roads?',opts:['Low sports cars','High-sided vehicles, motorcycles, and cyclists','Heavy goods vehicles only','Vehicles with small engines'],ans:1,exp:'High-sided vehicles, motorcycles, and cyclists are particularly vulnerable to being blown off course by strong winds.'},
{id:424,cat:'safety',q:'You are driving into low sun glare. What should you do?',opts:['Speed up to get through the glare quickly','Slow down, use your sun visor, and wear sunglasses','Flash your headlights','Close your eyes briefly'],ans:1,exp:'Sun glare can severely reduce visibility. Slow down and use your sun visor or clean sunglasses.'},
{id:425,cat:'safety',q:'When is sun glare most likely to be a problem?',opts:['Midday in summer','When driving east at dawn or west at dusk','Only during winter','When it is raining'],ans:1,exp:'The sun is low on the horizon at dawn and dusk, causing glare directly in drivers\' eyes.'},
{id:426,cat:'safety',q:'A dirty windscreen can make sun glare worse. Why?',opts:['Dirt blocks all light','Dirt scatters light and increases glare','Dirt makes the glass stronger','Dirt has no effect on glare'],ans:1,exp:'A dirty or smeared windscreen scatters sunlight, making glare much worse and reducing visibility further.'},
{id:427,cat:'safety',q:'What extra hazard should you be aware of when driving at dawn or dusk?',opts:['Fewer vehicles on the road','Pedestrians and cyclists are harder to see in low light','Roads are always wet','Speed limits change'],ans:1,exp:'Visibility is reduced at dawn and dusk, making vulnerable road users harder to spot.'},
{id:428,cat:'safety',q:'Before entering a tunnel, what should you do?',opts:['Remove your sunglasses and turn on your headlights','Speed up to get through quickly','Turn off your headlights','Open all windows'],ans:0,exp:'Remove sunglasses so your eyes adjust and switch on dipped headlights to see and be seen in the tunnel.'},
{id:429,cat:'safety',q:'What should you do if your vehicle catches fire in a tunnel?',opts:['Stay in your vehicle','Drive out of the tunnel as fast as possible','Stop, switch off the engine, leave the vehicle, and use emergency exits','Reverse out of the tunnel'],ans:2,exp:'Leave the vehicle immediately and use the tunnel\'s emergency exits and fire points. Do not try to drive through.'},
{id:430,cat:'safety',q:'If traffic stops in a tunnel, what should you do?',opts:['Keep your engine running and stay close to the vehicle in front','Switch off your engine to reduce fumes and keep a safe distance','Sound your horn continuously','Reverse to the tunnel entrance'],ans:1,exp:'Switch off the engine to prevent a build-up of exhaust fumes in the enclosed tunnel.'},
{id:431,cat:'safety',q:'What do the red flashing lights at a level crossing mean?',opts:['You may proceed with caution','You must stop and wait','Speed up and cross quickly','The crossing is out of order'],ans:1,exp:'Red flashing lights mean you must stop. A train is approaching or the crossing is not clear.'},
{id:432,cat:'safety',q:'At a level crossing, the barriers are down but you cannot see a train. What should you do?',opts:['Drive around the barriers','Wait until the barriers rise fully','Reverse away from the crossing','Get out and check the track'],ans:1,exp:'Never drive around or past closed barriers. Wait until they are fully raised before crossing.'},
{id:433,cat:'safety',q:'What should you do if your vehicle breaks down on a level crossing?',opts:['Try to push it off the crossing alone','Get everyone out and call the signal operator immediately','Wait in the vehicle for help','Try to repair the vehicle on the crossing'],ans:1,exp:'Get everyone out and away from the crossing, then use the railway telephone to contact the signal operator.'},
{id:434,cat:'safety',q:'When carrying a heavy load in your vehicle, what should you check?',opts:['That you do not exceed the maximum authorised mass','That the load is visible from outside','That the windows are open','That the radio is turned off'],ans:0,exp:'Exceeding your vehicle\'s maximum authorised mass is illegal and makes the vehicle unsafe to drive.'},
{id:435,cat:'safety',q:'How does carrying a heavy load affect your vehicle?',opts:['It improves fuel economy','It makes steering lighter','It increases braking distances and affects handling','It has no effect on performance'],ans:2,exp:'A heavy load increases momentum, meaning longer stopping distances and reduced stability.'},
{id:436,cat:'safety',q:'What should you do before driving with a roof rack fitted?',opts:['Remove the vehicle aerial','Check the load is secure and within the weight limit','Drive a short test at high speed','Nothing, roof racks are always safe'],ans:1,exp:'An insecure or overloaded roof rack can cause items to fall off, endangering other road users.'},
{id:437,cat:'safety',q:'How does a loaded roof rack affect your vehicle?',opts:['It lowers the centre of gravity','It raises the centre of gravity, reducing stability','It improves aerodynamics','It has no effect'],ans:1,exp:'A roof rack raises the centre of gravity, making the vehicle less stable, especially on bends and in crosswinds.'},
{id:438,cat:'safety',q:'When coupling a trailer, what must you check?',opts:['That the trailer lights, brakes, and coupling are all working correctly','That the trailer is the same colour as the car','That the trailer has alloy wheels','That the trailer has a spare tyre on the roof'],ans:0,exp:'Lights, brakes, indicators, and a secure coupling are all legal requirements for towing a trailer.'},
{id:439,cat:'safety',q:'What can happen if a trailer is not properly coupled to the towing vehicle?',opts:['The trailer will slow you down','The trailer could detach and cause a serious collision','The engine will overheat','Nothing significant'],ans:1,exp:'An improperly coupled trailer can break free, posing an extreme danger to other road users.'},
{id:440,cat:'safety',q:'Which of the following is an eco-driving technique?',opts:['Harsh acceleration from every stop','Anticipating the road ahead and driving smoothly','Driving in the lowest gear at all times','Keeping the engine revs high'],ans:1,exp:'Smooth driving, gentle acceleration, and reading the road ahead all reduce fuel consumption.'},
{id:441,cat:'safety',q:'How can you reduce your vehicle\'s fuel consumption?',opts:['Avoid heavy braking by planning ahead','Carry unnecessary weight in the boot','Drive with under-inflated tyres','Leave the engine idling for long periods'],ans:0,exp:'Anticipating traffic flow and braking gently saves fuel compared to harsh braking and acceleration.'},
{id:442,cat:'safety',q:'At what speed does fuel consumption increase significantly?',opts:['Above 20 mph','Above 40 mph','Above 50-60 mph due to increased air resistance','Only above 100 mph'],ans:2,exp:'Air resistance increases rapidly above 50-60 mph, significantly increasing fuel consumption.'},
{id:443,cat:'safety',q:'How do correctly inflated tyres help with fuel economy?',opts:['They make no difference','They reduce rolling resistance, using less fuel','They increase engine power','They improve the sound system'],ans:1,exp:'Under-inflated tyres create more rolling resistance, meaning the engine works harder and uses more fuel.'},
{id:444,cat:'safety',q:'When might cruise control be a risk to use?',opts:['On a straight, dry motorway','On wet or icy roads where grip is reduced','When driving in light traffic','On a dual carriageway'],ans:1,exp:'Cruise control can cause wheelspin or loss of control on slippery surfaces as it tries to maintain speed.'},
{id:445,cat:'safety',q:'What should you do in an emergency when you need to brake suddenly?',opts:['Pump the brakes gently','Apply maximum braking force while keeping the steering wheel straight','Brake and steer sharply at the same time','Only use the handbrake'],ans:1,exp:'In an emergency, brake firmly and quickly. Keep the wheel straight to maintain control.'},
{id:446,cat:'safety',q:'What does ABS (Anti-lock Braking System) allow you to do during emergency braking?',opts:['Stop in a shorter distance on all surfaces','Continue to steer while braking hard','Accelerate and brake at the same time','Ignore road conditions'],ans:1,exp:'ABS prevents wheel lock-up, allowing you to maintain steering control during hard braking.'},
{id:447,cat:'safety',q:'How should you use the brakes on a vehicle fitted with ABS?',opts:['Pump the brake pedal rapidly','Apply firm, continuous pressure to the brake pedal','Only use the brakes lightly','Use the handbrake instead'],ans:1,exp:'With ABS, press the brake pedal firmly and hold it. The system will prevent the wheels from locking.'},
{id:448,cat:'safety',q:'Your vehicle starts to skid. What should you do?',opts:['Brake as hard as possible','Steer into the skid and ease off the accelerator','Accelerate to regain control','Turn the steering wheel in the opposite direction to the skid'],ans:1,exp:'Steer gently in the direction the rear of the car is sliding and ease off the accelerator to regain control.'},
{id:449,cat:'safety',q:'What is the main cause of skidding?',opts:['Faulty brakes','The driver braking, accelerating, or steering too harshly for the conditions','Worn windscreen wipers','A flat battery'],ans:1,exp:'Skids are almost always caused by the driver asking too much of the tyres for the available grip.'},
{id:450,cat:'safety',q:'You are driving on a wet motorway and your steering suddenly feels very light. What is happening?',opts:['Your power steering has failed','Your tyres are hydroplaning on a film of water','Your tyres are over-inflated','The road surface has improved'],ans:1,exp:'Light steering on a wet road means your tyres have lost contact with the surface due to hydroplaning.'},
{id:451,cat:'safety',q:'What should you do if your vehicle begins to hydroplane?',opts:['Brake firmly','Ease off the accelerator and do not brake harshly','Accelerate to push through the water','Turn the steering wheel sharply'],ans:1,exp:'Ease off the accelerator gently to allow the tyres to regain grip. Harsh braking could worsen the skid.'},
{id:452,cat:'safety',q:'Why is carbon monoxide dangerous in vehicles?',opts:['It has a strong smell that causes headaches','It is a colourless, odourless gas that can be fatal','It damages paintwork','It only affects diesel engines'],ans:1,exp:'Carbon monoxide is colourless and odourless, making it impossible to detect without a detector. It can kill.'},
{id:453,cat:'safety',q:'When is the risk of carbon monoxide poisoning greatest in a vehicle?',opts:['When driving at high speed','When the engine is running in an enclosed space with poor ventilation','When the vehicle is parked in the open air','When using electric windows'],ans:1,exp:'Running an engine in a garage or enclosed space allows carbon monoxide to build up to lethal levels.'},
{id:454,cat:'safety',q:'You are parked and waiting with the engine running. What should you do?',opts:['Keep all windows closed','Ensure there is adequate ventilation','Rev the engine to keep warm','Recirculate the cabin air'],ans:1,exp:'Good ventilation prevents the build-up of harmful exhaust fumes inside the vehicle.'},
{id:455,cat:'safety',q:'A casualty at a road accident is bleeding heavily from a wound. What should you do?',opts:['Remove any objects embedded in the wound','Apply firm pressure to the wound with a clean cloth','Give them food and water','Move them to a more comfortable position'],ans:1,exp:'Apply firm pressure with a clean material to slow or stop the bleeding until medical help arrives.'},
{id:456,cat:'safety',q:'At the scene of an accident, what should you do to protect against further danger?',opts:['Move injured people immediately','Switch off all vehicle engines and warn other traffic','Leave the scene to get help from a shop','Direct traffic yourself at high speed'],ans:1,exp:'Switch off engines to reduce fire risk and warn other traffic to prevent further collisions.'},
{id:457,cat:'safety',q:'When should you NOT move a casualty from a vehicle after an accident?',opts:['When they ask to be moved','When there is no further danger','When moving them could worsen spinal injuries and there is no immediate danger','When the weather is cold'],ans:2,exp:'Unless there is immediate danger such as fire, do not move a casualty as this could worsen spinal injuries.'},
{id:458,cat:'safety',q:'What should you remove before driving through a tunnel?',opts:['Your seatbelt','Tinted sunglasses to help your eyes adjust','Your shoes','The vehicle tax disc'],ans:1,exp:'Removing sunglasses before entering a tunnel helps your eyes adjust more quickly to the lower light.'},
{id:459,cat:'safety',q:'An object falls from your roof rack onto the road while driving. What should you do?',opts:['Ignore it and continue driving','Stop safely when possible, retrieve the object if safe, and report if necessary','Reverse back to collect it','Ask a passenger to lean out and grab it'],ans:1,exp:'Stop safely and retrieve the object to prevent it causing an accident. On motorways, do not attempt retrieval yourself—call Highways England.'},
{id:460,cat:'safety',q:'What is the main benefit of eco-driving techniques?',opts:['They allow you to drive faster','They reduce fuel consumption, emissions, and running costs','They wear out the brakes more quickly','They only work on electric vehicles'],ans:1,exp:'Eco-driving reduces fuel use and emissions, saving money and helping the environment.'},
{id:461,cat:'vehicle',q:'What is the main purpose of a vehicle\'s suspension system?',opts:['To increase engine power','To absorb road shocks and maintain tyre contact','To reduce fuel consumption','To improve braking distance'],ans:1,exp:'The suspension system absorbs shocks from the road surface and keeps the tyres in contact with the road for safe handling.'},
{id:462,cat:'vehicle',q:'What could happen if your shock absorbers are worn?',opts:['The engine will overheat','The vehicle may bounce excessively and take longer to stop','The steering wheel will lock','The exhaust will become louder'],ans:1,exp:'Worn shock absorbers cause excessive bouncing, reduced tyre contact with the road, and increased braking distances.'},
{id:463,cat:'vehicle',q:'How can you check if your shock absorbers are working correctly?',opts:['Listen for engine knocking','Push down firmly on each corner of the vehicle and release','Check the oil dipstick','Inspect the exhaust pipe'],ans:1,exp:'If the vehicle bounces more than once or twice after pushing down and releasing, the shock absorbers may be worn.'},
{id:464,cat:'vehicle',q:'What is a symptom of incorrect wheel alignment?',opts:['The horn sounds quieter','The vehicle pulls to one side or tyres wear unevenly','The headlights dim','The radio loses signal'],ans:1,exp:'Incorrect wheel alignment causes the vehicle to pull to one side and leads to uneven or rapid tyre wear.'},
{id:465,cat:'vehicle',q:'What problem can unbalanced wheels cause?',opts:['Engine misfiring','Vibration through the steering wheel, especially at higher speeds','Difficulty starting the engine','Poor radio reception'],ans:1,exp:'Unbalanced wheels cause vibrations felt through the steering wheel, particularly at higher speeds, and can cause uneven tyre wear.'},
{id:466,cat:'vehicle',q:'What does the alternator do in a vehicle?',opts:['It starts the engine','It filters the exhaust gases','It charges the battery and powers the electrical system while the engine runs','It controls the gearbox'],ans:2,exp:'The alternator generates electricity to charge the battery and power the vehicle\'s electrical systems while the engine is running.'},
{id:467,cat:'vehicle',q:'What might a red battery warning light on the dashboard indicate?',opts:['The tyres need inflating','The alternator may not be charging the battery','The fuel tank is full','The handbrake is released'],ans:1,exp:'A red battery warning light usually means the alternator is not charging the battery properly, which needs immediate attention.'},
{id:468,cat:'vehicle',q:'What is the function of the starter motor?',opts:['To keep the engine running at idle','To turn the engine over so it can start','To cool the engine','To power the headlights'],ans:1,exp:'The starter motor uses electrical energy from the battery to crank the engine and initiate combustion.'},
{id:469,cat:'vehicle',q:'What does the clutch do in a manual vehicle?',opts:['It applies the brakes','It connects and disconnects the engine from the gearbox','It charges the battery','It adjusts the mirrors'],ans:1,exp:'The clutch allows the driver to connect or disconnect the engine from the gearbox to change gear or stop without stalling.'},
{id:470,cat:'vehicle',q:'What can happen if you ride the clutch excessively?',opts:['The tyres will wear out','The clutch plate will wear prematurely','The windscreen will crack','The suspension will fail'],ans:1,exp:'Riding the clutch causes unnecessary friction and heat, leading to premature wear of the clutch plate and potential failure.'},
{id:471,cat:'vehicle',q:'What is a key difference between a manual and automatic gearbox?',opts:['Automatic vehicles have no engine','Manual vehicles cannot reverse','An automatic gearbox changes gear without the driver using a clutch pedal','Automatic vehicles use more oil'],ans:2,exp:'An automatic gearbox selects the appropriate gear automatically without the driver needing to operate a clutch pedal.'},
{id:472,cat:'vehicle',q:'In an automatic vehicle, what does \'creep\' refer to?',opts:['A slow oil leak','The vehicle moving slowly forward when in Drive with the brake released','The engine overheating','The steering pulling to one side'],ans:1,exp:'Automatic vehicles tend to creep forward slowly when in Drive or Reverse with the foot off the brake, due to the torque converter.'},
{id:473,cat:'vehicle',q:'What is the purpose of a turbocharger?',opts:['To reduce the vehicle\'s weight','To force more air into the engine to increase power output','To improve the air conditioning','To make the exhaust quieter'],ans:1,exp:'A turbocharger forces more air into the engine cylinders, allowing more fuel to be burned and increasing power output.'},
{id:474,cat:'vehicle',q:'Why might a turbocharged engine experience \'turbo lag\'?',opts:['Because the fuel tank is low','Because it takes a moment for exhaust gases to spin the turbine up to speed','Because the tyres are cold','Because the battery is flat'],ans:1,exp:'Turbo lag occurs because the turbocharger relies on exhaust gas flow to spin the turbine, which takes a brief moment to build up.'},
{id:475,cat:'vehicle',q:'What is the purpose of a diesel particulate filter (DPF)?',opts:['To improve engine power','To capture and store soot particles from the exhaust to reduce emissions','To filter the engine oil','To clean the fuel before injection'],ans:1,exp:'The DPF traps soot particles from diesel exhaust gases, reducing harmful particulate emissions into the atmosphere.'},
{id:476,cat:'vehicle',q:'What type of driving can cause a DPF to become blocked?',opts:['Frequent long motorway journeys','Frequent short, low-speed journeys','Driving in reverse','Driving with the windows open'],ans:1,exp:'Frequent short journeys at low speeds prevent the DPF from reaching the temperature needed to burn off trapped soot, causing blockages.'},
{id:477,cat:'vehicle',q:'What is AdBlue used for in diesel vehicles?',opts:['To clean the windscreen','To reduce nitrogen oxide (NOx) emissions from the exhaust','To lubricate the engine','To improve fuel octane rating'],ans:1,exp:'AdBlue is a urea-based solution injected into the exhaust system to convert harmful nitrogen oxides into harmless nitrogen and water.'},
{id:478,cat:'vehicle',q:'What happens if a vehicle fitted with an AdBlue system runs out of AdBlue?',opts:['The headlights will stop working','The engine may not restart once switched off or power may be reduced','The tyres will deflate','The radio will stop working'],ans:1,exp:'If AdBlue runs out, the vehicle may enter a reduced power mode or the engine may not restart, as required by emissions regulations.'},
{id:479,cat:'vehicle',q:'What type of charging point is typically used to charge an electric vehicle at home in the UK?',opts:['A three-pin plug only','A dedicated wallbox charger, typically 7 kW','A 100 kW rapid charger','A diesel generator'],ans:1,exp:'Most home EV charging in the UK uses a dedicated 7 kW wallbox charger, which is safer and faster than a standard three-pin plug.'},
{id:480,cat:'vehicle',q:'What should you be aware of when driving a fully electric vehicle at low speeds?',opts:['The brakes may not work','The vehicle may be very quiet, making it harder for pedestrians to hear','The steering will lock','The lights will not function'],ans:1,exp:'Electric vehicles are very quiet at low speeds, so pedestrians, cyclists, and other vulnerable road users may not hear you approaching.'},
{id:481,cat:'vehicle',q:'What is a hybrid vehicle?',opts:['A vehicle that uses only diesel fuel','A vehicle that combines an internal combustion engine with an electric motor','A vehicle with two steering wheels','A vehicle that can only drive on motorways'],ans:1,exp:'A hybrid vehicle uses both an internal combustion engine and one or more electric motors to improve fuel efficiency and reduce emissions.'},
{id:482,cat:'vehicle',q:'What is regenerative braking?',opts:['A system that replaces brake pads automatically','A system that recovers energy during braking and stores it in the battery','A type of handbrake','A system that increases braking distance'],ans:1,exp:'Regenerative braking uses the electric motor as a generator when slowing down, converting kinetic energy back into electrical energy to recharge the battery.'},
{id:483,cat:'vehicle',q:'How does regenerative braking feel different from conventional braking?',opts:['The vehicle accelerates when braking','The vehicle may slow down noticeably when you lift off the accelerator','The steering becomes heavier','The engine becomes louder'],ans:1,exp:'Regenerative braking often slows the vehicle when the driver lifts off the accelerator, which can feel like engine braking but more pronounced.'},
{id:484,cat:'vehicle',q:'How does using air conditioning affect your vehicle?',opts:['It has no effect','It increases fuel consumption','It improves engine power','It reduces tyre wear'],ans:1,exp:'Air conditioning puts extra load on the engine, which increases fuel consumption. Use it only when needed to save fuel.'},
{id:485,cat:'vehicle',q:'At lower speeds, what is a more fuel-efficient alternative to using air conditioning?',opts:['Using the heated rear window','Opening the windows','Turning on the headlights','Using the horn'],ans:1,exp:'At lower speeds, opening the windows can cool the car without the fuel penalty of air conditioning. At higher speeds, open windows increase drag.'},
{id:486,cat:'vehicle',q:'Where can you find your vehicle\'s maximum towing capacity?',opts:['On the number plates','In the vehicle handbook or on the VIN plate','On the tax disc','On the MOT certificate'],ans:1,exp:'The vehicle handbook and the VIN plate (or vehicle identification plate) show the maximum towing capacity and gross train weight.'},
{id:487,cat:'vehicle',q:'What effect does fitting a roof box have on your vehicle?',opts:['It improves fuel efficiency','It increases aerodynamic drag and fuel consumption','It makes the vehicle lower','It improves acceleration'],ans:1,exp:'A roof box increases the vehicle\'s frontal area and disrupts airflow, increasing aerodynamic drag and fuel consumption.'},
{id:488,cat:'vehicle',q:'What should you do with a roof box when it is not in use?',opts:['Leave it on for convenience','Remove it to reduce drag and improve fuel economy','Fill it with heavy items','Paint it to match the car'],ans:1,exp:'Removing a roof box when not in use reduces aerodynamic drag and improves fuel economy, even if the box is empty.'},
{id:489,cat:'vehicle',q:'When must your number plate lights be working?',opts:['Only during the day','At all times when your vehicle is on the road at night or in poor visibility','Only when reversing','Only during an MOT test'],ans:1,exp:'Number plate lights must illuminate the rear number plate at night and in poor visibility. They are a legal requirement and checked during the MOT.'},
{id:490,cat:'vehicle',q:'When should you use your sidelights?',opts:['When driving on a motorway','When parked on a road with a speed limit over 30 mph at night','When overtaking','Only during the day'],ans:1,exp:'Sidelights must be used when parking at night on a road with a speed limit greater than 30 mph, so your vehicle remains visible.'},
{id:491,cat:'vehicle',q:'What are daytime running lights designed to do?',opts:['Illuminate the road ahead at night','Make your vehicle more visible to other road users during the day','Help you see in fog','Light up the dashboard'],ans:1,exp:'Daytime running lights improve the visibility of your vehicle to other road users during daylight hours, reducing the risk of collisions.'},
{id:492,cat:'vehicle',q:'When do reversing lights come on?',opts:['When you turn on the headlights','Automatically when reverse gear is selected','When you press the brake pedal','When you sound the horn'],ans:1,exp:'Reversing lights activate automatically when reverse gear is selected, warning other road users that the vehicle is about to move backwards.'},
{id:493,cat:'vehicle',q:'Why is it important to check that your indicator bulbs are working?',opts:['To improve fuel economy','So other road users can see your intended direction of travel','To make the engine run smoothly','To keep the battery charged'],ans:1,exp:'Working indicators are essential for signalling your intentions to other road users. A fast-clicking indicator often means a bulb has failed.'},
{id:494,cat:'vehicle',q:'When is it illegal to sound your horn?',opts:['At a junction','In a built-up area between 11:30 pm and 7:00 am while stationary','When overtaking','On a dual carriageway'],ans:1,exp:'It is illegal to sound your horn in a built-up area between 11:30 pm and 7:00 am while your vehicle is stationary, unless a moving vehicle poses a danger.'},
{id:495,cat:'vehicle',q:'What is the most effective way to demist your windscreen quickly?',opts:['Open all the windows fully','Use the air conditioning or heated windscreen with the blower directed at the windscreen','Drive faster','Turn off all electrical systems'],ans:1,exp:'Using the demister setting with air conditioning removes moisture from the air quickly, clearing the windscreen effectively.'},
{id:496,cat:'vehicle',q:'What is the purpose of a heated rear window?',opts:['To keep passengers warm','To clear condensation and ice from the rear window for visibility','To charge the battery','To heat the boot space'],ans:1,exp:'The heated rear window has embedded heating elements that clear condensation, frost, and ice to maintain rear visibility.'},
{id:497,cat:'vehicle',q:'Why should you switch off your heated rear window once the screen is clear?',opts:['It will crack the glass','It uses a significant amount of electrical energy and increases fuel consumption','It damages the wiper blades','It affects the steering'],ans:1,exp:'The heated rear window draws a significant electrical current, increasing the load on the alternator and raising fuel consumption.'},
{id:498,cat:'vehicle',q:'What should you do if your electric mirror adjustment stops working?',opts:['Remove the mirror','Adjust the mirror manually if possible and have the electrical fault checked','Ignore it as mirrors are optional','Cover the mirror'],ans:1,exp:'If electric mirror adjustment fails, adjust the mirror by hand if the design allows and have the electrical fault investigated by a qualified technician.'},
{id:499,cat:'vehicle',q:'How can parking sensors help you?',opts:['They automatically steer the vehicle','They alert you to obstacles nearby when manoeuvring at low speed','They reduce fuel consumption','They improve top speed'],ans:1,exp:'Parking sensors use ultrasonic or electromagnetic signals to detect nearby obstacles and warn the driver with audible or visual alerts when manoeuvring.'},
{id:500,cat:'vehicle',q:'What benefit can a dash cam provide?',opts:['It reduces your road tax','It can provide video evidence in the event of an incident or collision','It improves fuel economy','It increases engine power'],ans:1,exp:'A dash cam records video footage of the road ahead, which can be used as evidence in the event of a collision or insurance claim.'},
{id:501,cat:'signs',q:'What does a temporary road sign with a yellow background indicate?',opts:['A permanent change to the road layout','Roadworks or temporary hazards ahead','A scenic route diversion','A private road ahead'],ans:1,exp:'Temporary signs have yellow backgrounds to warn drivers of roadworks or temporary hazards.'},
{id:502,cat:'signs',q:'Which shape is used for diversion route symbols on black signs?',opts:['Only circles','Only triangles','Only squares','Squares, triangles, circles, or diamonds'],ans:3,exp:'Diversion route symbols use four shapes: square, triangle, circle, and diamond, each marking a different diversion route.'},
{id:503,cat:'signs',q:'Why are different shapes used for diversion route symbols?',opts:['To indicate the speed limit on the diversion','To distinguish between multiple diversion routes at the same point','To show the length of the diversion','To indicate whether the road is open to HGVs'],ans:1,exp:'Different shapes allow drivers to follow the correct diversion when multiple routes operate from the same location.'},
{id:504,cat:'signs',q:'What does a square symbol on a black background indicate on a diversion sign?',opts:['A scenic route','One of four possible diversion routes','An emergency-only route','A route for heavy goods vehicles only'],ans:1,exp:'The square is one of four geometric symbols used to mark different diversion routes.'},
{id:505,cat:'signs',q:'What does a triangular warning sign showing the road narrowing on both sides mean?',opts:['Road narrows on the left only','Road narrows on both sides','Two lanes merge into one from the right','The road is closing ahead'],ans:1,exp:'A road narrows sign showing both sides narrowing warns that the carriageway becomes narrower ahead on both sides.'},
{id:506,cat:'signs',q:'What does a triangular warning sign showing the road narrowing on the right side mean?',opts:['Road narrows on the right','Traffic merges from the right','Right lane ends','Right turn only ahead'],ans:0,exp:'The sign warns that the road becomes narrower on the right-hand side ahead.'},
{id:507,cat:'signs',q:'What does a triangular sign showing two arrows pointing towards each other vertically mean?',opts:['Road ahead splits into two','Two-way traffic crosses a one-way road','Two-way traffic ahead on the road you are using','Dual carriageway ahead'],ans:2,exp:'This sign warns that you are about to enter a section of road with two-way traffic, for example after leaving a one-way street.'},
{id:508,cat:'signs',q:'When would you expect to see a two-way traffic sign?',opts:['On a motorway slip road','When leaving a one-way street onto a two-way road','At a roundabout exit','On a dual carriageway'],ans:1,exp:'The two-way traffic sign is commonly seen when a one-way system ends and normal two-way traffic resumes.'},
{id:509,cat:'signs',q:'What does a triangular warning sign showing a car driving through water mean?',opts:['Car wash ahead','Flood risk area','Ford ahead','Slippery road surface'],ans:2,exp:'This sign warns of a ford ahead, where the road passes through a stream or river.'},
{id:510,cat:'signs',q:'What should you do when you see a ford warning sign?',opts:['Speed up to get through quickly','Stop and find an alternative route','Slow down and check the depth of water before crossing','Sound your horn before entering'],ans:2,exp:'You should slow down and assess the depth of the water. After crossing, test your brakes as they may be wet and less effective.'},
{id:511,cat:'signs',q:'What does a triangular warning sign showing a grid of vertical lines across the road indicate?',opts:['Level crossing ahead','Cattle grid ahead','Road surface change','Speed bumps ahead'],ans:1,exp:'This sign warns of a cattle grid ahead, commonly found in rural areas to prevent livestock crossing boundaries.'},
{id:512,cat:'signs',q:'What does a triangular warning sign showing a quayside or river bank mean?',opts:['Ferry terminal ahead','Danger of falling into water ahead','Swimming area nearby','Boat ramp ahead'],ans:1,exp:'The quayside or river bank warning sign alerts drivers to the danger of vehicles going over the edge into water.'},
{id:513,cat:'signs',q:'What does a triangular warning sign showing a tunnel entrance mean?',opts:['Underground car park ahead','Tunnel ahead','Bridge ahead','Underpass for pedestrians'],ans:1,exp:'This sign warns of a tunnel ahead. You should switch on your headlights and remove sunglasses before entering.'},
{id:514,cat:'signs',q:'What should you do when you see a tunnel ahead sign?',opts:['Speed up to pass through quickly','Switch on headlights and be prepared for a change in conditions','Keep your sunglasses on to reduce glare','Open your windows fully'],ans:1,exp:'Before entering a tunnel, switch on dipped headlights, remove sunglasses, and tune to the indicated radio frequency if shown.'},
{id:515,cat:'signs',q:'What does a diamond-shaped sign with a white tram symbol on a blue background indicate?',opts:['Tram stop ahead','Trams only beyond this point','Route to be used by trams','Railway station ahead'],ans:2,exp:'Diamond-shaped blue signs with a tram symbol indicate routes used by trams.'},
{id:516,cat:'signs',q:'What shape are signs giving orders or warnings specifically related to trams?',opts:['Circular','Triangular','Diamond','Rectangular'],ans:2,exp:'Tram signs are diamond-shaped to distinguish them from signs intended for other road users.'},
{id:517,cat:'signs',q:'What does a triangular warning sign showing tram rails crossing the road mean?',opts:['Railway crossing ahead','Tramway crossing ahead','Track maintenance in progress','Heritage railway ahead'],ans:1,exp:'This sign warns that tram rails cross or run along the road ahead. Take extra care, especially in wet conditions when rails can be slippery.'},
{id:518,cat:'signs',q:'What does a blue rectangular sign with a white bicycle symbol indicate?',opts:['No cycling allowed','Cycle lane or route ahead','Bicycle parking','Bicycle repair station'],ans:1,exp:'Blue rectangular signs with a bicycle symbol indicate a recommended cycle route or cycle lane.'},
{id:519,cat:'signs',q:'What does a blue circular sign with a white bicycle symbol mean?',opts:['Cycle parking ahead','Route recommended for cyclists','Route to be used by pedal cycles only','No cycling beyond this point'],ans:2,exp:'A blue circular sign with a bicycle means the route is for pedal cycles only. Circular blue signs give mandatory instructions.'},
{id:520,cat:'signs',q:'What does a sign showing a bicycle above a horizontal line with a bus below it indicate?',opts:['Buses and cycles share the same lane','Cyclists must give way to buses','Bus stop with cycle parking','No buses or cycles allowed'],ans:0,exp:'This sign indicates a bus lane that may also be used by cyclists.'},
{id:521,cat:'signs',q:'What does a rectangular sign saying "BUS LANE" with operating hours mean?',opts:['Buses can park here during these times','The lane is reserved for buses and permitted vehicles during the stated hours','All traffic may use the lane during these hours','The road is closed to all traffic during these hours'],ans:1,exp:'Bus lane signs show the hours of operation. During these times, only buses and other permitted vehicles such as taxis and cyclists may use the lane.'},
{id:522,cat:'signs',q:'What might happen if you drive in a bus lane during its hours of operation without permission?',opts:['Nothing, bus lanes are advisory only','You could receive a penalty charge notice','Your vehicle could be impounded','You will be stopped by police immediately'],ans:1,exp:'Driving in a bus lane during operational hours can result in a penalty charge notice, often issued by camera enforcement.'},
{id:523,cat:'signs',q:'What does the congestion charge sign with a white letter C on a red circle indicate?',opts:['Car park ahead','City centre ahead','You are entering a congestion charging zone','Clearway - no stopping'],ans:2,exp:'The red C sign indicates entry into a congestion charging zone where a daily charge applies to most vehicles.'},
{id:524,cat:'signs',q:'What should you be prepared to do when you see a congestion charge zone sign?',opts:['Stop and pay at a toll booth','Pay the charge online, by phone, or at a retail outlet','Show your driving licence at a checkpoint','Nothing, it only applies to commercial vehicles'],ans:1,exp:'The congestion charge must be paid by the end of the charging day. Payment can be made online, by phone, or at designated outlets.'},
{id:525,cat:'signs',q:'What does a sign showing "Low Emission Zone" with a green boundary line indicate?',opts:['An area with reduced speed limits to cut emissions','An area where the most polluting vehicles must pay a charge or are banned','A zone where only electric vehicles are allowed','A pedestrian-only zone'],ans:1,exp:'Low Emission Zone signs indicate areas where vehicles that do not meet emission standards must pay a daily charge or face a penalty.'},
{id:526,cat:'signs',q:'What is the purpose of a Low Emission Zone?',opts:['To reduce traffic congestion','To improve air quality by discouraging the most polluting vehicles','To raise revenue for road maintenance','To encourage cycling and walking only'],ans:1,exp:'Low Emission Zones aim to improve air quality by deterring the most polluting vehicles from entering the area.'},
{id:527,cat:'signs',q:'What does a circular sign with a red border showing a height measurement such as "4.4m" mean?',opts:['Recommended height for vehicles','No vehicles over the height shown','Distance to the next bridge','Height of the road above sea level'],ans:1,exp:'A circular sign with a red border showing a height is a prohibition sign meaning no vehicles exceeding that height may proceed.'},
{id:528,cat:'signs',q:'Why is it important to know your vehicle\'s height before driving under a height restriction sign?',opts:['To calculate fuel consumption','To avoid striking a low bridge or other structure','To determine the correct lane','To adjust tyre pressures'],ans:1,exp:'Striking a bridge can cause serious damage, injury, and disruption. You must know your vehicle\'s height and obey height restriction signs.'},
{id:529,cat:'signs',q:'What does a triangular warning sign showing "14\'6\"" indicate?',opts:['Speed limit of 14.6 mph','Weight limit of 14.6 tonnes','Available height of the bridge or structure ahead is 14 feet 6 inches','Distance to the next junction is 14.6 miles'],ans:2,exp:'Triangular signs showing height in imperial measurements warn of a low bridge or structure ahead with restricted headroom.'},
{id:530,cat:'signs',q:'What does a circular sign with a red border showing a width measurement mean?',opts:['Minimum lane width ahead','No vehicles wider than the measurement shown','Recommended vehicle width','Width of the parking spaces ahead'],ans:1,exp:'This prohibition sign means vehicles exceeding the width shown must not proceed.'},
{id:531,cat:'signs',q:'What does a circular sign with a red border and a U-turn arrow crossed out mean?',opts:['U-turns recommended','No U-turns allowed','No left turn','No right turn'],ans:1,exp:'A red circle with a crossed-out U-turn arrow means making a U-turn is prohibited at that location.'},
{id:532,cat:'signs',q:'What does a circular blue sign with a red cross and red border mean?',opts:['No entry for vehicles','No waiting at any time','No stopping at any time (clearway)','Hospital ahead'],ans:2,exp:'The clearway sign means no stopping is allowed on the main carriageway at any time, not even to pick up or set down passengers.'},
{id:533,cat:'signs',q:'On which type of road would you most likely see a clearway sign?',opts:['A residential street','An urban clearway or main road','A car park entrance','A motorway hard shoulder'],ans:1,exp:'Clearway signs are commonly found on urban clearways and main roads where stopping would obstruct traffic flow.'},
{id:534,cat:'signs',q:'What does a rectangular sign saying "ZONE" with parking restriction symbols indicate?',opts:['A multi-storey car park','Entry to a controlled parking zone','A park and ride scheme','A pedestrian zone'],ans:1,exp:'Controlled zone entry signs indicate areas where specific parking or waiting restrictions apply throughout the zone.'},
{id:535,cat:'signs',q:'What does the "End of controlled zone" sign mean?',opts:['Speed limits no longer apply','The zone parking restrictions shown on the entry sign no longer apply','All road signs are now advisory','You have left the urban area'],ans:1,exp:'The end of controlled zone sign means the parking and waiting restrictions that applied within the zone have ended.'},
{id:536,cat:'signs',q:'What does a blue sign with a white motorway symbol and the word "End" mean?',opts:['End of speed limit','End of dual carriageway','End of motorway regulations','End of the road'],ans:2,exp:'This sign indicates that motorway regulations no longer apply. You may encounter different speed limits, junctions, and other road users.'},
{id:537,cat:'signs',q:'What should you do when you see an "End of motorway" sign?',opts:['Immediately reduce speed to 30 mph','Be prepared for different driving conditions and adjust your speed','Move into the left lane and stop','Flash your headlights to warn other drivers'],ans:1,exp:'After the end of motorway sign, you may encounter roundabouts, traffic lights, and slower traffic. Adjust your driving accordingly.'},
{id:538,cat:'signs',q:'What does a blue rectangular sign with a white motorway symbol indicate at the start of a slip road?',opts:['Services ahead','Start of motorway - motorway regulations apply','Dual carriageway begins','Fast lane ahead'],ans:1,exp:'This sign indicates the start of a motorway where motorway regulations, including minimum speed capabilities and vehicle restrictions, apply.'},
{id:539,cat:'signs',q:'What does a rectangular yellow plate showing "MAX SPEED 30 advisory" mean?',opts:['The speed limit is legally 30 mph','30 mph is the recommended maximum speed but not legally enforced','You must drive at exactly 30 mph','The road is closed above 30 mph'],ans:1,exp:'Advisory speed plates suggest a safe maximum speed for a hazard but are not legally enforceable like speed limit signs.'},
{id:540,cat:'signs',q:'Where would you typically see an advisory speed plate?',opts:['On a motorway','Beneath a warning sign for a bend, roundabout, or other hazard','At traffic lights','In a car park'],ans:1,exp:'Advisory speed plates are placed below warning signs to suggest a safe speed for approaching hazards such as sharp bends.'},
{id:541,cat:'signs',q:'What are the small posts with coloured reflectors found at the edge of motorways?',opts:['Speed cameras','Distance marker posts (driver location signs)','Decoration','Parking zone indicators'],ans:1,exp:'Distance marker posts on motorways are placed every 100 metres and help identify your location in an emergency.'},
{id:542,cat:'signs',q:'What information can you find on a driver location sign on a motorway?',opts:['The nearest fuel station','The motorway number and your precise location','The speed limit','Traffic density information'],ans:1,exp:'Driver location signs show the motorway number, direction of travel, and a location reference to help emergency services find you.'},
{id:543,cat:'signs',q:'What colour are the reflective studs on the left-hand edge of a motorway?',opts:['White','Amber','Red','Green'],ans:2,exp:'Red reflective studs mark the left-hand edge of the carriageway (nearest the hard shoulder on a motorway).'},
{id:544,cat:'signs',q:'What do amber reflective studs on a motorway indicate?',opts:['The left edge of the carriageway','The central reservation (middle of the road)','The edge of the hard shoulder','A lane closed ahead'],ans:1,exp:'Amber studs mark the central reservation, separating carriageways on a motorway or dual carriageway.'},
{id:545,cat:'signs',q:'What do green reflective studs indicate?',opts:['The central reservation','A contraflow system','The edge of the main carriageway at a lay-by or slip road','A cycle lane boundary'],ans:2,exp:'Green reflective studs mark the edge of the main carriageway at lay-bys and slip roads.'},
{id:546,cat:'signs',q:'What information can variable message signs on motorways display?',opts:['Only speed limits','Only weather forecasts','Warnings about congestion, lane closures, speed limits, and other hazards','Only fuel prices'],ans:2,exp:'Variable message signs (VMS) display real-time information including speed limits, lane closures, congestion warnings, and incident alerts.'},
{id:547,cat:'signs',q:'What does a flashing amber signal on a variable message sign above a motorway lane mean?',opts:['The lane is closed','Change lanes immediately','A temporary speed limit or warning applies - proceed with caution','The lane is for emergency vehicles only'],ans:2,exp:'Flashing amber signals on overhead gantries indicate a warning or advisory. You should comply with the information shown.'},
{id:548,cat:'signs',q:'What does a red X displayed on a variable message sign above a motorway lane mean?',opts:['Reduce speed','Use this lane with caution','Do not use this lane - it is closed','Emergency vehicles approaching'],ans:2,exp:'A red X means the lane is closed. You must not drive in a lane showing a red X. Move safely into an open lane.'},
{id:549,cat:'signs',q:'On a temporary yellow road sign at roadworks, what does a black arrow pointing left mean?',opts:['Left turn only','Traffic should move to the left to avoid the obstruction','Road curves to the left','Left lane closed ahead'],ans:1,exp:'On temporary yellow signs, black arrows direct traffic to move in the direction shown to navigate safely around roadworks.'},
{id:550,cat:'signs',q:'What do white reflective studs on a motorway mark?',opts:['The hard shoulder edge','Lane markings separating traffic lanes','The central reservation','Slip road boundaries'],ans:1,exp:'White reflective studs mark the lane boundaries between traffic lanes on a motorway.'},
{id:551,cat:'hazards',q:'You are driving on a dual carriageway and see a vehicle ahead with its hazard warning lights on. What should you do?',opts:['Overtake it quickly','Slow down and be prepared to stop','Flash your headlights at it','Sound your horn'],ans:1,exp:'Hazard warning lights on a dual carriageway indicate a problem ahead. Slow down and be ready to stop.'},
{id:552,cat:'hazards',q:'What is a particular danger when joining a dual carriageway from a slip road?',opts:['Traffic on the dual carriageway may be travelling much faster than you expect','The slip road will always have traffic lights','You must always stop at the end of the slip road','Vehicles on the dual carriageway must give way to you'],ans:0,exp:'Traffic on dual carriageways travels at high speed. You must adjust your speed on the slip road to merge safely.'},
{id:553,cat:'hazards',q:'You are driving on a country road and see mud on the road surface. What hazard does this present?',opts:['It will damage your tyres','It may make the road very slippery','It means the road is closed ahead','It indicates a speed camera is nearby'],ans:1,exp:'Mud on the road, often from farm vehicles, can be very slippery and significantly reduce your grip.'},
{id:554,cat:'hazards',q:'What should you be especially aware of when driving on narrow country roads?',opts:['Speed cameras are more common','Pedestrians, horses and slow-moving farm vehicles','There are no road markings anywhere','You always have right of way'],ans:1,exp:'Country roads are shared by many vulnerable users including pedestrians, horse riders and slow agricultural vehicles.'},
{id:555,cat:'hazards',q:'You are driving in an urban area and notice a pedestrian walking along the pavement looking at their phone. What should you do?',opts:['Sound your horn to get their attention','Speed up to pass them quickly','Be prepared for them to step into the road without looking','Flash your headlights at them'],ans:2,exp:'Distracted pedestrians using phones may step into the road without checking for traffic. Anticipate this hazard.'},
{id:556,cat:'hazards',q:'Why are urban junctions particularly hazardous?',opts:['They always have traffic lights','There are fewer road signs','Multiple road users including cyclists and pedestrians may be present','Speed limits are always 20 mph'],ans:2,exp:'Urban junctions are busy with various road users. You must check carefully for cyclists, pedestrians and other vehicles.'},
{id:557,cat:'hazards',q:'When driving at night, what should you do if you are dazzled by the headlights of an oncoming vehicle?',opts:['Flash your headlights back at them','Slow down and if necessary stop','Stare directly at the oncoming lights','Speed up to pass the vehicle quickly'],ans:1,exp:'If dazzled, slow down or stop if necessary. Avoid looking directly at the oncoming headlights.'},
{id:558,cat:'hazards',q:'At night, what does a single headlight coming towards you on a road most likely indicate?',opts:['A car with one headlight not working or a motorcycle','A bicycle with a bright light','A pedestrian with a torch','A parked vehicle'],ans:0,exp:'A single headlight could be a motorcycle or a vehicle with a faulty headlight. Be cautious as judging its speed and position is harder.'},
{id:559,cat:'hazards',q:'Why is driving at dawn or dusk particularly hazardous?',opts:['Street lights are always switched off','The low sun can cause serious glare and other road users are harder to see','Speed limits are reduced','Road surfaces change at these times'],ans:1,exp:'At dawn and dusk, the low sun causes glare and the changing light makes other road users harder to see.'},
{id:560,cat:'hazards',q:'What should you do if the sun is low and directly in your eyes while driving?',opts:['Use your sun visor and slow down','Close your eyes briefly','Overtake the vehicle in front to get out of the sun','Ignore it and continue at the same speed'],ans:0,exp:'Use your sun visor and clean windscreen to reduce glare. Slow down because your visibility is reduced.'},
{id:561,cat:'hazards',q:'You are driving in autumn and notice wet leaves on the road. Why is this dangerous?',opts:['They will block your exhaust','They can be as slippery as ice when wet','They will scratch your paintwork','They make no difference to driving'],ans:1,exp:'Wet leaves on the road can be extremely slippery, similar to driving on ice, and can significantly increase stopping distances.'},
{id:562,cat:'hazards',q:'You see a rainbow-coloured patch on the road surface. What does this indicate?',opts:['The road has recently been resurfaced','There is an oil spill on the road','Water is flowing across the road','The road markings have been repainted'],ans:1,exp:'A rainbow-coloured sheen on the road indicates an oil spill. This will make the surface very slippery, especially when wet.'},
{id:563,cat:'hazards',q:'How should you deal with an oil spill on the road?',opts:['Brake hard to stop before you reach it','Reduce your speed and avoid sudden braking or steering','Accelerate to drive through it quickly','Swerve sharply to avoid it'],ans:1,exp:'On an oil spill, reduce speed gradually and avoid harsh braking or steering, as the surface will be very slippery.'},
{id:564,cat:'hazards',q:'You are driving on a road with loose gravel. What should you do?',opts:['Drive at normal speed','Reduce your speed to avoid throwing up stones and losing grip','Brake hard if you feel the tyres slipping','Drive as close to the centre line as possible'],ans:1,exp:'Loose gravel reduces tyre grip and can be thrown up by your tyres, damaging other vehicles. Slow down.'},
{id:565,cat:'hazards',q:'What is the purpose of road humps in residential areas?',opts:['To test your vehicle\'s suspension','To slow traffic down and improve safety','To mark the entrance to a motorway','To indicate a change in speed limit'],ans:1,exp:'Road humps are traffic-calming measures designed to slow vehicles down in residential areas to protect pedestrians.'},
{id:566,cat:'hazards',q:'How should you approach a series of road humps?',opts:['Speed up between each hump','Brake sharply on each hump','Slow down and maintain a steady reduced speed','Swerve to avoid them'],ans:2,exp:'Maintain a steady, reduced speed over road humps. Harsh braking or acceleration between them is uncomfortable and can damage your vehicle.'},
{id:567,cat:'hazards',q:'What is the purpose of chicanes on a road?',opts:['To provide extra parking spaces','To slow traffic by creating a winding route','To widen the road at junctions','To improve drainage'],ans:1,exp:'Chicanes are traffic-calming features that create a winding path to slow vehicles down, often used in residential areas.'},
{id:568,cat:'hazards',q:'You are approaching a road that narrows and there is oncoming traffic. What should you do?',opts:['Speed up to get through first','Be prepared to give way to oncoming traffic if the obstruction is on your side','Always give way regardless of which side the obstruction is on','Sound your horn and proceed'],ans:1,exp:'If the obstruction causing the narrowing is on your side, you should give way to oncoming traffic.'},
{id:569,cat:'hazards',q:'What is a passing place on a single-track road used for?',opts:['Parking your vehicle','Allowing vehicles travelling in opposite directions to pass each other','Overtaking slower vehicles at speed','Emergency stopping only'],ans:1,exp:'Passing places on single-track roads allow vehicles to pass each other safely. They should not be used for parking.'},
{id:570,cat:'hazards',q:'On a single-track road, you see an oncoming vehicle. There is a passing place on your left. What should you do?',opts:['Flash your lights and continue','Speed up to reach the next passing place','Pull into the passing place on your left to let the other vehicle pass','Stop in the middle of the road'],ans:2,exp:'Pull into the passing place on your left. If the passing place is on your right, wait opposite it to let the other vehicle use it.'},
{id:571,cat:'hazards',q:'You are approaching a railway level crossing and the red lights start flashing. What must you do?',opts:['Speed up to cross before the barriers come down','Stop behind the white line and wait','Cross if you think you have time','Reverse away from the crossing'],ans:1,exp:'When red lights flash at a level crossing, you must stop behind the white line. It is illegal and extremely dangerous to cross.'},
{id:572,cat:'hazards',q:'At an automatic half-barrier level crossing, why must you never zigzag around the barriers?',opts:['It is only illegal at night','A train may be approaching on the other track that you cannot see','The barriers will rise more quickly if you wait','It will damage your vehicle'],ans:1,exp:'Half barriers only cover the left side of the road. Zigzagging around them is extremely dangerous as a train could be approaching from either direction.'},
{id:573,cat:'hazards',q:'You are at a level crossing with no barriers or lights. What should you do?',opts:['Cross without stopping as there are no signals','Stop, look both ways and listen for trains before crossing','Sound your horn and drive across quickly','Wait for another vehicle to cross first'],ans:1,exp:'At open level crossings without barriers or lights, you must stop, look both ways and listen carefully for approaching trains.'},
{id:574,cat:'hazards',q:'What should you do if your vehicle breaks down on a railway level crossing?',opts:['Stay in the vehicle and call for help','Get everyone out of the vehicle and clear of the crossing, then call the signal operator','Try to push the vehicle off the crossing alone','Wait for the next train to stop and help'],ans:1,exp:'Get everyone out and clear immediately. Use the railway telephone to contact the signal operator before trying to move the vehicle.'},
{id:575,cat:'hazards',q:'Why are tram rails a particular hazard for cyclists and motorcyclists?',opts:['Trams travel too slowly','The rails can be slippery and wheels can get caught in the grooves','Trams always have priority at junctions','The rails cause punctures'],ans:1,exp:'Tram rails are smooth and can be very slippery, especially when wet. Cycle and motorcycle wheels can also become trapped in the grooves.'},
{id:576,cat:'hazards',q:'Where should you look when driving in an area with trams?',opts:['Only in your mirrors','Only at the traffic lights','In all directions, including checking for trams approaching from behind when turning','Only ahead'],ans:2,exp:'Trams can approach silently from any direction. Always check all around, especially before turning across tram tracks.'},
{id:577,cat:'hazards',q:'An aggressive driver is tailgating you. What is the safest response?',opts:['Brake sharply to teach them a lesson','Speed up to create a gap','Allow them to overtake by pulling over when safe','Slam on your brakes repeatedly'],ans:2,exp:'Do not retaliate. Allow the aggressive driver to pass when it is safe. Avoid escalating the situation.'},
{id:578,cat:'hazards',q:'Another driver makes a rude gesture at you. What should you do?',opts:['Make a gesture back','Ignore it and continue driving calmly','Follow them to confront them','Report them immediately by phone while driving'],ans:1,exp:'Do not react to provocation from other drivers. Stay calm, avoid eye contact and do not retaliate. This prevents road rage escalating.'},
{id:579,cat:'hazards',q:'How can you reduce the risk of road rage incidents?',opts:['Always drive as fast as possible','Use your horn frequently to warn others','Allow plenty of time for your journey so you do not feel rushed','Tailgate slow drivers to encourage them to move'],ans:2,exp:'Planning your journey and allowing extra time reduces stress and the temptation to drive aggressively.'},
{id:580,cat:'hazards',q:'Why are electric and hybrid vehicles a particular hazard to pedestrians at low speeds?',opts:['They produce toxic fumes','They are much wider than normal cars','They are almost silent, making them hard for pedestrians to hear','They cannot stop as quickly'],ans:2,exp:'Electric and hybrid vehicles are very quiet at low speeds, so pedestrians, especially those with visual impairments, may not hear them approaching.'},
{id:581,cat:'hazards',q:'What is the purpose of an Acoustic Vehicle Alerting System (AVAS) fitted to electric vehicles?',opts:['To play music through external speakers','To emit a sound at low speeds so pedestrians can hear the vehicle approaching','To alert the driver to low battery','To warn of speed cameras'],ans:1,exp:'AVAS produces an artificial sound at speeds below 20 km/h to alert pedestrians to the presence of a quiet electric vehicle.'},
{id:582,cat:'hazards',q:'What does an autonomous emergency braking (AEB) system do?',opts:['It replaces the need for the driver to brake','It automatically applies the brakes if it detects an imminent collision and the driver has not responded','It only works at motorway speeds','It steers the vehicle away from danger'],ans:1,exp:'AEB detects potential collisions and applies the brakes automatically if the driver does not respond. It assists the driver but does not replace their responsibility.'},
{id:583,cat:'hazards',q:'Should you rely solely on autonomous emergency braking to avoid collisions?',opts:['Yes, it will always prevent a collision','No, it is a driver aid and may not work in all situations','Yes, as long as the vehicle is serviced regularly','No, because it is not legal in the UK'],ans:1,exp:'AEB is a driver assistance system. It may not detect all hazards and should not replace attentive driving and proper observation.'},
{id:584,cat:'hazards',q:'What does a lane departure warning system alert you to?',opts:['Vehicles in your blind spot','Your vehicle drifting out of its lane without signalling','Speed cameras ahead','Low tyre pressure'],ans:1,exp:'Lane departure warning systems alert you if your vehicle begins to drift out of its lane without the indicator being used, which may indicate driver fatigue or distraction.'},
{id:585,cat:'hazards',q:'Why can cruise control be dangerous on wet roads?',opts:['It makes the engine use more fuel','It may cause the vehicle to accelerate through standing water, increasing the risk of aquaplaning','It turns off the headlights','It disables the brakes'],ans:1,exp:'Cruise control maintains a set speed and may try to accelerate on wet surfaces, increasing the risk of aquaplaning. Switch it off in wet conditions.'},
{id:586,cat:'hazards',q:'When should you avoid using cruise control?',opts:['On motorways','On dry straight roads','In heavy rain, on icy roads or in heavy traffic','Only at night'],ans:2,exp:'Cruise control should not be used in adverse weather conditions or heavy traffic where you need to frequently adjust your speed.'},
{id:587,cat:'hazards',q:'What effect can driving on long, straight roads have on a driver?',opts:['It improves concentration','It can cause drowsiness and a loss of concentration due to monotony','It makes drivers more alert','It reduces fuel consumption'],ans:1,exp:'Long, straight, monotonous roads can make drivers drowsy and less alert. Take regular breaks and stay vigilant.'},
{id:588,cat:'hazards',q:'You are feeling drowsy while driving on a motorway. What should you do?',opts:['Open the window and turn up the radio','Stop at the next service area and rest','Increase your speed to reach your destination faster','Drink an energy drink while continuing to drive'],ans:1,exp:'If you feel drowsy, the only safe action is to stop at the next service area and rest. Fresh air and loud music are not effective long-term solutions.'},
{id:589,cat:'hazards',q:'How often should you take a break on a long journey to reduce fatigue?',opts:['Every four hours','At least every two hours','Only when you feel tired','Every thirty minutes'],ans:1,exp:'The Highway Code recommends taking a break of at least 15 minutes every two hours on a long journey.'},
{id:590,cat:'hazards',q:'What should you do before entering a tunnel?',opts:['Remove your sunglasses, switch on your dipped headlights and tune to the tunnel\'s radio frequency if displayed','Speed up to get through quickly','Switch off your headlights','Close all windows and turn off ventilation'],ans:0,exp:'Before entering a tunnel, remove sunglasses, switch on dipped headlights, and tune into the radio frequency shown on signs for safety information.'},
{id:591,cat:'hazards',q:'What should you do if traffic comes to a stop in a tunnel?',opts:['Turn around and drive out','Switch off your engine if the delay is long, keep sidelights on, and follow tunnel signals','Leave your engine running and sound your horn','Abandon your vehicle immediately'],ans:1,exp:'If traffic stops in a tunnel, switch off your engine to prevent fumes building up. Keep sidelights on so others can see you.'},
{id:592,cat:'hazards',q:'What particular hazard should you be aware of when driving over a high bridge?',opts:['Speed cameras','Strong crosswinds that could blow your vehicle off course','Low-flying aircraft','Flooding'],ans:1,exp:'Exposed bridges are vulnerable to strong crosswinds, which can cause your vehicle to veer off course, especially high-sided vehicles.'},
{id:593,cat:'hazards',q:'Why might a bridge surface be more hazardous than a normal road in winter?',opts:['Bridges are always narrower','Bridge surfaces freeze before normal roads because cold air circulates above and below them','Bridges have steeper gradients','There are more potholes on bridges'],ans:1,exp:'Bridge decks are exposed to cold air on all sides, so they freeze before other road surfaces. Watch for ice warnings on bridges.'},
{id:594,cat:'hazards',q:'What should you be aware of when driving in a multi-storey car park?',opts:['There are no speed limits in car parks','Pedestrians, tight bends, low headroom and vehicles reversing out of spaces','You do not need to use lights','Other vehicles always give way to you'],ans:1,exp:'Multi-storey car parks present multiple hazards including pedestrians, sharp turns, height restrictions and vehicles manoeuvring.'},
{id:595,cat:'hazards',q:'You are driving down a steep ramp in a multi-storey car park. What should you do?',opts:['Coast in neutral to save fuel','Use a low gear and drive slowly, being ready for oncoming vehicles on the ramp','Sound your horn continuously','Drive at normal road speed'],ans:1,exp:'Use a low gear for engine braking on steep ramps and drive slowly as you may meet vehicles coming up on a shared ramp.'},
{id:596,cat:'hazards',q:'What hazard do overhanging trees and hedgerows present on country roads?',opts:['They improve the view of the road','They can restrict your view, hide signs and drop debris on the road','They have no effect on driving','They always indicate a junction ahead'],ans:1,exp:'Overhanging vegetation can obscure your view of the road ahead, hide signs and junctions, and drop leaves or branches onto the road.'},
{id:597,cat:'hazards',q:'You are driving on a dual carriageway and traffic ahead suddenly slows. What should you do?',opts:['Move to the hard shoulder to pass the traffic','Use your hazard warning lights briefly to warn traffic behind you, then brake progressively','Maintain your speed and change lanes','Brake harshly without warning'],ans:1,exp:'Briefly using hazard warning lights alerts following traffic to the sudden change in speed ahead, helping prevent rear-end collisions.'},
{id:598,cat:'hazards',q:'Why should you take extra care when driving past a school at the start and end of the school day?',opts:['Speed limits are always 10 mph near schools','Children may run into the road unexpectedly and there will be more pedestrians','The road surface is different near schools','Parking is not allowed near schools at any time'],ans:1,exp:'Children are unpredictable and may run into the road without looking, especially when excited at the start or end of the school day.'},
{id:599,cat:'hazards',q:'What should you do if you experience a tyre blowout while driving on a dual carriageway?',opts:['Brake as hard as possible','Hold the steering wheel firmly, take your foot off the accelerator and pull up gradually on the left','Accelerate to maintain control','Immediately turn onto the hard shoulder'],ans:1,exp:'In a blowout, grip the steering firmly, do not brake harshly, ease off the accelerator and pull over gradually when safe.'},
{id:600,cat:'hazards',q:'You notice that a vehicle behind you is being driven aggressively. What is the best course of action?',opts:['Slow down to annoy the driver','Let them overtake you and do not engage with their behaviour','Match their aggression to show confidence','Brake-check them to make them back off'],ans:1,exp:'Never engage with aggressive drivers. Let them pass safely and avoid any actions that could escalate the situation. If concerned, drive to a safe public place.'},
{id:601,cat:'vulnerable',q:'What is a \'shared space\' street designed to do?',opts:['Separate vehicles and pedestrians completely','Remove most signs and markings so all users share the road equally','Give vehicles priority over pedestrians','Allow parking on both sides of the road'],ans:1,exp:'Shared space streets remove traditional kerbs, signs and road markings to encourage drivers, cyclists and pedestrians to share the area with greater awareness of each other.'},
{id:602,cat:'vulnerable',q:'What is the speed limit in a home zone?',opts:['30 mph','20 mph','15 mph','There is no set speed limit but you should drive at walking pace'],ans:3,exp:'Home zones do not have a fixed speed limit, but drivers are expected to travel at walking pace because the space is shared with pedestrians, especially children playing.'},
{id:603,cat:'vulnerable',q:'You see a road sign showing children playing. What type of area are you entering?',opts:['A school zone','A play street or home zone','A one-way street','A pedestrianised shopping area'],ans:1,exp:'A sign showing children at play warns you that you are entering a play street or home zone where children may be playing in the road.'},
{id:604,cat:'vulnerable',q:'You encounter a Class 3 mobility scooter being used on the road. How should you treat its user?',opts:['As a cyclist','As a slow-moving vehicle','As a pedestrian who may be vulnerable','As a motorcyclist'],ans:2,exp:'Mobility scooter users are classified as vulnerable road users. Be patient, give them plenty of room and be aware they may travel slowly.'},
{id:605,cat:'vulnerable',q:'Why might a mobility scooter user be particularly vulnerable at junctions?',opts:['They always have right of way','They sit low and may be harder for drivers to see','They cannot stop quickly','They must travel in the cycle lane'],ans:1,exp:'Mobility scooter users sit lower than most road users, making them harder to spot at junctions. Always look carefully before emerging.'},
{id:606,cat:'vulnerable',q:'How might a hearing aid user be affected in traffic?',opts:['They can always hear traffic clearly with their hearing aid','Background traffic noise may make it difficult for them to judge vehicle direction and speed','They are not allowed to cross roads without assistance','Hearing aids improve directional hearing in all situations'],ans:1,exp:'Hearing aids amplify all sounds, and background traffic noise can make it difficult for users to determine which direction a vehicle is coming from.'},
{id:607,cat:'vulnerable',q:'You notice a pedestrian who appears confused at a busy junction. What should you consider?',opts:['They are deliberately blocking traffic','They may have a learning difficulty and need extra time','Sound your horn to help them focus','Flash your lights to guide them across'],ans:1,exp:'Some pedestrians have learning difficulties that affect their ability to judge traffic speed and distance. Be patient and allow them extra time.'},
{id:608,cat:'vulnerable',q:'What is the purpose of a pedestrian refuge island in the centre of a road?',opts:['To park motorcycles','To allow pedestrians to cross the road in two stages','To slow down traffic with a chicane effect','To provide a turning point for vehicles'],ans:1,exp:'Pedestrian refuge islands let pedestrians cross wide roads in two stages, giving them a safe place to wait in the middle before completing the crossing.'},
{id:609,cat:'vulnerable',q:'When approaching a central island pedestrian refuge, what should you be aware of?',opts:['Pedestrians may step out from behind the island into your lane','Vehicles must stop at the island at all times','The island gives you priority over pedestrians','You must always change lane to avoid the island'],ans:0,exp:'Pedestrians may be waiting on the island and could step into your lane. Slow down and be ready to give way.'},
{id:610,cat:'vulnerable',q:'What is a staggered pedestrian crossing?',opts:['A crossing that alternates between red and green rapidly','Two separate crossings on either side of a central island, treated as individual crossings','A crossing where pedestrians walk diagonally','A crossing used only by disabled people'],ans:1,exp:'A staggered crossing has two separate parts divided by a central island. Each half is a separate crossing, and traffic lights operate independently for each side.'},
{id:611,cat:'vulnerable',q:'At a staggered puffin crossing, when may you proceed on the left-hand crossing?',opts:['Only when both sides show green','When your side shows green, even if the other side is red','When no pedestrians are visible anywhere','When the pedestrian countdown timer reaches zero'],ans:1,exp:'Each half of a staggered crossing operates independently. You may proceed when your side shows green, regardless of the other side.'},
{id:612,cat:'vulnerable',q:'What is a parallel crossing?',opts:['Two zebra crossings side by side','A crossing that combines a zebra crossing for pedestrians with a separate crossing for cyclists','A crossing only used on dual carriageways','A crossing where traffic flows in both directions simultaneously'],ans:1,exp:'A parallel crossing has a traditional zebra for pedestrians alongside a separate, marked cycle crossing, allowing both to cross at the same time.'},
{id:613,cat:'vulnerable',q:'At a parallel crossing, who has priority?',opts:['Only pedestrians on the zebra section','Only cyclists on the cycle section','Both pedestrians on the zebra section and cyclists on the cycle section','Neither — traffic lights control priority'],ans:2,exp:'At a parallel crossing, both pedestrians on the zebra section and cyclists on the cycle crossing have priority over motor vehicles, similar to a standard zebra crossing.'},
{id:614,cat:'vulnerable',q:'What distinguishes a Pegasus crossing from other signal-controlled crossings?',opts:['It is wider than normal crossings','It includes a high-level push button for horse riders','It has flashing blue lights','It is only found on motorway slip roads'],ans:1,exp:'Pegasus (equestrian) crossings have a higher-mounted push button so horse riders can activate the signals without dismounting.'},
{id:615,cat:'vulnerable',q:'You approach a Pegasus crossing and see a horse rider waiting. What should you do?',opts:['Sound your horn to alert the rider','Stop when the red light shows and allow the rider and horse to cross','Flash your headlights to signal them across','Overtake before the crossing activates'],ans:1,exp:'Treat a Pegasus crossing like any other signal-controlled crossing. Stop on red and wait patiently, as horses may take longer to cross.'},
{id:616,cat:'vulnerable',q:'Why should you give cyclists extra room when approaching a roundabout?',opts:['Cyclists always have priority on roundabouts','Cyclists may need to change lanes and can be unstable','Cyclists are not allowed on roundabouts','Cyclists must always use the outside lane'],ans:1,exp:'Cyclists on roundabouts may need to change position to take their exit, and they can be less stable than motor vehicles. Give them plenty of space.'},
{id:617,cat:'vulnerable',q:'A cyclist is in the left-hand lane of a roundabout but signals right. Why might this happen?',opts:['The cyclist is confused','The cyclist may be using the left lane to turn right because they feel safer there, as permitted by the Highway Code','The cyclist is breaking the law','The cyclist intends to stop'],ans:1,exp:'The Highway Code acknowledges that cyclists may stay in the left lane on roundabouts even when turning right, as they may feel safer. Be aware and give them room.'},
{id:618,cat:'vulnerable',q:'What is an advanced stop line (ASL) at a traffic-light junction?',opts:['A line where advanced drivers must stop','A marked area ahead of the main vehicle stop line reserved for cyclists','A line only for buses','A painted box for motorcycles only'],ans:1,exp:'An advanced stop line creates a cycle box between two stop lines, giving cyclists a safe space to wait ahead of motor traffic at red lights.'},
{id:619,cat:'vulnerable',q:'When are you allowed to enter a cycle box (advanced stop line area) at a junction?',opts:['At any time if no cyclists are present','Only when your traffic light is green and the box is clear','Never under any circumstances','Only when turning left'],ans:1,exp:'You must not enter the cycle box when the traffic light is red. If the light is green and the box is clear, you may proceed through it.'},
{id:620,cat:'vulnerable',q:'What does a contraflow cycle lane mean?',opts:['Cyclists travel in both directions on the same side of the road','Cyclists ride in the opposite direction to motor traffic on a one-way street','Cyclists must give way to all traffic','Cyclists share the lane with buses only'],ans:1,exp:'A contraflow cycle lane allows cyclists to ride in the opposite direction to the one-way traffic flow on a one-way street. Watch for cyclists coming towards you.'},
{id:621,cat:'vulnerable',q:'A cyclist ahead of you extends their right arm straight out. What does this signal mean?',opts:['They are waving you past','They intend to turn right','They are slowing down','They are pointing out a hazard'],ans:1,exp:'A cyclist extending their right arm straight out is signalling their intention to turn right. Slow down and give them time and space to make the turn.'},
{id:622,cat:'vulnerable',q:'A cyclist ahead repeatedly moves their right arm up and down. What are they signalling?',opts:['They want you to overtake','They intend to turn right','They are slowing down or stopping','They are greeting another road user'],ans:2,exp:'A cyclist moving their arm up and down is signalling that they are slowing down or preparing to stop. Be ready to reduce your speed.'},
{id:623,cat:'vulnerable',q:'What is a cargo bike and why does it need extra consideration?',opts:['A motorbike carrying goods that travels at normal speed','A bicycle designed to carry heavy loads or passengers, which is longer and wider than a standard cycle','A delivery van under 3.5 tonnes','A bicycle with a trailer that must use bus lanes'],ans:1,exp:'Cargo bikes are longer and wider than standard bicycles, making them slower to accelerate and less manoeuvrable. Give them extra time and space.'},
{id:624,cat:'vulnerable',q:'Where are rental e-scooters legally allowed to be used in the UK?',opts:['On any road and pavement','Only on roads and cycle lanes as part of authorised local trial schemes','Anywhere a bicycle can go','Only on private land'],ans:1,exp:'Rental e-scooters may be used on roads and cycle lanes only where an authorised government trial scheme operates. Privately owned e-scooters remain illegal on public roads and pavements.'},
{id:625,cat:'vulnerable',q:'Why should you take particular care around e-scooter riders?',opts:['They always travel above the speed limit','They have small wheels making them vulnerable to road imperfections, and they may be less experienced','They have no brakes','They are not required to follow traffic laws'],ans:1,exp:'E-scooter riders have small wheels that are sensitive to potholes and uneven surfaces. Riders may also be less experienced in traffic. Give them extra space.'},
{id:626,cat:'vulnerable',q:'You see children riding scooters on the pavement near a junction. What should you do?',opts:['Maintain your speed as they are on the pavement','Slow down because they could move into the road without warning','Sound your horn to warn them','Flash your headlights at them'],ans:1,exp:'Children on scooters are unpredictable and may ride off the pavement into the road without looking, especially near junctions and driveways.'},
{id:627,cat:'vulnerable',q:'What does a flashing amber warning light on a school bus mean?',opts:['The bus is about to move off','Children are getting on or off the bus — slow down and be prepared to stop','The bus has broken down','The bus is turning right'],ans:1,exp:'Flashing amber lights on a school bus warn that children are boarding or alighting. Slow down and watch for children who may cross the road.'},
{id:628,cat:'vulnerable',q:'You see a circular sign showing two children with a red border. What does this mean?',opts:['Children must be accompanied by an adult','No children allowed','School crossing patrol ahead — be ready to stop','Play street ahead — expect children on the road'],ans:2,exp:'This sign warns of a school crossing patrol ahead. Be prepared to slow down and stop when the patrol displays the stop sign.'},
{id:629,cat:'vulnerable',q:'What is the purpose of metal pedestrian barriers (guard rails) near schools?',opts:['To prevent vehicles from parking on the pavement','To guide children to safe crossing points and prevent them running into the road','To narrow the road for traffic calming','To separate cycle lanes from the pavement'],ans:1,exp:'Pedestrian barriers near schools channel children towards designated crossing points, reducing the risk of them running straight into the road.'},
{id:630,cat:'vulnerable',q:'What does tactile paving at a pedestrian crossing indicate?',opts:['The crossing is out of order','It warns visually impaired pedestrians of the crossing location through texture underfoot','The surface is being repaired','Cyclists must dismount here'],ans:1,exp:'Tactile paving uses raised bumps or ridged surfaces to alert visually impaired people to crossing points and hazards through the sensation underfoot.'},
{id:631,cat:'vulnerable',q:'What is the purpose of a dropped kerb at a pedestrian crossing?',opts:['To allow rainwater drainage','To make it easier for wheelchair users, pushchair users and people with mobility difficulties to cross','To mark a parking bay entrance','To indicate a bus stop area'],ans:1,exp:'Dropped kerbs provide level access between the pavement and road, helping wheelchair users, those with pushchairs and people with limited mobility to cross safely.'},
{id:632,cat:'vulnerable',q:'You are driving on an unlit rural road at night and see pedestrians walking ahead. What should you expect?',opts:['They will always be wearing high-visibility clothing','They should be walking on the right-hand side of the road facing oncoming traffic','They will be walking on the pavement','They will have a torch pointing at your vehicle'],ans:1,exp:'The Highway Code advises pedestrians on roads without pavements to walk on the right-hand side facing oncoming traffic, so they can see vehicles approaching.'},
{id:633,cat:'vulnerable',q:'You come across a large group of pedestrians walking on a narrow country road. What should you do?',opts:['Drive through them slowly using your horn','Slow right down and be prepared to stop, passing only when it is completely safe','Mount the verge to get past quickly','Flash your headlights until they move aside'],ans:1,exp:'Large groups of walkers on narrow roads may not all be able to move aside quickly. Slow down and wait until you can pass safely with plenty of room.'},
{id:634,cat:'vulnerable',q:'You meet a funeral procession while driving. How should you behave?',opts:['Overtake the procession as soon as possible','Show respect and patience — do not rev your engine, sound your horn or attempt to overtake','Sound your horn once as a sign of respect','Flash your headlights to acknowledge them'],ans:1,exp:'Funeral processions move slowly and should be treated with respect. Do not overtake, rev your engine or sound your horn.'},
{id:635,cat:'vulnerable',q:'You encounter runners taking part in an organised road race. What should you do?',opts:['Drive through gaps between the runners','Follow police or marshal directions and be prepared to wait or find an alternative route','Sound your horn to clear the road','Ignore any marshals and use your usual route'],ans:1,exp:'Organised road events such as charity runs may have police or marshals controlling traffic. Always follow their directions and be patient.'},
{id:636,cat:'vulnerable',q:'You approach a section of road used by a charity walk. Marshals are waving you to slow down. What must you do?',opts:['Ignore them as they have no legal authority','Comply with their signals as they are managing participants\' safety on the road','Speed up to get through quickly','Use the opposite carriageway without checking'],ans:1,exp:'Although marshals may not have the same legal authority as police, you should comply with their signals for everyone\'s safety and follow alternative route signs.'},
{id:637,cat:'vulnerable',q:'Why should you be especially careful when meeting farm vehicles and workers on a country road?',opts:['Farm vehicles always have right of way','Farm workers may be on foot alongside slow-moving machinery and mud on the road can reduce grip','Farm vehicles are exempt from lighting regulations','Farm workers wear high-visibility clothing at all times'],ans:1,exp:'Farm vehicles are slow and wide, and workers on foot may be walking beside machinery. Mud deposited on the road can make the surface slippery.'},
{id:638,cat:'vulnerable',q:'What colour is the tactile paving used at controlled pedestrian crossings?',opts:['Red','Yellow','Grey','Blue'],ans:0,exp:'Red tactile paving (blister surface) is used at controlled crossing points such as pelican, puffin and toucan crossings to alert visually impaired pedestrians.'},
{id:639,cat:'vulnerable',q:'You see a lollipop person (school crossing patrol) step into the road holding up their stop sign. What must you do?',opts:['Slow down and prepare to stop only if children are crossing','Stop and wait until the patrol and all pedestrians have cleared the road and the sign is lowered','Drive around them if the other side of the road is clear','Sound your horn to warn the children'],ans:1,exp:'It is a legal requirement to stop when a school crossing patrol displays the stop sign. Wait until the sign is lowered and the road is clear before proceeding.'},
{id:640,cat:'vulnerable',q:'You notice buff (beige) coloured tactile paving at the edge of a railway platform. What does this colour of tactile paving indicate at a roadside location?',opts:['A bus stop area','A shared-use route for pedestrians and cyclists, warning of a change in surface','A loading bay for goods vehicles','A fire exit route'],ans:1,exp:'Buff (beige) tactile paving is used at shared pedestrian and cycle routes and other locations to warn visually impaired people of a transition between areas.'},
{id:641,cat:'motorway',q:'How far apart are motorway service areas typically located?',opts:['Every 10 miles','Approximately every 28 miles','Every 50 miles','Every 5 miles'],ans:1,exp:'The government recommends motorway services are no more than 28 miles apart.'},
{id:642,cat:'motorway',q:'What colour are emergency telephones on motorways?',opts:['Red','Green','Blue','Orange'],ans:3,exp:'Motorway emergency telephones are orange and connect directly to Highways England control centres.'},
{id:643,cat:'motorway',q:'On a smart motorway, where are emergency SOS phones located?',opts:['Only on bridges','In emergency refuge areas','At every junction','On central reservations only'],ans:1,exp:'On smart motorways, SOS phones are located in emergency refuge areas (ERAs) spaced at regular intervals.'},
{id:644,cat:'motorway',q:'What does a matrix sign displaying a red X above a lane mean?',opts:['Lane available for use','Lane closed - do not use this lane','Reduce speed in this lane','Hard shoulder available'],ans:1,exp:'A red X means the lane is closed. It is illegal to drive in a lane with a red X displayed above it.'},
{id:645,cat:'motorway',q:'When a mandatory speed limit is shown on a motorway gantry sign, what surrounds the speed figure?',opts:['A blue circle','A red circle','A green triangle','A white square'],ans:1,exp:'Mandatory speed limits on motorway gantry signs are displayed within a red circle, just like standard speed limit signs.'},
{id:646,cat:'motorway',q:'How can you identify an advisory speed signal on a motorway?',opts:['It is shown in a red circle','It is shown without a red circle','It flashes amber','It is displayed on a blue background'],ans:1,exp:'Advisory speed signals are shown without a red circle. They recommend a safe speed but are not legally enforceable.'},
{id:647,cat:'motorway',q:'How are motorway exits typically numbered?',opts:['Alphabetically','Sequentially by junction number','By distance from London','By region'],ans:1,exp:'Motorway exits are numbered by junction number, running sequentially along the route of the motorway.'},
{id:648,cat:'motorway',q:'What is a contraflow system on a motorway?',opts:['A one-way traffic system','Traffic flowing in both directions on one carriageway','Traffic diverted onto a slip road','A system for emergency vehicles only'],ans:1,exp:'In a contraflow, traffic from both carriageways uses one side of the motorway, often during roadworks.'},
{id:649,cat:'motorway',q:'During a motorway widening scheme, what should you expect?',opts:['Normal speed limits throughout','Narrower lanes, lower speed limits and no hard shoulder','Wider lanes than usual','No speed restrictions'],ans:1,exp:'Motorway widening often involves narrow lanes, reduced speed limits and temporary removal of the hard shoulder.'},
{id:650,cat:'motorway',q:'What is the most common temporary speed limit through motorway roadworks?',opts:['40 mph','50 mph','60 mph','30 mph'],ans:1,exp:'50 mph is the most common speed limit through motorway roadworks in the UK.'},
{id:651,cat:'motorway',q:'How do average speed cameras work in motorway roadworks?',opts:['They measure your speed at one point','They calculate your average speed between two or more camera points','They only work at night','They only detect speeds above 80 mph'],ans:1,exp:'Average speed cameras record your time at multiple points and calculate your average speed over the distance.'},
{id:652,cat:'motorway',q:'What does an overhead gantry sign showing an amber flashing signal mean?',opts:['Lane ahead closed','Danger ahead - adjust your speed','Move to the hard shoulder','Motorway ends ahead'],ans:1,exp:'Amber flashing signals warn of a hazard ahead. You should adjust your speed and be prepared for queuing traffic.'},
{id:653,cat:'motorway',q:'When a lane closure is indicated by signs on a motorway, what should you do?',opts:['Stay in the closing lane as long as possible at speed','Move into the open lane in good time','Stop immediately','Reverse to the previous junction'],ans:1,exp:'You should move into the open lane in good time, following the signs and merging safely.'},
{id:654,cat:'motorway',q:'What does an incident support unit do on a motorway?',opts:['Repairs your vehicle','Helps manage the scene and traffic at incidents','Provides fuel','Tows vehicles to service stations'],ans:1,exp:'Incident support units help manage traffic and the scene at motorway incidents, working with emergency services.'},
{id:655,cat:'motorway',q:'What is stopped vehicle detection (SVD) on smart motorways?',opts:['CCTV cameras operated by police','Radar technology that detects stationary vehicles in live lanes','Sensors embedded in the road surface only','A mobile phone app for drivers'],ans:1,exp:'SVD uses radar to automatically detect stopped vehicles in live lanes and alert the control centre to set signals.'},
{id:656,cat:'motorway',q:'What should you do if fog reduces visibility on a motorway?',opts:['Use full beam headlights','Slow down and use dipped headlights and fog lights if visibility is below 100 metres','Maintain speed and stay in the outside lane','Pull onto the hard shoulder and wait'],ans:1,exp:'Use dipped headlights and rear fog lights if visibility drops below 100 metres. Reduce speed and increase following distance.'},
{id:657,cat:'motorway',q:'What is aquaplaning and when is it most likely on a motorway?',opts:['Skidding on ice at low speed','Tyres losing contact with the road due to water build-up at speed','Sliding on oil','Braking too hard on dry roads'],ans:1,exp:'Aquaplaning occurs when water builds up between the tyres and road surface, causing loss of grip. It is most likely at higher motorway speeds in heavy rain.'},
{id:658,cat:'motorway',q:'Why are motorways particularly dangerous in high winds?',opts:['There are no barriers','High-sided vehicles and motorcycles can be blown off course, and bridges and exposed sections increase risk','Speed limits are removed','Other drivers always speed up'],ans:1,exp:'Motorways often have exposed sections and bridges where crosswinds are stronger, affecting high-sided vehicles, motorcycles and cars towing trailers.'},
{id:659,cat:'motorway',q:'When driving on a motorway at night, which lights should you normally use?',opts:['Sidelights only','Dipped headlights','Full beam headlights at all times','Fog lights'],ans:1,exp:'Use dipped headlights on a lit motorway. On unlit sections you may use full beam if no vehicle is ahead or approaching.'},
{id:660,cat:'motorway',q:'What is the recommended action if you feel tired while driving on a motorway?',opts:['Open the window and carry on','Leave at the next exit or services and take a break of at least 15 minutes','Stop on the hard shoulder for a nap','Increase your speed to reach your destination faster'],ans:1,exp:'If you feel drowsy, leave the motorway at the next exit or service area. A break of at least 15 minutes with a caffeinated drink is recommended.'},
{id:661,cat:'motorway',q:'Why should you avoid driving in a convoy of heavy vehicles on a motorway?',opts:['It is illegal','It reduces your visibility and ability to anticipate hazards ahead','It saves fuel','Convoys have right of way'],ans:1,exp:'Driving in a convoy of large vehicles limits your view of the road ahead and reduces your ability to react to hazards.'},
{id:662,cat:'motorway',q:'On which motorways in England and Wales are lorries restricted from overtaking during certain hours?',opts:['All motorways at all times','Some motorways have experimental restrictions but there is no nationwide ban','Only the M25','Only in Scotland'],ans:1,exp:'There is no nationwide ban on lorry overtaking on motorways in England and Wales, though some sections have restrictions.'},
{id:663,cat:'motorway',q:'Which major motorway in the UK operates as a toll road?',opts:['M1','M6 Toll','M25','M4'],ans:1,exp:'The M6 Toll in the West Midlands is the UK\'s first toll motorway, providing an alternative route around Birmingham.'},
{id:664,cat:'motorway',q:'How is the Dartford Crossing toll paid?',opts:['At a toll booth on arrival','In advance or by midnight the day after crossing via the Dart Charge scheme','By post within 7 days','It is free for all vehicles'],ans:1,exp:'The Dart Charge must be paid online, by phone or at retail outlets, in advance or by midnight the day after crossing.'},
{id:665,cat:'motorway',q:'What precaution should you take when stopping at a motorway service area?',opts:['Leave valuables on display','Lock your vehicle and take valuables with you','Leave the engine running','Park away from other vehicles only'],ans:1,exp:'Always lock your vehicle and take valuables with you to reduce the risk of theft at service areas.'},
{id:666,cat:'motorway',q:'If you break down on a motorway with passengers, where should they wait?',opts:['Inside the vehicle with seatbelts on','On the embankment or verge, away from the carriageway and hard shoulder','In the outside lane','Standing behind the vehicle'],ans:1,exp:'Passengers should leave the vehicle from the side away from traffic and wait on the embankment or verge, well away from the hard shoulder.'},
{id:667,cat:'motorway',q:'What should you do with a pet if you break down on a motorway?',opts:['Leave it in the vehicle','Let it roam free on the verge','Keep it under control on the verge, away from the carriageway, unless it is unsafe to do so','Tie it to the vehicle'],ans:2,exp:'Keep pets under control on the verge away from traffic. Only leave them in the vehicle if it is unsafe to remove them.'},
{id:668,cat:'motorway',q:'What should you do before driving on a motorway in snowy conditions?',opts:['Only clear the windscreen','Ensure all windows, mirrors, lights and roof are clear of snow and ice','Drive slowly in the outside lane','Use only sidelights'],ans:1,exp:'Clear all snow and ice from windows, mirrors, lights and the roof before setting off. Snow from the roof can slide and obscure your view or endanger other drivers.'},
{id:669,cat:'motorway',q:'What is the minimum safe following distance in wet conditions on a motorway?',opts:['One car length','Two-second gap','At least four seconds from the vehicle ahead','The same as in dry conditions'],ans:2,exp:'In wet conditions you should at least double the normal two-second gap, giving at least a four-second following distance.'},
{id:670,cat:'motorway',q:'If an amber warning light appears on a smart motorway overhead sign showing 40, what must you do?',opts:['It is only advisory so you can ignore it','You must not exceed 40 mph as it is a mandatory speed limit','Slow down to 30 mph','Move to the hard shoulder'],ans:1,exp:'Speed limits shown in red circles on smart motorway gantries are mandatory and legally enforceable.'},
{id:671,cat:'documents',q:'What is a Driver Certificate of Professional Competence (CPC)?',opts:['A certificate for car drivers','A qualification required to drive lorries or buses professionally','A vehicle inspection certificate','An MOT alternative'],ans:1,exp:'Driver CPC is a mandatory qualification for professional lorry and bus drivers, requiring 35 hours of periodic training every five years.'},
{id:672,cat:'documents',q:'How often must a professional LGV or PCV driver complete periodic CPC training?',opts:['Every year','Every 35 hours over five years','Every 10 years','Only once'],ans:1,exp:'Drivers must complete 35 hours of periodic training every five years to maintain their Driver CPC qualification.'},
{id:673,cat:'documents',q:'What does a tachograph record?',opts:['Fuel consumption only','Driving time, breaks and rest periods','Vehicle emissions','Route taken'],ans:1,exp:'Tachographs record driving time, other work, breaks and rest periods to ensure drivers comply with hours rules.'},
{id:674,cat:'documents',q:'What is an operator\'s licence (O-licence)?',opts:['A licence to operate a taxi','A licence required to operate goods vehicles over 3.5 tonnes or passenger vehicles with more than 9 seats','A driving licence for motorways','A parking permit'],ans:1,exp:'An O-licence is required by anyone using goods vehicles over 3.5 tonnes or PSVs with more than 9 seats for hire or reward.'},
{id:675,cat:'documents',q:'What categories of driving licence cover HGV and PSV vehicles?',opts:['Category A and B','Category C (goods) and D (passenger) with variants','Category F and G','Category K only'],ans:1,exp:'Category C covers large goods vehicles and category D covers passenger-carrying vehicles, with sub-categories for different sizes.'},
{id:676,cat:'documents',q:'When might you need an International Driving Permit (IDP)?',opts:['To drive in Scotland','To drive in certain countries outside the UK','To drive on UK motorways','To hire a car in the UK'],ans:1,exp:'An IDP may be required to drive legally in some countries outside the UK. The type needed depends on the destination country.'},
{id:677,cat:'documents',q:'What was a green card in the context of motor insurance?',opts:['A vehicle registration document','Proof of minimum motor insurance cover valid in other countries','A breakdown cover certificate','A vehicle tax disc'],ans:1,exp:'A green card is an international certificate of motor insurance proving you have at least minimum compulsory cover abroad.'},
{id:678,cat:'documents',q:'What is a European Accident Statement?',opts:['A police report form','A standardised form for recording details of a road traffic incident agreed by both parties','A court summons','An insurance claim form'],ans:1,exp:'A European Accident Statement is a standard form both parties can complete at the scene to record facts of a collision.'},
{id:679,cat:'documents',q:'What is the Motor Insurance Database (MID)?',opts:['A list of car dealers','A central record of all insured vehicles in the UK','A database of MOT results','A register of driving licences'],ans:1,exp:'The MID is maintained by the Motor Insurers\' Bureau and holds records of every insured vehicle in the UK. Police use it to identify uninsured vehicles.'},
{id:680,cat:'documents',q:'What happens when you receive a Notice of Intended Prosecution (NIP)?',opts:['You are immediately disqualified','You must respond within 28 days identifying the driver at the time of the alleged offence','You must pay a fine within 7 days','Your vehicle is seized'],ans:1,exp:'A NIP must be served within 14 days of the offence. The registered keeper must identify the driver within 28 days.'},
{id:681,cat:'documents',q:'Who is eligible to attend a speed awareness course instead of receiving points?',opts:['Anyone regardless of speed','Drivers caught within a specific speed range above the limit who have not attended a course recently','Only new drivers','Only drivers over 25'],ans:1,exp:'Eligibility depends on the speed recorded, typically within a set range above the limit, and you must not have attended a course for the same offence type recently.'},
{id:682,cat:'documents',q:'What is a drink-drive rehabilitation course?',opts:['A course to avoid prosecution','A course that can reduce a driving ban period if completed by offenders convicted of drink-driving','A course for recovering alcoholics only','A mandatory part of every driving licence renewal'],ans:1,exp:'A court may offer a drink-drive rehabilitation course which, if completed, can reduce the disqualification period by up to 25%.'},
{id:683,cat:'documents',q:'After disqualification for certain offences, what type of driving test may you be required to pass?',opts:['A theory test only','An extended driving test','A standard practical test','A motorcycle test'],ans:1,exp:'Courts can order an extended driving test after disqualification for dangerous driving or other serious offences. It lasts about 70 minutes.'},
{id:684,cat:'documents',q:'Which medical conditions must you notify the DVLA about?',opts:['Only conditions requiring hospital visits','Any condition that could affect your ability to drive safely, such as epilepsy, diabetes or heart conditions','Only conditions diagnosed after age 70','Only mental health conditions'],ans:1,exp:'You must tell the DVLA about any medical condition or disability that could affect your driving. Failure to do so is a criminal offence.'},
{id:685,cat:'documents',q:'What is the minimum eyesight requirement for driving in the UK?',opts:['Reading a number plate at 10 metres','Reading a number plate at 20 metres (20.5 metres for old-style plates)','Reading a number plate at 30 metres','Having 20/20 vision'],ans:1,exp:'You must be able to read a number plate from 20 metres (or 20.5 metres for older-style plates) in good daylight.'},
{id:686,cat:'documents',q:'What must a driver with insulin-treated diabetes do to maintain their driving licence?',opts:['Nothing special','Notify the DVLA and meet medical standards, including regular blood glucose monitoring','Only inform their GP','Take an annual driving test'],ans:1,exp:'Drivers with insulin-treated diabetes must notify the DVLA, meet medical standards and may receive a shorter-duration licence subject to review.'},
{id:687,cat:'documents',q:'How long must a person with epilepsy be seizure-free before they can drive a car?',opts:['3 months','6 months','12 months (or meet other specific criteria)','5 years'],ans:2,exp:'A person with epilepsy must normally be seizure-free for 12 months before a car driving licence can be issued or renewed, though specific rules vary.'},
{id:688,cat:'documents',q:'Who can apply for a Blue Badge for disabled parking?',opts:['Anyone over 65','People with severe mobility problems, certain disabilities or conditions that affect walking','Only wheelchair users','Only war veterans'],ans:1,exp:'Blue Badges are available to people with a range of conditions that severely affect their mobility, not just wheelchair users.'},
{id:689,cat:'documents',q:'Which vehicles may be exempt from the London Congestion Charge?',opts:['All hybrid vehicles','Vehicles meeting certain emissions standards, disabled tax class vehicles and some alternative fuel vehicles','Only electric vehicles','Only vehicles registered in London'],ans:1,exp:'Exemptions and discounts apply to certain ultra-low emission vehicles, disabled tax class vehicles and other qualifying categories.'},
{id:690,cat:'documents',q:'What are vehicle emissions categories used for in the UK?',opts:['Determining road tax only','Classifying vehicles for entry into Clean Air Zones and ULEZ based on Euro emission standards','Setting speed limits','Insurance pricing'],ans:1,exp:'Euro emission standards classify vehicles into categories that determine whether they meet Clean Air Zone and ULEZ requirements.'},
{id:691,cat:'documents',q:'How can you check if your vehicle is ULEZ compliant?',opts:['By checking the colour of your tax disc','By using the TfL online vehicle checker tool','By asking your local council','By reading the V5C only'],ans:1,exp:'Transport for London provides an online vehicle checker where you enter your registration to see if your vehicle meets ULEZ standards.'},
{id:692,cat:'documents',q:'How can you check if your vehicle is subject to a manufacturer recall?',opts:['Contact your local MOT centre','Check the DVSA online recall tool using your vehicle make and model','Phone the DVLA','Check your V5C document'],ans:1,exp:'The DVSA provides a free online tool to check for vehicle recalls by entering the make and model of your vehicle.'},
{id:693,cat:'documents',q:'What is an HPI check on a vehicle?',opts:['A mechanical inspection','A check of the vehicle\'s history including outstanding finance, theft records and write-off status','An emissions test','A tyre pressure check'],ans:1,exp:'An HPI-type check reveals if a vehicle has outstanding finance, has been reported stolen, written off or has a mileage discrepancy.'},
{id:694,cat:'documents',q:'What is the difference between the registered keeper and the legal owner of a vehicle?',opts:['They are always the same person','The registered keeper on the V5C is responsible for taxing and registering the vehicle but is not necessarily the legal owner','The keeper owns the vehicle','The owner must always be the keeper'],ans:1,exp:'The V5C names the registered keeper, who is legally responsible for the vehicle\'s registration and tax, but this does not prove ownership.'},
{id:695,cat:'documents',q:'How do you transfer a personalised registration number to another vehicle?',opts:['Just swap the plates yourself','Apply to the DVLA using the online service or form V317, paying the transfer fee','Tell your insurance company','Contact the MOT centre'],ans:1,exp:'You must apply to the DVLA and pay a fee to transfer or retain a personalised registration number. Both vehicles must be taxed or have a SORN.'},
{id:696,cat:'documents',q:'What is a cherished number plate retention certificate?',opts:['A certificate proving your car is vintage','A V778 certificate allowing you to keep a registration number for assignment to another vehicle','A document confirming your car\'s value','An MOT certificate for classic cars'],ans:1,exp:'A V778 retention certificate lets you hold a registration number for up to 10 years before assigning it to another vehicle.'},
{id:697,cat:'documents',q:'How often must you renew your driving licence photo?',opts:['Every 5 years','Every 10 years','Every 15 years','It never needs renewing'],ans:1,exp:'The photocard driving licence must be renewed every 10 years to update the photograph. The driving entitlement itself does not expire until age 70.'},
{id:698,cat:'documents',q:'What restrictions apply to a provisional driving licence holder?',opts:['None','Must display L plates (or D plates in Wales), must be accompanied by a qualified driver, and cannot drive on motorways unless with an approved instructor','Can drive on any road unsupervised','Only restricted at night'],ans:1,exp:'Provisional licence holders must use L plates, be supervised by a qualified driver aged 21+ with 3+ years\' experience, and may only drive on motorways with an approved driving instructor.'},
{id:699,cat:'documents',q:'How long is a theory test pass certificate valid?',opts:['1 year','2 years','5 years','Indefinitely'],ans:1,exp:'A theory test pass certificate is valid for two years. You must pass the practical test within that period or retake the theory test.'},
{id:700,cat:'documents',q:'What do you need before you can book a practical driving test?',opts:['Only a provisional licence','A valid theory test pass certificate and a provisional driving licence','Just a car','An instructor\'s recommendation'],ans:1,exp:'To book a practical driving test you need a valid provisional licence and a current theory test pass certificate (less than two years old).'},
];
